function openCharacterSetup(){showModal(`<div class="modalTop"><div class="avatar">✨</div><div class="modalTitle">Nieuw leven starten</div></div><div class="modalBody"><p>Kies jongen/meisje, je voornaam en je eigen achternaam. Je ouders krijgen standaard dezelfde achternaam.</p><input id="startFirstName" type="text" placeholder="Voornaam" maxlength="16" style="width:100%;padding:12px;border-radius:9px;border:1px solid #556;background:#15171b;color:#fff;font-size:18px;margin:6px 0 8px"><input id="startLastName" type="text" placeholder="Achternaam" maxlength="18" style="width:100%;padding:12px;border-radius:9px;border:1px solid #556;background:#15171b;color:#fff;font-size:18px;margin:0 0 10px"><button class="btn" onclick="confirmCharacterSetup('male')">👦 Start als jongen</button><button class="btn pink" onclick="confirmCharacterSetup('female')">👧 Start als meisje</button><button class="btn alt" onclick="closeModal()">Annuleren</button></div>`);setTimeout(()=>{let el=document.getElementById('startFirstName');if(el)el.focus()},40)}function confirmCharacterSetup(gender){let first=(document.getElementById('startFirstName')?.value||'').trim();let last=(document.getElementById('startLastName')?.value||'').trim();state=fresh(gender,first,last);state.legacy=state.legacy||{};state.legacy.familyName=state.name.split(' ').slice(-1)[0];addLog(`<b>Birth</b><br>Ik ben geboren als ${state.name}. Mijn moeder is ${state.mother.name} en mijn vader is ${state.father.name}.`,'good',false);safeSave();render();closeModal();}function newLife(){toggleMenu(false);closeScreen();openCharacterSetup();}
function migrate(s){if(!s||typeof s!=='object')return fresh();s.version='16.8';s.gender=inferPersonGender(s,s.gender||'male');s.firstName=s.firstName||((s.name||'').split(' ')[0])||pick(PLAYER_NAMES[s.gender]||PLAYER_NAMES.male);s.icon=humanIcon(s.gender,s.age||0);s.stats=s.stats||{Happiness:50,Health:50,Smarts:50,Looks:50};s.fitness=clamp(s.fitness??Math.round(((s.stats.Health||50)+(s.stats.Looks||50))/2));s.stamina=clamp(s.stamina??Math.round((s.stats.Health||50)+5));s.education=s.education||{primary:false,highschool:false,mbo:false,hbo:false,uni:false,studying:null,studyYears:0};s.talents=s.talents||{thief:0,honesty:0,sport:0};s.houses=s.houses||[];s.cars=s.cars||[];s.items=s.items||[];s.children=(s.children||[]).map(c=>{let g=inferPersonGender(c,c.gender);return {...c,gender:g,icon:humanIcon(g,c.age||0)}});s.siblings=(s.siblings||[]).map(b=>{let g=inferPersonGender(b,b.gender);let role=b.role||(g==='female'?'Zus':'Broer');let kids=(b.children||[]).map(k=>{let kg=inferPersonGender(k,k.gender);return {...k,gender:kg,icon:k.icon||humanIcon(kg,k.age||0),rel:k.rel??r(35,80)}});let partner=b.partner?{...b.partner,gender:inferPersonGender(b.partner,b.partner.gender),icon:b.partner.icon||humanIcon(inferPersonGender(b.partner,b.partner.gender),b.partner.age||b.age||18)}:null;return {...b,gender:g,role,rel:b.rel??r(35,80),icon:humanIcon(g,b.age||0),movedOut:!!b.movedOut,job:b.job||null,partner,married:!!b.married,children:kids,adultEvents:b.adultEvents||{}}});s.parentsDivorced=!!s.parentsDivorced;s.friends=(s.friends||[]).map(f=>{let g=inferPersonGender(f,f.gender);return {...f,gender:g,icon:humanIcon(g,Math.max(6,f.age||16))}});s.pets=(s.pets||[]).map(p=>({...p,icon:p.icon||petIcon(p.type||p.breed||'Pet'),health:p.health??r(60,95),rel:p.rel??r(55,90),upkeep:p.upkeep??petUpkeep(p.type||p.breed||'Pet')}));s.achievements=s.achievements||[];s.snapshots=[];s.debts=s.debts||0;s.jobYears=s.jobYears||0;s.careerLevel=s.careerLevel||0;if(s.job){s.job.performance=s.job.performance??50;s.job.stress=s.job.stress??20;s.job.colleagues=s.job.colleagues||[];s.job.boss=s.job.boss||null;}s.lastAgeIncome=s.lastAgeIncome||0;s.school=s.school||{teacher:null,classmates:[]};s.flags=s.flags||{};s.addiction=s.addiction||{alcoholUse:0,drugUse:0,weedUse:0,alcohol:false,drugs:false,weed:false,underInfluence:false,lastDuiAge:-99,lastStealAge:-99};s.addiction.alcoholUse=s.addiction.alcoholUse||0;s.addiction.drugUse=s.addiction.drugUse||0;s.addiction.weedUse=s.addiction.weedUse||0;s.addiction.weed=!!s.addiction.weed;s.addiction.lastDuiAge=s.addiction.lastDuiAge??-99;s.addiction.lastStealAge=s.addiction.lastStealAge??-99;s.license=!!s.license;s.jail=s.jail||null;s.talents=s.talents||{thief:0,honest:0,sporty:0};s.mother={...(s.mother||{}),gender:'female',icon:(s.mother&&s.mother.icon)||humanIcon('female',(s.mother&&s.mother.age)||35)};s.father={...(s.father||{}),gender:'male',icon:(s.father&&s.father.icon)||humanIcon('male',(s.father&&s.father.age)||38)};if(s.partner){let g=inferPersonGender(s.partner,s.partner.gender);s.partner={...s.partner,gender:g,icon:humanIcon(g,s.partner.age||18)}}if(s.school.teacher){s.school.teacher={...s.school.teacher,icon:s.school.teacher.icon||teacherAvatar(s.school.teacher)}}if(Array.isArray(s.school.classmates)){s.school.classmates=s.school.classmates.map(c=>{let g=inferPersonGender(c,c.gender);return {...c,gender:g,icon:humanIcon(g,state?.age||c.age||12)}});}s.world=s.world||'normal';s.vacation=s.vacation||null;s.homeWorldBeforeVacation=s.homeWorldBeforeVacation||s.world||'normal';s.nc=s.nc||{streetCred:0,heat:0,humanity:100,cyberware:0,techSkill:0,combatSkill:0,corporateTrust:0};s.nightCityOfferShown=!!s.nightCityOfferShown;s.talents=s.talents||{sport:0,thief:0,social:0,tech:0,combat:0,honesty:0,discipline:0,stress:0};s.mental=s.mental||{stress:Math.max(0,100-(s.stats?.Happiness||60)),trauma:0,burnout:0};s.businesses=s.businesses||[];s.football=s.football||{level:'recreatief',club:null,goals:0,scout:false,contract:false};s.legacy=s.legacy||{generation:s.legacy?.generation||1,familyName:(s.name||'').split(' ').slice(-1)[0]||'Familie',fame:s.legacy?.fame||0};s.lifeGoals=s.lifeGoals||{};s.legacy=s.legacy||{};s.legacy.familyName=s.legacy.familyName||((s.name||'').split(' ').slice(-1)[0]||'Familie');if(!s.parentsDivorced){let ln=s.legacy.familyName;if(s.mother&&s.mother.name&&!s.mother.name.endsWith(' '+ln))s.mother.name=(s.mother.name.split(' ')[0]||pick(DATE_NAMES.female))+' '+ln;if(s.father&&s.father.name&&!s.father.name.endsWith(' '+ln))s.father.name=(s.father.name.split(' ')[0]||pick(DATE_NAMES.male))+' '+ln;}s.log=(s.log||[]).slice(-90);return s;}
function loadGame(show){try{let raw=localStorage.getItem(SAVE_KEY);if(raw){state=migrate(JSON.parse(raw));if(show)toast('Save geladen');render();}else{state=null;openCharacterSetup();}}catch(e){state=null;toast('Save beschadigd, start een nieuw leven');openCharacterSetup();}}
function compact(){let s=clone(state);s.log=(s.log||[]).slice(-100);s.snapshots=(s.snapshots||[]).slice(-3).map(x=>{x.log=(x.log||[]).slice(-25);x.snapshots=[];return x});return s;}
function safeSave(){try{localStorage.setItem(SAVE_KEY,JSON.stringify(compact()));}catch(e){state.log=state.log.slice(-35);state.snapshots=[];localStorage.setItem(SAVE_KEY,JSON.stringify(compact()));}}
function resetSave(){OLD_KEYS.forEach(k=>localStorage.removeItem(k));localStorage.removeItem(SAVE_KEY);newLife();toast('Reset gedaan');}
function addLog(html,type='',save=true){state.log.push({html,type,age:state.age});if(state.log.length>100)state.log=state.log.slice(-100);if(save)safeSave();}
function applyStats(o){for(const k in o){if(k==='Fitness'){state.fitness=clamp((state.fitness||50)+o[k]);continue}if(k==='Stamina'){state.stamina=clamp((state.stamina||50)+o[k]);continue}state.stats[k]=clamp((state.stats[k]||50)+o[k]);}}
function bodyBar(v){return `<div class="miniBar"><div class="miniFill ${v<35?'low':''}" style="width:${clamp(v)}%"></div></div>`}
function resultMetaFromAction(title,text,stats,cash,type){let keys=Object.keys(stats||{});let map={Happiness:'Happiness',Health:'Health',Smarts:'Smarts',Looks:'Looks',Fitness:'Fitheid',Stamina:'Stamina'};let k=keys[0]||'';let label='Resultaat';let value=72;let tone='';if(k){label=map[k]||k;value=k==='Fitness'?clamp(state.fitness||50):k==='Stamina'?clamp(state.stamina||50):clamp(state.stats[k]||50);tone=(stats[k]||0)<0?'low':'';if(value<20)tone='dead';else if(value<40&&tone!=='dead')tone='low';}else if(cash){label=cash>0?'Winst':'Kosten';let pct=Math.min(100,Math.max(10,Math.round(Math.abs(cash)/25)));value=pct;tone=cash<0?'low':'';}else if(type==='good'){label='Effect';value=82;}else if(type==='bad'){label='Effect';value=24;tone='low';}else if(type==='warn'){label='Effect';value=38;tone='low';}let titles={Happiness:['Nice!','Lekker bezig','Mooi zo'],Health:['Gezond bezig','Frisse boost','Sterker'],Smarts:['Slim gespeeld','Brain gain','Kennis erbij'],Looks:['Looking good','Netjes','Stijl omhoog'],Fitness:['Goed getraind','Fit bezig','Sterker lichaam'],Stamina:['Meer energie','Op adem komen','Conditie'],Resultaat:['Resultaat','Klaar','Afgerond']};let modalTitle=(titles[label]&&pick(titles[label]))||pick(titles.Resultaat); if(/flirt|date|ask out|liefde|crush/i.test(title+' '+text)) modalTitle=pick(['Any bites?','Vlinders','Spanning']); if(/conversation|gesprek|praat|talk/i.test(title+' '+text)) modalTitle=pick(['Class mates','Gesprek','Even bijpraten']); if(/huisdier|pet|dog|cat|walk|treat|bath|vet/i.test(title+' '+text)) modalTitle=pick(['Here you go','Trouwe vriend','Pootjes vooruit']); if(/meditat|mind|body|relax/i.test(title+' '+text)) modalTitle=pick(['Omm Omm','Rust gevonden','Zen moment']); return {title:modalTitle,text:text+(cash?` ${cash>0?'Je verdiende':'Het kostte'} ${money(Math.abs(cash))}.`:''),label,value,tone};}
function showActionResult(meta){showModal(`<div class="resultWrap"><div class="resultShell"><div class="resultHead"><div class="resultLogo"><span class="sperm">◠◡◠</span><span>BitLife</span></div></div><div class="resultBody"><div class="resultTitle">${meta.title}</div><div class="resultText">${meta.text}</div><div class="meterBlock"><div class="meterLabel">${meta.label}</div><div class="resultBar"><div class="resultFill ${meta.tone||''}" style="width:${clamp(meta.value)}%"></div></div></div><div class="resultOk"><button class="btn" onclick="closeModal()">OK</button></div></div></div></div>`);}
function action(title,text,stats={},cash=0,type=''){state.money+=cash;applyStats(stats);addLog(`<b>${title}</b><br>${text}${cash?`<br>${cash>0?'+':'-'} ${money(Math.abs(cash))}`:''}`,type||cash>0?'good':cash<0?'bad':'');render();showActionResult(resultMetaFromAction(title,text,stats,cash,type));}
function ensureAddiction(){state.addiction=state.addiction||{alcoholUse:0,drugUse:0,weedUse:0,alcohol:false,drugs:false,weed:false,underInfluence:false,lastDuiAge:-99,lastStealAge:-99};state.addiction.weedUse=state.addiction.weedUse||0;state.addiction.weed=!!state.addiction.weed;return state.addiction;}function substanceChance(counter,kind){let base=Math.min(kind==='weed'?0.28:kind==='drugs'?0.38:0.30,counter*(kind==='weed'?0.035:kind==='drugs'?0.045:0.04));let cap=state.homeless?0.50:0.20;return Math.min(cap,base);}function recordSubstance(kind,amount=1){let a=ensureAddiction();a.underInfluence=true;if(kind==='alcohol'){a.alcoholUse=(a.alcoholUse||0)+amount;let chance=substanceChance(a.alcoholUse,'alcohol');if(!a.alcohol&&a.alcoholUse>=5&&Math.random()<chance){a.alcohol=true;addLog('<b>Verslaving</b><br>Mijn alcoholgebruik werd geen losse avond meer. Ik begin afhankelijk te worden van drank.','warn',false);showActionResult(resultMetaFromAction('Verslaving','Door vaak te drinken ontwikkelde ik een alcoholverslaving.',{Health:-8,Happiness:-6},0,'bad'));}}if(kind==='drugs'){a.drugUse=(a.drugUse||0)+amount;let chance=substanceChance(a.drugUse,'drugs');if(!a.drugs&&a.drugUse>=4&&Math.random()<chance){a.drugs=true;addLog('<b>Verslaving</b><br>Door vaak drugs te gebruiken begon het mijn keuzes over te nemen.','bad',false);showActionResult(resultMetaFromAction('Verslaving','Door vaak drugs te gebruiken ontwikkelde ik een drugsverslaving.',{Health:-10,Smarts:-6,Happiness:-7},0,'bad'));}}if(kind==='weed'){a.weedUse=(a.weedUse||0)+amount;let chance=substanceChance(a.weedUse,'weed');if(!a.weed&&a.weedUse>=5&&Math.random()<chance){a.weed=true;addLog('<b>Verslaving</b><br>Joints en wiet werden te normaal. Ik merk dat ik er afhankelijk van raak.','warn',false);showActionResult(resultMetaFromAction('Wietverslaving','Door vaak joints/wiet te gebruiken ontwikkelde ik een wietverslaving.',{Health:-5,Smarts:-4,Stamina:-5},0,'warn'));}}}function addictionYearEvents(){let a=ensureAddiction();if(state.dead||state.jail)return;a.underInfluence=false;if(a.alcoholUse>0)a.alcoholUse=Math.max(0,Math.round(a.alcoholUse*.82));if(a.drugUse>0)a.drugUse=Math.max(0,Math.round(a.drugUse*.78));if(a.weedUse>0)a.weedUse=Math.max(0,Math.round(a.weedUse*.84));if(a.alcohol&&Math.random()<.35){applyStats({Health:-3,Happiness:-2,Stamina:-5});addLog('<b>Verslaving</b><br>Mijn alcoholgebruik trok aan mijn gezondheid en energie dit jaar.','warn',false)}if(a.drugs&&Math.random()<.45){applyStats({Health:-5,Smarts:-3,Happiness:-3,Stamina:-6});addLog('<b>Verslaving</b><br>Mijn drugsgebruik maakte mijn jaar zwaarder. Focus, geld en gezondheid kregen een klap.','bad',false)}if(a.weed&&Math.random()<.35){applyStats({Health:-2,Smarts:-3,Happiness:-1,Stamina:-4});addLog('<b>Wietverslaving</b><br>Ik merkte dat joints/wiet mijn focus en energie steeds vaker omlaag trokken.','warn',false)}if(a.drugs&&state.money<80&&state.age-(a.lastStealAge??-99)>=3&&Math.random()<.28){a.lastStealAge=state.age;setTimeout(()=>drugStealEvent(),350);return}if((a.alcohol||a.drugs||a.alcoholUse>5||a.drugUse>4)&&state.license&&state.cars&&state.cars.length&&state.age-(a.lastDuiAge??-99)>=2&&Math.random()<.24){a.lastDuiAge=state.age;setTimeout(()=>duiEvent(),430)}}function drugStealEvent(){showModal(`<div class="modalTop"><div class="avatar">🚨</div><div class="modalTitle">Drang</div></div><div class="modalBody"><p>Ik had weinig geld en kreeg de neiging om iets te stelen voor drugs. Wat doe ik?</p><button class="btn red" onclick="resolveDrugSteal('steal')">Stelen</button><button class="btn" onclick="resolveDrugSteal('resist')">Weerstand bieden</button><button class="btn green" onclick="resolveDrugSteal('help')">Hulp zoeken</button></div>`)}function resolveDrugSteal(choice){closeModal();let a=ensureAddiction();if(choice==='steal'){let caught=Math.random()<.42;if(caught){action('Verslaving', 'Ik probeerde te stelen voor drugs, maar werd gepakt. Dit kan juridische gevolgen krijgen.', {Happiness:-12,Smarts:-2}, 0, 'bad');if(Math.random()<.45)lawyerChoice('stelen voor drugs',state.age<18?1:r(1,3));}else{let gain=r(20,120);action('Verslaving','Ik stal iets om aan geld te komen. Het lukte, maar het voelde als een nieuwe bodem.',{Happiness:-6,Smarts:-1},gain,'warn');}}if(choice==='resist'){a.drugUse=Math.max(0,(a.drugUse||0)-2);action('Verslaving','Ik wist de drang te weerstaan. Het was moeilijk, maar ik bleef uit de problemen.',{Happiness:2,Smarts:2,Health:1},0,'good')}if(choice==='help'){a.drugs=false;a.drugUse=Math.max(0,(a.drugUse||0)-4);action('Hulp zoeken','Ik vroeg hulp voor mijn drugsprobleem. Het was niet stoer, maar wel verstandig.',{Health:5,Smarts:2,Happiness:3},-Math.min(state.money,80),'good')}}function duiEvent(){showModal(`<div class="modalTop"><div class="avatar">🚗</div><div class="modalTitle">Rijden onder invloed</div></div><div class="modalBody"><p>Ik had een auto en rijbewijs, maar was niet helemaal nuchter. Wat doe ik?</p><button class="btn red" onclick="resolveDui('drive')">Toch rijden</button><button class="btn" onclick="resolveDui('taxi')">Taxi/OV pakken</button><button class="btn alt" onclick="resolveDui('sleep')">Wachten tot ik nuchter ben</button></div>`)}function resolveDui(choice){closeModal();if(choice==='taxi'){action('Rijden','Ik liet de auto staan en pakte ander vervoer. Slimme keuze.',{Smarts:2,Health:1,Happiness:1},-Math.min(state.money,45),'good');return}if(choice==='sleep'){action('Rijden','Ik besloot niet te rijden en wachtte tot ik weer helder was.',{Smarts:2,Health:1},0,'good');return}let roll=Math.random();if(roll<.25){state.license=false;action('Rijden onder invloed','Ik werd aangehouden. Mijn rijbewijs werd ingevorderd en ik kreeg een flinke boete.',{Happiness:-14,Smarts:-3,Health:-2},-Math.min(state.money,900),'bad')}else if(roll<.43){action('Rijden onder invloed','Ik veroorzaakte bijna een ongeluk. De schrik zat er goed in.',{Happiness:-10,Health:-8,Smarts:-2},-Math.min(state.money,500),'bad')}else if(roll<.58){action('Rijden onder invloed','Ik werd gepakt voor rijden onder invloed. Dit kan juridisch gedoe geven.',{Happiness:-12,Smarts:-2},-Math.min(state.money,650),'bad');if(Math.random()<.55)lawyerChoice('rijden onder invloed',state.age<18?1:r(1,2));}else{action('Rijden onder invloed','Ik reed onder invloed en kwam thuis zonder gepakt te worden. Dat was dom geluk, geen slimme keuze.',{Happiness:-2,Smarts:-2,Health:-2},0,'warn')}}
function stage(){if(state.age<2)return 'Baby';if(state.age<4)return 'Peuter';if(state.age<12)return 'Kind';if(state.age<18)return 'Tiener';if(state.age<25)return 'Jongvolwassene';if(state.age<40)return 'Volwassene';if(state.age<65)return 'Middenleeftijd';if(state.age<80)return 'Senior';return 'Oudere';}
function humanIcon(g,age=18){g=normalizeDateGender(g);if(age<2)return '👶';if(age<4)return '🧒';if(age<13)return g==='female'?'👧':'👦';if(age<18)return g==='female'?'👧':'👦';if(age<25)return g==='female'?'👩':'👨';if(age<65)return g==='female'?'👩':'👨';return g==='female'?'👵':'👴';}function avatar(){if(!state)return '👤';if(state.dead)return '☠️';return humanIcon(state.gender||'male',state.age||0);}function classmateAvatar(g){return humanIcon(g,(state&&state.age)||8)}function teacherAvatar(t){return /Mrs\.|Mevrouw|Juf/i.test((t&&t.name)||'')?'👩‍🏫':'👨‍🏫'}function petIcon(type){let t=(type||'').toLowerCase();if(t.includes('dog')||t.includes('corgi')||t.includes('beagle')||t.includes('spaniel')||t.includes('bulldog')||t.includes('retriever')||t.includes('chihuahua')||t.includes('dachshund')||t.includes('shepherd'))return '🐶';if(t.includes('cat')||t.includes('abyssinian')||t.includes('siamese')||t.includes('ragdoll')||t.includes('persian')||t.includes('maine'))return '🐱';if(t.includes('rabbit'))return '🐰';if(t.includes('gerbil')||t.includes('hamster'))return '🐹';if(t.includes('bird')||t.includes('macaw')||t.includes('parakeet'))return '🦜';if(t.includes('horse'))return '🐴';if(t.includes('snake'))return '🐍';return '🐾';}function itemIcon(name){let t=(name||'').toLowerCase();if(t.includes('gaming pc')||t==='pc'||t.includes('computer'))return '🖥️';if(t.includes('fitness'))return '🏋️';if(t.includes('kleding')||t.includes('clothes'))return '👕';if(t.includes('studieboeken')||t.includes('boeken')||t.includes('book'))return '📚';if(t.includes('ring'))return '💍';if(t.includes('broodmes')||t.includes('mes'))return '🔪';if(t.includes('optische scanner')||t.includes('optic scanner')||t.includes('scanner'))return '🔎';if(t.includes('cyberdeck'))return '💻';if(t.includes('datachip'))return '💾';return '🎁';}function petUpkeep(type){let t=(type||'').toLowerCase();if(t.includes('dog'))return 180;if(t.includes('cat'))return 130;if(t.includes('horse'))return 1800;if(t.includes('bird'))return 60;if(t.includes('rabbit'))return 55;if(t.includes('gerbil'))return 25;return 80;}function averageParentRel(){return Math.round(((state.mother?.rel||50)+(state.father?.rel||50))/2)}
function eduRank(){let e=state.education;if(e.uni)return 'uni';if(e.hbo)return 'hbo';if(e.mbo)return 'mbo';if(e.highschool)return 'highschool';return 'none'}function eduScore(x){return {none:0,highschool:1,mbo:2,hbo:3,uni:4}[x]||0}
function netWorth(){return state.money + state.houses.reduce((s,h)=>s+h.value,0)+state.cars.reduce((s,c)=>s+c.value,0)+state.items.reduce((s,i)=>s+i.price*.45,0)-state.debts;}
function relationBar(v){return `<div class="miniBar"><div class="miniFill ${v<35?'low':''}" style="width:${clamp(v)}%"></div></div>`}
function livingText(){if(state.age<18)return 'Woont thuis bij ouders · geen huur';let home=state.houses.find(h=>h.primary)||state.houses[0];if(!home)return state.world==='nightcity'?'Geen Night City woning · capsulekosten':'Huurwoning · vaste lasten';if(home.owned)return home.world==='nightcity'?(home.mortgage?'Night City koopwoning · hypotheek':'Night City koopwoning'):(home.mortgage?'Eigen woning · hypotheek':'Eigen woning');return home.name+' · huur '+money(home.monthlyRent||0)+'/mnd'}
function addRel(obj,delta){obj.rel=clamp((obj.rel||50)+delta);return obj.rel}
function createSibling(lastName,age=null,gender=null,name=''){gender=gender||((Math.random()<.5)?'male':'female');let first=(name||'').trim()||pick(DATE_NAMES[gender]||DATA.firstNames);return {name:first+' '+lastName,age:age===null?r(0,Math.max(0,(state?.age||0)+4)):age,gender,role:gender==='female'?'Zus':'Broer',rel:r(35,85),icon:humanIcon(gender,age||0)}}
function createStartingSiblings(lastName){let arr=[];if(Math.random()<.28){let g=Math.random()<.5?'male':'female';let older=Math.random()<.55;let age=older?r(1,6):0;arr.push({name:pick(DATE_NAMES[g])+' '+lastName,age,gender:g,role:g==='female'?'Zus':'Broer',rel:r(35,82),icon:humanIcon(g,age)});}return arr;}
function maybeFamilyEventAfterBirthday(){if(state.dead)return;state.flags=state.flags||{};if(!state.parentsDivorced&&state.age>=4&&Math.random()<0.025){state.parentsDivorced=true;state.mother.rel=clamp((state.mother.rel||60)-r(4,12));state.father.rel=clamp((state.father.rel||60)-r(4,12));safeSave();setTimeout(()=>action('Familie','Mijn ouders gingen uit elkaar. Het veranderde de sfeer thuis behoorlijk.',{Happiness:-7},0,'warn'),420);return;}let maxSiblings=4;if(state.age<=18&&(state.siblings||[]).length<maxSiblings&&Math.random()<0.055){setTimeout(()=>newSiblingNameEvent(),520);}}
function newSiblingNameEvent(){let g=Math.random()<.5?'male':'female';let def=pick(DATE_NAMES[g]||DATA.firstNames);let role=g==='female'?'zusje':'broertje';showModal(`<div class="modalTop"><div class="avatar">${humanIcon(g,0)}</div><div class="modalTitle">Nieuw ${role}</div></div><div class="modalBody"><p>Je ouders hebben een baby gekregen: een ${role}. Jij mag de naam kiezen.</p><input id="siblingNameInput" type="text" value="${def}" maxlength="16" style="width:100%;padding:12px;border-radius:9px;border:1px solid #556;background:#15171b;color:#fff;font-size:18px;margin:6px 0 10px"><button class="btn" onclick="confirmNewSibling('${g}')">Naam opslaan</button><button class="btn alt" onclick="confirmNewSibling('${g}',true)">Random naam</button></div>`);}
function confirmNewSibling(g,randomize=false){let last=state.name.split(' ').slice(-1)[0];let raw=randomize?'':(document.getElementById('siblingNameInput')?.value||'').trim();let sib=createSibling(last,0,g,raw);state.siblings=state.siblings||[];state.siblings.push(sib);closeModal();action('Familie',`Ik kreeg een ${g==='female'?'zusje':'broertje'}: ${sib.name}.`,{Happiness:8},0,'good');}
function siblingJob(){return pick(['supermarktmedewerker','horecamedewerker','monteur','administratief medewerker','zorgmedewerker','ICT-support','verkoper','student met bijbaan','bezorger','teamleider'])}
function maybeSiblingAdultLife(){if(!state.siblings)return;let last=state.name.split(' ').slice(-1)[0];state.siblings.forEach((b,idx)=>{b.children=b.children||[];b.adultEvents=b.adultEvents||{};if(b.age>=18&&!b.movedOut&&Math.random()<0.55){b.movedOut=true;addLog(`<b>Familie</b><br>${b.role||genderLabel(b)} ${b.name} is uit huis gegaan.`, 'good', false)}if(b.age>=18&&!b.job&&Math.random()<0.35){b.job=siblingJob();addLog(`<b>Familie</b><br>${b.name} vond werk als ${b.job}.`, 'good', false)}if(b.age>=16&&!b.partner&&Math.random()<0.22){let pg=b.gender==='female'?'male':'female';let p={name:pick(DATE_NAMES[pg])+' '+pick(DATA.lastNames),age:Math.max(16,b.age+r(-2,4)),gender:pg,icon:humanIcon(pg,Math.max(16,b.age)),rel:r(45,90)};b.partner=p;addLog(`<b>Familie</b><br>${b.name} kreeg een ${pg==='female'?'vriendin':'vriend'}: ${p.name}.`, 'good', false)}if(b.age>=21&&b.partner&&!b.married&&Math.random()<0.10){b.married=true;addLog(`<b>Familie</b><br>${b.name} is getrouwd met ${b.partner.name}.`, 'good', false)}if(b.age>=24&&b.partner&&b.married&&Math.random()<0.025){let ex=b.partner.name;b.partner=null;b.married=false;addLog(`<b>Familie</b><br>${b.name} en ${ex} zijn gescheiden.`, 'warn', false)}if(b.age>=20&&b.partner&&b.children.length<4&&Math.random()<0.13){let kg=Math.random()<.5?'male':'female';let kid={name:pick(DATE_NAMES[kg])+' '+last,age:0,gender:kg,icon:humanIcon(kg,0),rel:r(40,85)};b.children.push(kid);addLog(`<b>Familie</b><br>${b.name} kreeg een kind: ${kid.name}. Je hebt nu een ${kg==='female'?'nichtje':'neefje'}.`, 'good', false)}})}
function siblingScreen(i){let b=state.siblings[i];if(!b)return;let status=[];if(b.movedOut)status.push('uit huis');else status.push('woont thuis');if(b.job)status.push('werk: '+b.job);if(b.partner)status.push(`${b.married?'getrouwd met':'relatie met'} ${b.partner.name}`);else if(b.age>=16)status.push('single');let kids=(b.children||[]).map((k,ki)=>`<button class="btn" onclick="nieceNephewScreen(${i},${ki})">${k.icon||humanIcon(k.gender,k.age)} ${k.name}<br><span class="mini">${k.gender==='female'?'Nichtje':'Neefje'} · ${k.age} jaar</span></button>`).join('');showModal(`<div class="modalTop"><div class="avatar">${b.icon||humanIcon(b.gender,b.age)}</div><div class="modalTitle">${b.name}</div></div><div class="modalBody"><div class="card">${b.role||genderLabel(b)}<br>${b.age} jaar<br>${status.join('<br>')}<br>Relatie: ${b.rel}% ${relationBar(b.rel)}</div><button class="btn" onclick="talkSibling(${i})">💬 Gesprek</button><button class="btn" onclick="spendSibling(${i})">🕒 Tijd doorbrengen</button><button class="btn" onclick="complimentSibling(${i})">😘 Compliment</button><button class="btn red" onclick="insultSibling(${i})">🤬 Beledigen</button>${kids?`<div class="section">Neefjes / nichtjes</div>${kids}`:''}<button class="btn alt" onclick="closeModal()">Terug</button></div>`)}
function nieceNephewScreen(si,ki){let b=state.siblings[si],k=b&&b.children?b.children[ki]:null;if(!k)return;showModal(`<div class="modalTop"><div class="avatar">${k.icon||humanIcon(k.gender,k.age)}</div><div class="modalTitle">${k.name}</div></div><div class="modalBody"><div class="card">${k.gender==='female'?'Nichtje':'Neefje'}<br>${k.age} jaar<br>Kind van ${b.name}<br>Relatie: ${k.rel||50}%</div><button class="btn" onclick="spendNieceNephew(${si},${ki})">Tijd doorbrengen</button><button class="btn alt" onclick="siblingScreen(${si})">Terug</button></div>`)}
function spendNieceNephew(si,ki){let b=state.siblings[si],k=b&&b.children?b.children[ki]:null;if(!k)return;k.rel=clamp((k.rel||50)+r(4,11));closeModal();action('Familie',`Ik bracht tijd door met mijn ${k.gender==='female'?'nichtje':'neefje'} ${k.name}.`,{Happiness:4},0,'good')}
function talkSibling(i){let b=state.siblings[i];b.rel=clamp((b.rel||50)+r(2,7));closeModal();action('Familie',`Ik had een gesprek met ${b.name} over ${pick(['school','games','voetbal','rare dromen','wie de afstandsbediening mocht hebben','welke Pokémon starter het beste is'])}.`,{Happiness:3},0,'good')}
function spendSibling(i){let b=state.siblings[i];b.rel=clamp((b.rel||50)+r(3,9));closeModal();action('Familie',`Ik bracht tijd door met ${b.name}. We ${pick(SPEND_ACTIVITIES)}.`,{Happiness:4},0,'good')}
function complimentSibling(i){let b=state.siblings[i];b.rel=clamp((b.rel||50)+r(4,10));closeModal();action('Familie',`Ik gaf ${b.name} een compliment. ${b.gender==='female'?'Ze':'Hij'} deed alsof het normaal was, maar vond het duidelijk leuk.`,{Happiness:3},0,'good')}
function insultSibling(i){let b=state.siblings[i];b.rel=clamp((b.rel||50)-r(8,18));closeModal();action('Familie',`Ik beledigde ${b.name}. Dat liep meteen uit op ruzie.`,{Happiness:-5},0,'bad')}
function statEmoji(k){return {Happiness:'😀',Health:'❤️',Smarts:'🧠',Looks:'😎'}[k]||''}
function render(){if(!state)return;document.body.classList.toggle('nightcity',state.world==='nightcity' && state.vacation!=='jamaica');document.body.classList.toggle('jamaica',state.vacation==='jamaica');let stageMap={Baby:'👶',Peuter:'🧸',Kind:'🧒',Tiener:'🧑',Jongvolwassene:'🧑‍🎓',Volwassene:'🧑‍💼',Middenleeftijd:'🧔',Senior:'🧓',Oudere:'👴'};let st=state.jail&&state.jail.yearsLeft>0?(state.age<18?'Juvenile Delinquent':'Prisoner'):stage();document.querySelector('.profile').classList.toggle('brickBg',!!(state.jail&&state.jail.yearsLeft>0));$('name').textContent=state.name;$('stage').textContent=`${state.jail&&state.jail.yearsLeft>0?'⚖️':(stageMap[st]||'🏷️')} ${st} · ${state.age} jaar`;$('avatar').textContent=avatar();$('tabAvatar').textContent=avatar();$('lifeTab').textContent=st;$('money').innerHTML=`${money(state.money)}<span>Bank Balance</span>`;$('stars').textContent=state.stars||0;$('stats').innerHTML=['Happiness','Health','Smarts','Looks'].map(k=>`<div class="statrow"><div class="statLabel"><span>${k}</span><span class="statEmoji">${statEmoji(k)}</span></div><div class="bar"><div class="fill ${(state.stats[k]<35?'low':'')} ${(state.stats[k]<15?'dead':'')}" style="width:${clamp(state.stats[k])}%"></div></div><div>${clamp(state.stats[k])}%</div></div>`).join('');$('log').innerHTML=state.dead?deathHTML():state.log.slice().reverse().map(e=>`<p class="entry ${e.type||''}">${e.html}</p>`).join('');}
function openScreen(name){if(state.dead&&name!=='life')return toast('Je bent overleden. Start een nieuw leven.');$('screen').classList.add('show');let titles={life:'LIFE',assets:'ASSETS',relationships:'RELATIONSHIPS',activities:'ACTIVITIES'};$('screenTitle').textContent=titles[name]||name.toUpperCase();$('screenContent').innerHTML=screenHTML(name);}function closeScreen(){$('screen').classList.remove('show');}
function row(icon,title,sub,fn,locked=false,cls=''){return `<div class="row ${locked?'locked':''} ${cls}" onclick="${locked?'':fn}"><div class="rIco">${icon}</div><div><div class="rTitle">${title}</div><div class="sub">${sub||''}</div></div><div class="chev">›</div></div>`}
function isInJail(){return !!(state&&state.jail&&state.jail.yearsLeft>0)}function screenHTML(name){if(name==='life')return lifeHTML();if(name==='assets')return assetsHTML();if(name==='relationships')return relationshipsHTML();return activitiesHTML();}
function lifeHTML(){return `<div class="section">Mijn leven</div>${row('📖','Journal',`${state.log.length} gebeurtenissen`,'journal()')}${row('🎓','Education',eduText(),'educationScreen()')}${row('💼','Work',state.job?state.job.title+' · '+money(jobSalary())+'/jaar':'Geen baan','workScreen()')}${row('🏆','Achievements',`${state.achievements.length} behaald`,'achievements()')}<div class="section">v8.5 Mega Systems</div>${row('🌳','Family Tree / Legacy','Generaties, erfstukken en familie-reputatie','legacyScreen()')}${row('🎯','Life Goals','Bekijk routes en einddoelen','lifeGoalsScreen()')}${row('📈','Skill Tree','Talenten en karakterrichting','skillTreeScreen()')}<div class="section">Status</div>${state.world==='nightcity'?ncStatsHTML():''}<div class="statusCard"><div><span>🏠 Wonen</span><b>${livingText()}</b></div><div><span>💶 Net worth</span><b>${money(netWorth())}</b></div><div><span>🎓 Diploma</span><b>${eduText()}</b></div><div><span>📉 Schuld</span><b>${money(state.debts)}</b></div><div><span>📱 Social followers</span><b>${state.social}</b></div><div><span>⚠️ Verslaving</span><b>${(state.addiction&&(state.addiction.alcohol||state.addiction.drugs))?[(state.addiction.alcohol?'Alcohol':null),(state.addiction.drugs?'Drugs':null)].filter(Boolean).join(' + '):'Geen'}</b></div><div><span>💪 Fitheid</span><b>${clamp(state.fitness||50)}%</b></div><div><span>⚡ Stamina</span><b>${clamp(state.stamina||50)}%</b></div></div>`}
function eduText(){let e=state.education;if(e.studying)return 'Studerend: '+e.studying.toUpperCase()+' jaar '+e.studyYears;if(e.uni)return 'Universitair diploma';if(e.hbo)return 'HBO diploma';if(e.mbo)return 'MBO diploma';if(e.highschool)return 'Middelbare school diploma';if(e.primary)return 'Basisschool afgerond';if(state.age>=4&&state.age<12)return 'Basisschool leerling';if(state.age>=12&&state.age<18&&!e.highschool)return 'Middelbare school leerling';return state.age<4?'Nog niet op school':'Geen diploma'}
function activeStudy(){return !!(state.education&&state.education.studying)}
function isInSchool(){return activeStudy()||(state.age>=4&&state.age<18&&!state.education.highschool)}
function schoolStatusText(){if(activeStudy())return `${state.education.studying.toUpperCase()} actief: leren, klas, vrienden en schoolacties`;if(state.age<4)return 'Nog niet op school';if(isInSchool())return state.age<12?'Basisschool: leren, spijbelen, vrienden maken':'Middelbare school: leren, spijbelen, vrienden maken';return 'Niet actief: je zit nu niet op school'}
function assetsHTML(){let h=state.houses.map((x,i)=>{let sub=x.owned?`${money(x.value)} · ${x.mortgage?'hypotheek '+money(x.monthlyMortgage)+'/mnd':'afbetaald'} · onderhoud ${money(x.upkeep||0)}/jr`:`huur ${money(x.monthlyRent)}/mnd · vaste lasten`;return row(x.owned?'🏠':'🏢',x.name,sub,`assetHouse(${i})`,state.age<18)}).join('');let c=state.cars.map((x,i)=>row('🚗',x.name,`${money(x.value)} · ${x.rented?'verhuurd '+money(x.rent)+'/jr':'eigen gebruik'} · onderhoud ${money(x.upkeep)}/jr`,`assetCar(${i})`,state.age<18)).join('');let it=state.items.map((x,i)=>row(x.icon||itemIcon(x.name),x.name,`${money(x.price)} aankoopwaarde`,`itemScreen(${i})`)).join('');return `<div class="section">Wonen</div>${row('🏘️','Huren / huis kopen',isInJail()?'Niet beschikbaar in gevangenis/jeugddetentie':state.world==='nightcity'?'Night City woning kiezen':state.age>=18?'Huurwoning kiezen of kopen met hypotheek':'Kan pas vanaf 18 jaar','buyHouseScreen()',state.age<18||isInJail())}<div class="section">Kopen</div>${row('🚘','Auto kopen',isInJail()?'Niet beschikbaar in gevangenis/jeugddetentie':state.age>=18?'Koop, verhuur of verkoop auto’s':'Kan pas vanaf 18 jaar','buyCarScreen()',state.age<18||isInJail())}${row('🛒','Items kopen','Spullen met kleine stat-bonussen','buyItemScreen()')}<div class="section">Mijn woning(en)</div>${h||'<div class="card">Nog geen woning. Tot 18 woon je thuis.</div>'}<div class="section">Mijn auto’s</div>${c||'<div class="card">Nog geen auto’s.</div>'}<div class="section">Mijn items</div>${it||'<div class="card">Nog geen items.</div>'}`}
function relationshipsHTML(){let s=`<div class="section">Familie</div>${row(state.mother.icon||humanIcon('female',state.mother.age),'Moeder',`${state.mother.name} · Vrouw · relatie ${state.mother.rel}%`,'parentScreen(\'mother\')')}${row(state.father.icon||humanIcon('male',state.father.age),'Vader',`${state.father.name} · Man · relatie ${state.father.rel}%`,'parentScreen(\'father\')')}`;s+=`<div class="section">Broers en zussen</div>`+(state.siblings&&state.siblings.length?state.siblings.map((b,i)=>row(b.icon||humanIcon(b.gender,b.age),b.name,`${b.role||genderLabel(b)} · ${b.age} jaar · relatie ${b.rel}%`,`siblingScreen(${i})`)).join(''):'<div class="card">Geen broers of zussen.</div>');s+=`<div class="section">Love</div>`;s+=state.partner?row(state.partner.married?'💍':(state.partner.icon||humanIcon(state.partner.gender,state.partner.age)),state.partner.name,`${genderLabel(state.partner)} · ${state.partner.married?'Getrouwd':'Partner'} · relatie ${state.partner.rel}%`,'partnerScreen()'):row('❤️','Love',state.age>=16?'Zoek iemand om te daten':'Daten kan vanaf 16 jaar','loveScreen()',state.age<16);s+=`<div class="section">Kinderen</div>`+(state.children.map((c,i)=>row(c.icon||humanIcon(c.gender,c.age),c.name,`${c.age} jaar · ${genderLabel(c)} · relatie ${c.rel}%`,`childScreen(${i})`)).join('')||'<div class="card">Nog geen kinderen.</div>');s+=`<div class="section">Vrienden</div>`+(state.friends.map((f,i)=>row(f.icon||humanIcon(f.gender,f.age),f.name,`${f.from||'vriend'} · ${genderLabel(f)} · relatie ${f.rel}%`,`friendScreen(${i})`)).join('')||'<div class="card">Nog geen vrienden.</div>');s+=`<div class="section">Huisdieren</div>`+(state.pets.map((p,i)=>row(p.icon||petIcon(p.type||p.breed),p.name,`${p.breed||p.type} · ${p.age} jaar · band ${p.rel||60}%`,`petScreen(${i})`)).join('')||'<div class="card">Nog geen pets.</div>');return s;}

