function clubChickProfile(clubIndex){
 let club=CLUBS[clubIndex]||CLUBS[0];
 let age=Math.max(18,state.age+r(-2,5));
 if(state.age<18) age=Math.max(16,state.age+r(-1,2));
 let girl={name:pick(DATE_NAMES.female)+' '+pick(DATA.lastNames),age,gender:'female',icon:humanIcon('female',age),looks:r(35,98),smarts:r(20,90),vibe:pick(['flirty','mysterious','feestbeest','rustig maar geïnteresseerd','brutaal','grappig','chaotisch','zelfverzekerd']),click:r(25,95),club:club.name,clubIndex};
 window._clubChick=girl;
 let chance=clamp(Math.round((girl.click+girl.looks+(state.stats.Looks||50)+(state.stats.Happiness||50))/4),10,95);
 showModal(`<div class="modalTop"><div class="avatar">${girl.icon}</div><div class="modalTitle">${girl.name}</div></div><div class="modalBody"><div class="card"><b>${girl.name}</b><br>Vrouw · ${girl.age} jaar<br>Club: ${club.name}<br>Looks: ${girl.looks}% ${relationBar(girl.looks)}<br>Vibe: ${girl.vibe}<br>Klikscore: ${girl.click}% ${relationBar(girl.click)}<br>Kans: ${chance}%</div>${state.age>=18?`<button class="btn pink" onclick="clubOneNight(true)">🔥 One night stand proberen</button>`:`<button class="btn locked">🔥 One night stand<br><span class="mini">Alleen 18+</span></button>`}<button class="btn" onclick="clubOneNight(false)">📱 Nummer vragen / flirten</button><button class="btn alt" onclick="clubActionMenu(${clubIndex})">Laat haar gaan</button></div>`)
}
function clubOneNight(tryOns){
 let girl=window._clubChick;if(!girl)return toast('Geen profiel gevonden.');
 let club=CLUBS[girl.clubIndex]||CLUBS[0];
 let f=Number.isInteger(window._clubFriendIndex)?state.friends[window._clubFriendIndex]:null;
 let base=(girl.click+girl.looks+(state.stats.Looks||50)+(state.stats.Happiness||50))/4+(f?5:0);
 let cost=r(club.price[0],club.price[1])+r(10,65);
 if(!tryOns){
   let ok=Math.random()*100<clamp(base+10,10,92);
   if(ok){let contact={name:girl.name,age:girl.age,rel:r(35,72),chem:r(45,78),from:'uitgaan',source:'Uitgaan',gender:'female',icon:girl.icon,status:'fling'};if(window.addFling133){addFling133(contact,'uitgaan')}else{state.flings=state.flings||[];state.flings.push(contact)}closeModal();action('Uitgaan',`Ik vroeg ${girl.name} om haar nummer in ${club.name}. Ze glimlachte en gaf het. Ze staat nu onder Flings, niet Friends.`,{Happiness:8,Looks:1,Stamina:-3},-cost,'good');}
   else{closeModal();action('Uitgaan',`Ik probeerde met ${girl.name} te flirten in ${club.name}, maar ze hield het kort en liep terug naar haar vrienden.`,{Happiness:-4,Looks:-1,Stamina:-2},-Math.round(cost/2),'bad');}
   return;
 }
 if(state.age<18){toast('One night stand kan pas vanaf 18 jaar.');return;}
 let chance=clamp(base-8,8,82);
 let ok=Math.random()*100<chance;
 if(ok){
   let keepContact=Math.random()<.35;
   if(keepContact)state.friends.push({name:girl.name,age:girl.age,rel:r(30,60),from:'one night stand',gender:'female',icon:girl.icon});
   closeModal();action('Uitgaan',`Ik klikte met ${girl.name} in ${club.name}. De avond werd spannend en eindigde als een one night stand. ${keepContact?'We wisselden daarna nog nummers uit.':'Daarna bleef het bij die ene nacht.'}`,{Happiness:14,Looks:2,Health:Math.random()<.25?-2:0,Stamina:-14},-cost,'good');
 }else{
   closeModal();action('Uitgaan',`Ik probeerde een one night stand met ${girl.name}, maar de vibe was er toch niet. Het werd ongemakkelijk en ze haakte af.`,{Happiness:-7,Looks:-1,Stamina:-5},-cost,'bad');
 }
}

function clubDo(clubIndex,kind){
 let club=CLUBS[clubIndex]||CLUBS[0];
 let f=Number.isInteger(window._clubFriendIndex)?state.friends[window._clubFriendIndex]:null;
 let cost=r(club.price[0],club.price[1]);
 let stats={},txt='',type='good';
 if(kind==='drink'){
   let over=Math.random()<.22;recordSubstance('alcohol',over?2:1);
   txt=over?`Ik ging naar ${club.name} en dronk veel te veel. Het was even leuk, maar later voelde ik me beroerd.`:`Ik ging naar ${club.name} en nam een paar drankjes. De avond werd losser en gezelliger.`;
   stats=over?{Happiness:3,Health:-7,Stamina:-12,Smarts:-2}:{Happiness:7,Health:-2,Stamina:-5};
   type=over?'warn':'good';
   if(state.age<18&&Math.random()<.25){addRel(state.mother,-3);txt+=' Thuis merkte mijn moeder dat ik niet helemaal fris was.';stats.Happiness=(stats.Happiness||0)-2;}
 }
 if(kind==='chick'){
   clubChickProfile(clubIndex);
   return;
 }
 if(kind==='fun'){
   if(f){f.rel=clamp((f.rel||50)+r(5,13));}
   else if(Math.random()<.45){let gender=Math.random()<.5?'male':'female';let nf={name:pick(DATE_NAMES[gender])+' '+pick(DATA.lastNames),age:state.age,rel:r(35,65),from:'uitgaan',gender,icon:humanIcon(gender,state.age)};state.friends.push(nf);txt=`Ik ging naar ${club.name} om gewoon lol te hebben. Ik ontmoette ${nf.name} en we hadden meteen domme inside jokes.`;}
   if(!txt)txt=f?`Ik ging met ${f.name} naar ${club.name}. We hadden vooral lol, lachten om alles en gingen veel te laat naar huis.`:`Ik ging naar ${club.name} en had gewoon lol. Dansen, lachen, slechte muziek: precies goed.`;
   stats={Happiness:r(8,14),Health:-1,Stamina:-6,Looks:1};
 }
 closeModal();
 action('Uitgaan',txt,stats,-cost,type);
}

function loveScreen(){if(state.age<16)return toast('Daten kan vanaf 16 jaar.');showModal(`<div class="modalTop"><div class="avatar">❤️</div><div class="modalTitle">Love</div></div><div class="modalBody"><button class="btn" onclick="celebrityDatingApp()">🌟 Celebrity Dating App<br><span class="mini">Date de celebrity van je dromen</span></button><button class="btn" onclick="dateWebsite()">❤️ Date<br><span class="mini">Vind een normale date</span></button><button class="btn" onclick="datingAppSetup()">📲 Dating App<br><span class="mini">Gebruik filters voor leeftijd en geld</span></button><button class="btn" onclick="hookUpScreen()">🖤 Hook Up<br><span class="mini">Een losse, volwassen flirt zonder relatiegarantie</span></button><button class="btn" onclick="mailBrideScreen()">📬 International Dating<br><span class="mini">Ontmoet iemand uit het buitenland</span></button><button class="btn alt" onclick="closeModal()">Terug</button></div>`)}
function datingAppSetup(){if(state.age<18)return toast('Dating app is vanaf 18 jaar.');showModal(`<div class="modalTop"><div class="avatar">📲</div><div class="modalTitle">Dating App</div></div><div class="modalBody"><p>Gebruik de dating app om iemand te vinden. Kosten: ${money(100)}</p><label class="mini">Leeftijd</label><select id="dateAgeFilter" style="width:100%;padding:11px;margin:6px 0 12px;background:#100715;color:#fff;border:1px solid #5b3063;border-radius:5px;font-size:17px"><option value="18-19">18-19</option><option value="20-24">20-24</option><option value="25-34">25-34</option><option value="35-50">35-50</option></select><label class="mini">Wie zoek je?</label><select id="dateGenderFilter" style="width:100%;padding:11px;margin:6px 0 12px;background:#100715;color:#fff;border:1px solid #5b3063;border-radius:5px;font-size:17px"><option value="any">Maakt niet uit</option><option value="female">Vrouw</option><option value="male">Man</option></select><label class="mini">Net worth</label><select id="dateWorthFilter" style="width:100%;padding:11px;margin:6px 0 12px;background:#100715;color:#fff;border:1px solid #5b3063;border-radius:5px;font-size:17px"><option value="any">Maakt niet uit</option><option value="low">Normaal</option><option value="rich">Rijk</option></select><button class="btn" onclick="datingAppResults()">Let's try it</button><button class="btn alt" onclick="loveScreen()">Terug</button></div>`)}
function datingAppResults(){if(state.money<100)return toast('Je hebt €100 nodig voor de dating app.');state.money-=100;let gf=$('dateGenderFilter')?.value||'any';let af=$('dateAgeFilter')?.value||'18-19';let wf=$('dateWorthFilter')?.value||'any';let [min,max]=af.split('-').map(Number);let people=[1,2,3,4].map(()=>{let gender=gf==='any'?normalizeDateGender('any'):gf;let age=r(min,max);let rel=r(35,85)+(wf==='rich'?r(-8,5):0);return {name:dateName(gender),age,rel:clamp(rel),married:false,gender,icon:dateIcon(gender,age),worth:wf==='rich'?r(70,98):r(5,70),source:'datingApp'}});window._dateChoices=people;showModal(`<div class="modalTop"><div class="avatar">📲</div><div class="modalTitle">Dating App</div></div><div class="modalBody"><p>Kies iemand. De klikscore bepaalt of het serieus wordt.</p>${people.map((p,i)=>`<button class="btn" onclick="chooseDateIndex(${i})">${p.icon} ${p.name}<br><span class="mini">${genderLabel(p)} · ${p.age} jaar · klik ${p.rel}% · money ${p.worth}%</span></button>`).join('')}<button class="btn alt" onclick="datingAppSetup()">Terug</button></div>`);render()}
function createLoveInterest(kind='date',forcedGender='any'){let g=forcedGender==='any'?normalizeDateGender('any'):normalizeDateGender(forcedGender);let age=kind==='mail'?r(23,36):kind==='celeb'?r(20,45):Math.max(16,state.age+r(-2,6));return {name:dateName(g),age,rel:r(30,86),gender:g,icon:dateIcon(g,age),looks:r(25,98),smarts:r(15,95),money:kind==='celeb'?r(70,100):kind==='mail'?r(5,60):r(0,85),craziness:r(0,75),married:false,source:kind}}
function loveInterestModal(p,mode='date'){window._loveInterest=p;let title=mode==='hook'?'Hook Up':mode==='mail'?'International Dating':mode==='celeb'?'Celebrity Dating App':'Love Interest';let desc=mode==='hook'?`Je hebt een kans op een losse date met ${p.name}. Geen relatiegarantie.`:mode==='mail'?`Je ontmoet ${p.name} via internationale dating. Het is duurder en riskanter, maar kan serieus worden.`:mode==='celeb'?`Je probeert een date te regelen met celebrity ${p.name}. De kans is klein, maar de beloning is groot.`:`Je ontmoette ${p.name} en er lijkt een klik te zijn.`;let fee=mode==='mail'?r(1500,5500):mode==='celeb'?r(500,2500):mode==='hook'?r(20,120):r(15,80);p.fee=fee;showModal(`<div class="modalTop"><div class="avatar">${p.icon}</div><div class="modalTitle">${p.name} <span style="float:right;font-style:italic">Love</span></div></div><div class="modalBody"><h2 style="color:#63dff0">${mode==='hook'?'🖤':mode==='mail'?'📬':mode==='celeb'?'🌟':'❤️'} ${title}</h2><p>${desc}</p><div class="card"><b>Name:</b> ${p.name}<br><b>Gender:</b> ${genderLabel(p)}<br><b>Age:</b> ${p.age}<br><b>Cost:</b> ${money(fee)}</div><div class="card">Looks ${relationBar(p.looks)}<br>Smarts ${relationBar(p.smarts)}<br>Money ${relationBar(p.money)}<br>Craziness ${relationBar(p.craziness)}</div><button class="btn" onclick="resolveLoveInterest('${mode}')">${mode==='hook'?'Hook up':mode==='mail'?'See if this becomes serious':mode==='celeb'?'Ask celebrity on a date':'Ask on a date'}</button><button class="btn alt" onclick="loveScreen()">Nee, niet mijn type</button></div>`)}
function resolveLoveInterest(mode){let p=window._loveInterest;if(!p)return;if(state.money<(p.fee||0))return toast('Niet genoeg geld.');state.money-=p.fee||0;let base=mode==='celeb'?0.18:mode==='mail'?0.40:mode==='hook'?0.48:0.62;let chance=base+(state.stats.Looks||50)/240+(state.stats.Happiness||50)/300-(p.craziness||0)/500;closeModal();if(mode==='hook'){let ok=Math.random()<chance;action('Hook Up',ok?`Ik had een losse date met ${p.name}. Het was leuk, maar het werd geen vaste relatie.`:`Ik probeerde iets met ${p.name}, maar het liep ongemakkelijk en snel dood.`,{Happiness:ok?6:-4,Looks:ok?1:-1},0,ok?'good':'bad');return;}if(Math.random()<chance){state.partner={name:p.name,age:p.age,rel:clamp(p.rel+r(5,18)),married:false,gender:p.gender,icon:p.icon,source:mode};action('Love',`${p.name} wilde mij beter leren kennen. ${p.name} staat nu bij Relationships als partner.`,{Happiness:12,Looks:1},0,'good')}else{action('Love',`${p.name} zag het toch niet zitten. Het bleef bij een mislukte poging.`,{Happiness:-8},0,'bad')}}
