function ensureJamaica(){state.jamaica=state.jamaica||{days:0,vibe:50,beachRep:0,spent:0,memories:[]};return state.jamaica}
function jamaicaStatsHTML(){let j=ensureJamaica();return `<div class="jamaicaCard"><b>🇯🇲 Jamaica vakantie</b><br>Dagen op eiland: ${j.days||0}<br>Island vibe: ${clamp(j.vibe||50)}%<br>Beach rep: ${clamp(j.beachRep||0)}%<br>Uitgegeven: ${money(j.spent||0)}</div>`}
function jamaicaActivitiesHTML(){ensureJamaica();return `<div class="section">Jamaica Vacation DLC</div>${jamaicaStatsHTML()}${row('🏖️','Stranddag','Zwemmen, zonnen en relaxen aan zee','jamaicaActivity(\'beach\')')}${row('🎶','Reggae bar','Live muziek, dansen en nieuwe mensen ontmoeten','jamaicaActivity(\'reggae\')')}${row('🍗','Jerk food tour','Eten bij lokale tentjes, pittig en gezellig','jamaicaActivity(\'jerk\')')}${row('🤿','Snorkelen','Dieren tegenkomen: aaien, kijken of wegzwemmen','jamaicaSnorkelEvent()')}${row('🚶🏾','Wandelen op Jamaica','Random eiland-events die je dag beïnvloeden','jamaicaWalkEvent()')}${row('🛍️','Jamaica items kopen','Souvenirs, lokale spullen en island gear','jamaicaShopScreen()')}${row('🌿','Jamaica smoke shop','18+: wiet/jointjes met risico','jamaicaSmokeShop()',state.age<18)}${row('👥','Mensen ontmoeten','Nieuwe lokale contacten, vrienden en vibe','jamaicaMeetPeople()')}${row('💃🏾','Beach party social','Feesten, flirten en misschien hook-up','jamaicaPartySocial()')}${row('💦','Waterval hike','Natuurtrip met stamina/health-effect','jamaicaActivity(\'waterfall\')')}${row('🏨','Resort chill','Veilig ontspannen maar duur','jamaicaActivity(\'resort\')')}${row('🛍️','Lokale markt','Souvenirs, onderhandelen en random encounters','jamaicaActivity(\'market\')')}${row('🔥','Beach party','Feest op het strand met risico en fun','jamaicaActivity(\'party\')')}${row('🥃','Rum tasting','Volwassen activiteit met alcohol-risico','jamaicaActivity(\'rum\')',state.age<18)}${row('⚽','Voetbal op strand','Sporttalent en fitheid omhoog','jamaicaActivity(\'football\')')}${row('📞','Bel naar huis','Contact houden met familie/vrienden','jamaicaActivity(\'callhome\')')}${row('✈️','Terug naar huis','Vakantie beëindigen en terug naar normale wereld/Night City','returnFromJamaicaScreen()')}`}
function jamaicaActivity(kind){let j=ensureJamaica();j.days=(j.days||0)+1;let txt='',stats={},cash=0,type='good';
 if(kind==='beach'){txt=pick(['Ik lag op het strand en voelde mijn stress uit mijn lichaam lekken alsof de zon een resetknop was.','Ik dook de zee in en kwam terug met zand op plekken waarvan ik niet wist dat zand daar kon komen.','Ik chillde aan het water en vergat even al mijn rekeningen.']);stats={Happiness:8,Health:2,Stamina:2};j.vibe=clamp((j.vibe||50)+5)}
 if(kind==='reggae'){txt=pick(['Ik ging naar een reggae bar. Een oude muzikant zei dat ik danste alsof mijn knieën ruzie hadden.','De bass stond zo hard dat mijn hartslag op het ritme mee ging.','Ik leerde een paar locals kennen en deed alsof ik de tekst van elk nummer kende.']);stats={Happiness:10,Looks:1,Stamina:-4};cash=-r(35,120);j.beachRep=clamp((j.beachRep||0)+4)}
 if(kind==='jerk'){txt=pick(['Ik at jerk chicken die zo pittig was dat mijn ziel even uitlogde.','Ik volgde de geur van rook en kruiden en eindigde bij het beste eten van de vakantie.','Een kok lachte omdat ik stoer deed over pittig eten en daarna bijna moest huilen.']);stats={Happiness:8,Health:1,Stamina:-1};cash=-r(18,55)}
 if(kind==='snorkel'){let bad=Math.random()<.14;if(bad){txt='Tijdens het snorkelen raakte ik in paniek door de stroming. Ik kwam veilig terug, maar mijn hart zat in mijn keel.';stats={Happiness:-4,Health:-5,Stamina:-12};type='warn'}else{txt=pick(['Ik snorkelde boven helder water en zag vissen die eruitzagen alsof ze in 4K waren gerenderd.','Ik vond een schelp en voelde me drie seconden een ontdekkingsreiziger.','Onder water was het stil genoeg om mijn eigen gedachten eindelijk te horen.']);stats={Happiness:12,Health:3,Stamina:-6};j.vibe=clamp((j.vibe||50)+6)}}
 if(kind==='waterfall'){let slip=Math.random()<.12;if(slip){txt='Bij de waterval gleed ik uit op een natte steen. Geen ramp, wel een pijnlijke reminder dat slippers geen hike-gear zijn.';stats={Happiness:-3,Health:-8,Looks:-2,Stamina:-10};type='warn'}else{txt=pick(['Ik maakte een hike naar een waterval en voelde me alsof ik in een reisposter stond.','Het water was koud, maar ik sprong erin alsof ik in een videoclip zat.','Bovenaan het pad keek ik uit over groen, water en totale rust.']);stats={Happiness:11,Health:5,Fitness:3,Stamina:-9};j.beachRep=clamp((j.beachRep||0)+2)}}
 if(kind==='resort'){txt=pick(['Ik bleef in het resort en liet mijn hele planning oplossen in zwembadwater.','Ik bestelde iets met een parasolletje erin en voelde me rijker dan mijn rekening toeliet.','Ik deed niks. En precies dat was het punt.']);stats={Happiness:9,Health:2,Stamina:5};cash=-r(120,360)}
 if(kind==='market'){let scam=Math.random()<.16;if(scam){txt='Op de markt kocht ik een “handgemaakt uniek souvenir” dat verdacht veel op fabrieksspul leek. Ach ja, vakantie.';stats={Happiness:-1,Smarts:1};cash=-r(60,180);type='warn'}else{txt=pick(['Ik onderhandelde op de lokale markt en liep weg met souvenirs en een veel te grote glimlach.','Een verkoper noemde me “boss” en plots kocht ik drie dingen die ik niet nodig had.','Ik vond een klein kunstwerkje dat mijn hele vakantie samenvatte.']);stats={Happiness:7,Smarts:2};cash=-r(25,110)}}
 if(kind==='party'){let chaos=Math.random()<.2;if(chaos){txt='De beach party werd chaotisch. Iemand gooide drank over mijn schoenen en ik verloor mijn waardigheid ergens bij de speakers.';stats={Happiness:3,Health:-4,Stamina:-14};cash=-r(70,220);type='warn'}else{txt=pick(['Ik ging naar een beach party en danste tot mijn benen dachten dat ze ontslag konden nemen.','De zon ging onder, de muziek ging harder en ik voelde me even hoofdpersonage.','Ik ontmoette mensen uit drie landen en niemand wist de volgende ochtend nog wie de rekening betaalde.']);stats={Happiness:14,Looks:2,Stamina:-12};cash=-r(60,180);j.beachRep=clamp((j.beachRep||0)+8)}}
 if(kind==='rum'){if(state.age<18)return toast('Rum tasting kan pas vanaf 18.');txt=pick(['Ik deed een rum tasting en knikte alsof ik verstand had van “houttonen”.','De rum was sterker dan mijn motivatie om morgen vroeg op te staan.','Ik proefde lokale rum en mijn tong vroeg om een advocaat.']);stats={Happiness:7,Health:-4,Stamina:-8};cash=-r(45,140); if(state.addiction){state.addiction.alcoholUse=(state.addiction.alcoholUse||0)+2;if(state.addiction.alcoholUse>8&&Math.random()<.25)state.addiction.alcohol=true}type='warn'}
 if(kind==='football'){txt=pick(['Ik speelde voetbal op het strand. Mijn eerste aanname verdween bijna de zee in.','Ik deed mee met een potje strandvoetbal en scoorde alsof er scouts in de palmbomen zaten.','Ik speelde op blote voeten en ontdekte dat zand zowel veld als tegenstander is.']);stats={Happiness:9,Health:3,Fitness:4,Stamina:-8};state.talents=state.talents||{};state.talents.sport=clamp((state.talents.sport||0)+3);j.beachRep=clamp((j.beachRep||0)+5)}
 if(kind==='callhome'){txt=pick(['Ik belde naar huis en vertelde dat alles goed ging, behalve mijn budget.','Ik stuurde een foto van het strand en kreeg direct de vraag of ik wel goed smeerde.','Ik belde mijn familie en hoorde op de achtergrond gewoon weer het normale leven doorgaan.']);stats={Happiness:5,Smarts:1,Stamina:1};}
 j.spent=(j.spent||0)+Math.abs(cash<0?cash:0);action('Jamaica',txt,stats,cash,type);}

function jamaicaSnorkelEvent(){let fish=pick(JAMAICA_FISH_EVENTS);showModal(`<div class="modalTop"><div class="avatar">${fish.icon}</div><div class="modalTitle">Snorkelen</div></div><div class="modalBody"><div class="card">Je ziet een ${fish.name}. Hij/zij ${fish.look}.<br><br>Gevaar-score: ${fish.danger}%</div><button class="btn" onclick="jamaicaSnorkelChoice('${fish.name}','pet',${fish.danger})">Aanraken / aaien</button><button class="btn green" onclick="jamaicaSnorkelChoice('${fish.name}','watch',${fish.danger})">Alleen kijken</button><button class="btn alt" onclick="jamaicaSnorkelChoice('${fish.name}','swim',${fish.danger})">Wegzwemmen</button></div>`)}
function jamaicaSnorkelChoice(name,choice,danger){let j=ensureJamaica();j.days=(j.days||0)+1;let stats={},txt='',type='good';if(choice==='watch'){txt=`Ik bleef rustig kijken naar de ${name}. Het was precies spannend genoeg zonder dom te worden.`;stats={Happiness:8,Smarts:2,Stamina:-4};j.vibe=clamp((j.vibe||50)+4);}else if(choice==='swim'){txt=`Ik zag de ${name} en besloot netjes weg te zwemmen. Niet elke vakantiefoto is een ziekenhuisrekening waard.`;stats={Happiness:2,Smarts:3,Stamina:-3};type='warn';}else{let bite=Math.random()*100<danger;if(bite){let dmg=r(20,34);txt=`Ik probeerde de ${name} aan te raken. Slecht idee. Ik werd geraakt/gebeten en verloor ongeveer ${dmg}% health. Jamaica gaf me meteen een les nederigheid.`;stats={Health:-dmg,Happiness:-8,Stamina:-12,Smarts:-2};type='bad';}else{txt=`Ik raakte voorzichtig de ${name} aan en kwam ermee weg. Dom? Misschien. Vet verhaal? Absoluut.`;stats={Happiness:13,Looks:1,Smarts:-1,Stamina:-5};j.beachRep=clamp((j.beachRep||0)+5);}}closeModal();action('Jamaica snorkelen',txt,stats,0,type)}
function jamaicaShopScreen(){showModal(`<div class="modalTop"><div class="avatar">🛍️</div><div class="modalTitle">Jamaica shop</div></div><div class="modalBody"><div class="card">Koop Jamaicaanse souvenirs en island gear.</div>${JAMAICA_ITEMS.map((it,i)=>`<button class="btn" onclick="buyJamaicaItem(${i})">${it.icon} ${it.name}<br><span class="mini">${money(it.price)}</span></button>`).join('')}<button class="btn alt" onclick="closeModal()">Terug</button></div>`)}
function buyJamaicaItem(i){let it=JAMAICA_ITEMS[i];if(!it)return;if(state.money<it.price)return toast('Niet genoeg geld.');state.money-=it.price;state.items=state.items||[];state.items.push({name:'Jamaica: '+it.name,price:it.price,icon:it.icon,effect:it.effect||{}});applyStats(it.effect||{});let j=ensureJamaica();j.spent=(j.spent||0)+it.price;closeModal();action('Jamaica item',`Ik kocht ${it.name}. Het voelde als een klein stukje Jamaica voor in mijn inventory.`,it.effect||{},0,'good')}
function jamaicaSmokeShop(){if(state.age<18)return toast('Alleen 18+.');showModal(`<div class="modalTop"><div class="avatar">🌿</div><div class="modalTitle">Jamaica smoke shop</div></div><div class="modalBody"><div class="card">Volwassen keuze. Geeft vibe, maar kan Health/Smarts/Stamina en verslaving raken.</div><button class="btn" onclick="jamaicaSmoke('light')">🌿 Light island joint - €25</button><button class="btn" onclick="jamaicaSmoke('special')">🔥 Special strong joint - €60</button><button class="btn" onclick="jamaicaSmoke('skip')">Nee, toch niet</button><button class="btn alt" onclick="closeModal()">Terug</button></div>`)}
function jamaicaSmoke(kind){if(kind==='skip'){closeModal();action('Jamaica smoke shop','Ik keek even rond, maar besloot niks te kopen. Mijn longen deden een stille high five.',{Smarts:1,Health:1},0,'good');return;}let cost=kind==='special'?60:25;if(state.money<cost)return toast('Niet genoeg geld.');state.money-=cost;ensureAddiction();recordSubstance('weed',kind==='special'?3:1);let stats=kind==='special'?{Happiness:9,Health:-5,Smarts:-4,Stamina:-8}:{Happiness:5,Health:-2,Smarts:-2,Stamina:-4};let txt=kind==='special'?'Ik probeerde een sterke Jamaica-special. De vibe was hoog, maar mijn focus vertrok eerder dan mijn taxi.':'Ik nam een lichte island joint. Relaxed, maar niet gratis voor mijn health.';let j=ensureJamaica();j.spent=(j.spent||0)+cost;closeModal();action('Jamaica smoke',txt,stats,0,'warn')}
function jamaicaWalkEvent(){let ev=pick(JAMAICA_WALK_EVENTS);closeModal();let j=ensureJamaica();j.days=(j.days||0)+1;j.vibe=clamp((j.vibe||50)+r(-2,5));action(ev.t,ev.txt,ev.stats,ev.cash||0,ev.type||'good')}
function jamaicaMeetPeople(){let p=pick(JAMAICA_NPCS);let chance=45+Math.round((state.stats.Looks||50)/5)+Math.round((ensureJamaica().vibe||50)/8);showModal(`<div class="modalTop"><div class="avatar">${p.icon}</div><div class="modalTitle">${p.name}</div></div><div class="modalBody"><div class="card">${p.type}<br>${p.gender==='female'?'Vrouw':'Man'} · vibe: ${p.vibe}<br>Klikkans: ${chance}%</div><button class="btn" onclick="jamaicaFriend('${p.name}','${p.gender}','${p.icon}',${chance})">Praat en probeer vrienden te worden</button><button class="btn pink" onclick="jamaicaFlirt('${p.name}','${p.gender}','${p.icon}',${chance})">Flirten</button><button class="btn alt" onclick="closeModal()">Laat gaan</button></div>`)}
function jamaicaFriend(name,gender,icon,chance){let ok=Math.random()*100<chance;closeModal();if(ok){state.friends=state.friends||[];state.friends.push({name,gender,icon,rel:r(45,75),from:'Jamaica vakantie'});action('Jamaica contact',`Ik raakte aan de praat met ${name}. We lachten om precies dezelfde domme toeristendingen en werden vrienden.`,{Happiness:7},0,'good')}else action('Jamaica contact',`Ik probeerde met ${name} te connecten, maar het gesprek stierf sneller dan mijn telefoonbatterij op het strand.`,{Happiness:-2},0,'warn')}
function jamaicaFlirt(name,gender,icon,chance){let ok=Math.random()*100<(chance+(state.stats.Looks||50)/4);closeModal();if(ok)action('Jamaica flirt',`Ik flirtte met ${name}. De zon, muziek en die blik maakten het allemaal net iets spannender dan gepland.`,{Happiness:8,Looks:1,Stamina:-3},0,'good');else action('Jamaica flirt',`Ik probeerde te flirten met ${name}, maar mijn openingszin landde ergens tussen ongemakkelijk en toeristenbelasting.`,{Happiness:-3,Looks:-1},0,'warn')}
function jamaicaPartySocial(){let p=pick(JAMAICA_NPCS);let hookChance=35+Math.round((state.stats.Looks||50)/4)+Math.round((ensureJamaica().beachRep||0)/4);showModal(`<div class="modalTop"><div class="avatar">💃🏾</div><div class="modalTitle">Beach party</div></div><div class="modalBody"><div class="card">Je ontmoet ${p.icon} ${p.name}, ${p.type}.<br>Vibe: ${p.vibe}<br>Hook-up kans: ${hookChance}%</div><button class="btn" onclick="jamaicaPartyAction('dance','${p.name}','${p.gender}','${p.icon}',${hookChance})">Dansen en lol maken</button><button class="btn pink ${state.age<18?'locked':''}" onclick="${state.age>=18?`jamaicaPartyAction('hook','${p.name}','${p.gender}','${p.icon}',${hookChance})`:''}">18+ hook-up proberen</button><button class="btn alt" onclick="closeModal()">Rustig naar huis</button></div>`)}
function jamaicaPartyAction(kind,name,gender,icon,chance){closeModal();if(kind==='dance'){let j=ensureJamaica();j.beachRep=clamp((j.beachRep||0)+5);action('Jamaica party',`Ik danste met ${name}. Mijn ritme was discutabel, maar mijn confidence stond op standje vakantie.`,{Happiness:10,Looks:1,Stamina:-8},-r(20,80),'good');return;}let ok=Math.random()*100<chance;if(ok){action('Jamaica hook-up',`Ik had een spannende nacht met ${name}. Het bleef vakantie-chaos, geen automatische relatie.`,{Happiness:13,Health:-2,Stamina:-14},-r(30,120),'good')}else action('Jamaica hook-up',`Ik dacht dat er chemistry was met ${name}, maar blijkbaar sprak ik vloeiend verkeerde signalen.`,{Happiness:-4,Looks:-1,Stamina:-4},-r(10,40),'warn')}

function returnFromJamaicaScreen(){let j=ensureJamaica();showModal(`<div class="modalTop"><div class="avatar">✈️</div><div class="modalTitle">Terug naar huis?</div></div><div class="modalBody">${jamaicaStatsHTML()}<p>Je kunt je Jamaica-vakantie beëindigen. Je thema gaat terug naar je oude wereld.</p><button class="btn green" onclick="returnFromJamaica()">Ja, terug naar huis</button><button class="btn alt" onclick="closeModal()">Nog even blijven</button></div>`)}
function returnFromJamaica(){let j=ensureJamaica();state.vacation=null;state.world=state.homeWorldBeforeVacation||'normal';let msg=`Na ${j.days||0} dagen Jamaica vloog ik terug. Ik nam zon, verhalen en een beetje zand in mijn tas mee.`;closeModal();action('Terug van Jamaica',msg,{Happiness:6,Smarts:2,Stamina:-3},0,'good');openScreen('life')}

function ensureFootball(){
  state.talents=state.talents||{};
  ['sport','thief','social','tech','combat','honesty','discipline','stress','drive','race'].forEach(k=>state.talents[k]=state.talents[k]||0);
  let f=state.football||{};
  let oldContract=!!f.contract;
  state.football={
    active:!!f.active||!!f.club||oldContract,
    level:f.level||'none',
    club:f.club||null,
    position:f.position||null,
    skill:clamp(f.skill??(state.talents.sport||0)),
    form:clamp(f.form??50),
    coachTrust:clamp(f.coachTrust??50),
    injuryRisk:clamp(f.injuryRisk??10),
    salary:f.salary||0,
    fame:clamp(f.fame??0),
    matches:f.matches||0,
    goals:f.goals||0,
    assists:f.assists||0,
    scout:!!f.scout,
    contract:oldContract,
    injured:!!f.injured,
    injuryYears:f.injuryYears||0,
    manager:f.manager||null,
    lastMediaAge:f.lastMediaAge??-99,
    lastScoutAge:f.lastScoutAge??-99
  };
  if(state.football.level==='recreatief')state.football.level='none';
  return state.football;
}
function ensureMega(){state.talents=state.talents||{sport:0,thief:0,social:0,tech:0,combat:0,honesty:0,discipline:0,stress:0,drive:0,race:0};state.talents.drive=state.talents.drive||0;state.talents.race=state.talents.race||0;state.mental=state.mental||{stress:Math.max(0,100-(state.stats?.Happiness||60)),trauma:0,burnout:0};state.businesses=state.businesses||[];ensureFootball();state.legacy=state.legacy||{generation:1,familyName:(state.name||'').split(' ').slice(-1)[0]||'Familie',fame:0};state.lifeGoals=state.lifeGoals||{};}
function skillBar(v){return `<div class="resultBar"><div class="resultFill ${v<30?'low':''}" style="width:${clamp(v)}%"></div></div>`}
function skillTreeScreen(){ensureMega();let t=state.talents;showModal(`<div class="modalTop"><div class="avatar">📈</div><div class="modalTitle">Skill Tree</div></div><div class="modalBody"><div class="card">Je keuzes vormen je karakter. Skills bepalen kansen bij werk, voetbal, crime, Night City en sociale events.</div>${[['Sporttalent','sport','⚽'],['Dief-talent','thief','🕶️'],['Sociaal talent','social','🗣️'],['Tech Skill','tech','🖥️'],['Combat','combat','🥊'],['Drive Skill','drive','🚗'],['Race Skill','race','🏁'],['Eerlijkheid','honesty','⚖️'],['Discipline','discipline','🎯']].map(x=>`<div class="card"><b>${x[2]} ${x[0]}</b>${skillBar(t[x[1]]||0)}</div>`).join('')}<button class="btn alt" onclick="closeModal()">Terug</button></div>`)}
function lifeGoalsScreen(){ensureMega();let goals=[['Miljonair',netWorth()>=1000000],['Gezin opgebouwd',(state.children||[]).length>=2],['Street Legend',state.nc&&state.nc.streetCred>=80],['Profvoetballer',state.football&&state.football.contract],['Fixer Empire',state.nc&&state.nc.fixerEmpire],['Survivor',state.age>=80],['Legacy gestart',(state.legacy&&state.legacy.generation>1)]];showModal(`<div class="modalTop"><div class="avatar">🎯</div><div class="modalTitle">Life Goals</div></div><div class="modalBody">${goals.map(g=>`<div class="card">${g[1]?'✅':'⬜'} <b>${g[0]}</b></div>`).join('')}<button class="btn alt" onclick="closeModal()">Terug</button></div>`)}
function legacyScreen(){ensureMega();let fam=(state.siblings||[]).map(s=>`${s.icon||'🧑'} ${s.name} · ${s.age} jaar${s.children&&s.children.length?' · kinderen: '+s.children.map(c=>c.name).join(', '):''}`).join('<br>')||'Geen broers/zussen bekend.';let kids=(state.children||[]).map(c=>`${c.icon||'👶'} ${c.name} · ${c.age} jaar`).join('<br>')||'Geen kinderen.';showModal(`<div class="modalTop"><div class="avatar">🌳</div><div class="modalTitle">Family Tree</div></div><div class="modalBody"><div class="card"><b>Generatie:</b> ${state.legacy.generation}<br><b>Familienaam:</b> ${state.legacy.familyName}<br><b>Familie-reputatie:</b> ${state.legacy.fame||0}</div><div class="section">Kinderen</div><div class="card">${kids}</div><div class="section">Broers/zussen & neefjes/nichtjes</div><div class="card">${fam}</div><button class="btn alt" onclick="closeModal()">Terug</button></div>`)}
function mentalHealthScreen(){ensureMega();showModal(`<div class="modalTop"><div class="avatar">🧠</div><div class="modalTitle">Mental Health</div></div><div class="modalBody"><div class="card"><b>Stress</b>${skillBar(100-(state.mental.stress||0))}<br><b>Trauma:</b> ${state.mental.trauma||0}<br><b>Burn-out:</b> ${state.mental.burnout||0}</div><button class="btn" onclick="mentalAction('therapy')">🛋️ Therapie</button><button class="btn" onclick="mentalAction('rest')">😴 Rust nemen</button><button class="btn" onclick="mentalAction('family')">☎️ Steun zoeken bij familie</button><button class="btn alt" onclick="closeModal()">Terug</button></div>`)}
function mentalAction(kind){ensureMega();let cash=0,txt='',stats={};if(kind==='therapy'){cash=-120;state.mental.stress=Math.max(0,(state.mental.stress||0)-18);state.mental.trauma=Math.max(0,(state.mental.trauma||0)-8);txt='Ik ging naar therapie. Het loste niet alles op, maar mijn hoofd werd rustiger.';stats={Happiness:8,Smarts:1};}if(kind==='rest'){state.mental.stress=Math.max(0,(state.mental.stress||0)-10);txt='Ik nam bewust rust. Geen grote stappen, maar wel ademruimte.';stats={Happiness:5,Health:3,Stamina:12};}if(kind==='family'){state.mental.stress=Math.max(0,(state.mental.stress||0)-7);txt='Ik zocht steun bij familie. Het gesprek deed meer dan ik wilde toegeven.';stats={Happiness:6};}closeModal();action('Mental Health',txt,stats,cash,'good')}
function businessScreen(){ensureMega();showModal(`<div class="modalTop"><div class="avatar">🏪</div><div class="modalTitle">Business</div></div><div class="modalBody"><div class="card">Start iets naast je werk. Business kan groeien of falen.</div><button class="btn" onclick="startBusiness('webshop')">📦 Webshop starten (€500)</button><button class="btn" onclick="startBusiness('kanaal')">📱 TikTok/YouTube kanaal (€100)</button><button class="btn" onclick="startBusiness('snackbar')">🍟 Snackbar beginnen (€8500)</button>${state.world==='nightcity'?`<button class="btn" onclick="startBusiness('nc_hustle')">🌃 Night City side hustle (€1200)</button>`:''}<div class="section">Mijn businesses</div>${(state.businesses||[]).map((b,i)=>`<button class="btn" onclick="businessManage(${i})">${b.icon} ${b.name}<br><span class="mini">level ${b.level} · winst ${money(b.profit)}/jr · risico ${b.risk}%</span></button>`).join('')||'<div class="card">Nog geen business.</div>'}<button class="btn alt" onclick="closeModal()">Terug</button></div>`)}
function startBusiness(type){ensureMega();let map={webshop:{name:'Webshop',cost:500,icon:'📦',risk:18,profit:200},kanaal:{name:'Content kanaal',cost:100,icon:'📱',risk:22,profit:80},snackbar:{name:'Snackbar',cost:8500,icon:'🍟',risk:28,profit:2600},nc_hustle:{name:'Night City hustle',cost:1200,icon:'🌃',risk:45,profit:1200}};let b=map[type];if(state.money<b.cost)return toast('Niet genoeg geld.');state.money-=b.cost;state.businesses.push({...b,level:1});closeModal();action('Business',`Ik startte een ${b.name}. Vanaf nu kan dit elk jaar geld opleveren, of juist gedoe geven.`,{Happiness:4,Smarts:2},0,'good')}
function businessManage(i){let b=state.businesses[i];if(!b)return;showModal(`<div class="modalTop"><div class="avatar">${b.icon}</div><div class="modalTitle">${b.name}</div></div><div class="modalBody"><div class="card">Level ${b.level}<br>Verwachte winst: ${money(b.profit)}/jr<br>Risico: ${b.risk}%</div><button class="btn" onclick="investBusiness(${i})">📈 Investeren ${money(500*b.level)}</button><button class="btn red" onclick="sellBusiness(${i})">Verkopen</button><button class="btn alt" onclick="businessScreen()">Terug</button></div>`)}
function investBusiness(i){let b=state.businesses[i],cost=500*b.level;if(state.money<cost)return toast('Niet genoeg geld.');state.money-=cost;b.level++;b.profit=Math.round(b.profit*1.55);b.risk=Math.max(5,b.risk-3);closeModal();action('Business',`Ik investeerde in ${b.name}. Het bedrijf werd serieuzer.`,{Smarts:2,Discipline:1},0,'good')}
function sellBusiness(i){let b=state.businesses[i];let val=Math.round((b.profit*2)+(b.level*400));state.businesses.splice(i,1);state.money+=val;closeModal();action('Business',`Ik verkocht ${b.name}.`,{Happiness:3},0,'good');addLog(`<b>Business verkoop</b><br>Opbrengst: ${money(val)}`,'good')}

const FOOTBALL_CLUBS={
  youth:['FC Enkhuizen O17','West-Friesland Youth','Tobias Dahl Academy','Oranje Talenten O18'],
  amateur:['VV Enkhuizen','CSV Jong Holland','West-Friesland FC','SV De Dijk Amateurs'],
  street:['Parkplein Street XI','Haven Boys Straatteam','Koopgoot Five','Night Court Ballers'],
  academy:['AZ Scoutdag','Ajax Open Academy','FC Utrecht Talentendag','PSV Regionale Proeftraining']
};
const FOOTBALL_LEVEL_LABEL={none:'Geen club',youth:'Jeugdteam',amateur:'Amateurclub',street:'Straatvoetbalteam',academy:'Academy/Scoutdag',semi:'Semi-prof',pro:'Profclub',top:'Topclub'};
const FOOTBALL_POSITIONS=['Keeper','Verdediger','Middenvelder','Aanvaller'];
function footballCareerScreen(){ensureMega();let f=ensureFootball();if(state.age<15){showModal(`<div class="modalTop"><div class="avatar">⚽</div><div class="modalTitle">Football Career</div></div><div class="modalBody"><div class="card">Beschikbaar vanaf 15 jaar.<br>Blijf tot die tijd voetballen om sporttalent op te bouwen.</div><button class="btn alt" onclick="closeModal()">Terug</button></div>`);return}
 let contractTxt=f.contract?`${money(f.salary)}/jaar`:(f.salary?`${money(f.salary)}/jaar vergoeding`:'geen');
 let injured=f.injured?`<br><span style="color:#ff6b5a"><b>Geblesseerd:</b> ${f.injuryYears||1} jaar herstel</span>`:'';
 showModal(`<div class="modalTop"><div class="avatar">⚽</div><div class="modalTitle">Football Career</div></div><div class="modalBody">
 <div class="card"><b>Status:</b> ${FOOTBALL_LEVEL_LABEL[f.level]||f.level}<br><b>Club:</b> ${f.club||'geen'}<br><b>Positie:</b> ${f.position||'nog niet gekozen'}<br><b>Contract:</b> ${contractTxt}<br><b>Coach vertrouwen:</b> ${f.coachTrust}% ${skillBar(f.coachTrust)}<br><b>Vorm:</b> ${f.form}% ${skillBar(f.form)}<br><b>Football Skill:</b> ${f.skill}% ${skillBar(f.skill)}<br><b>Fame:</b> ${f.fame}% ${skillBar(f.fame)}<br><b>Stats:</b> ${f.matches} wedstrijden · ${f.goals} goals · ${f.assists} assists${injured}</div>
 ${!f.active?`<button class="btn" onclick="footballTryoutScreen()">📝 Try-out doen</button>`:`<button class="btn" onclick="footballTrainScreen()">🏋️ Trainen</button><button class="btn ${f.injured?'locked':''}" onclick="${f.injured?'':`footballMatch()`}">🏟️ Wedstrijd spelen</button><button class="btn" onclick="footballCoachTalk()">🧢 Coach spreken</button><button class="btn" onclick="footballContractScreen()">📄 Contract / manager</button><button class="btn gold" onclick="footballTransferScreen()">🔎 Andere club / niveau omhoog</button><button class="btn" onclick="footballRestRehab()">🩹 Rust / revalidatie</button><button class="btn red" onclick="footballQuit()">Stoppen met voetbal</button>`}
 <button class="btn alt" onclick="closeModal()">Terug</button></div>`)}
function footballTryoutScreen(){ensureMega();showModal(`<div class="modalTop"><div class="avatar">📝</div><div class="modalTitle">Try-out</div></div><div class="modalBody"><div class="card">Je try-out kans hangt af van sporttalent, fitness, stamina, health, discipline en je leeftijd.</div>${[['youth','Jeugdteam'],['amateur','Amateurclub'],['street','Straatvoetbalteam'],['academy','Academy / scoutdag']].map(x=>`<button class="btn" onclick="footballPickPosition('${x[0]}')">${x[1]}<br><span class="mini">Kies daarna je positie</span></button>`).join('')}<button class="btn alt" onclick="footballCareerScreen()">Terug</button></div>`)}
function footballPickPosition(type){showModal(`<div class="modalTop"><div class="avatar">⚽</div><div class="modalTitle">Kies positie</div></div><div class="modalBody"><div class="card">Elke positie gebruikt andere sterke punten.</div>${FOOTBALL_POSITIONS.map(p=>`<button class="btn" onclick="footballTryout('${type}','${p}')">${p}</button>`).join('')}<button class="btn alt" onclick="footballTryoutScreen()">Terug</button></div>`)}
function footballTryout(type,pos){ensureMega();let f=ensureFootball(),t=state.talents;let base=(t.sport||0)*.35+(state.fitness||50)*.22+(state.stamina||50)*.14+(state.stats.Health||50)*.12+(t.discipline||0)*.10+(state.stats.Smarts||50)*.07;let ageBonus=state.age<=19?8:state.age<=24?2:-8;let typeDiff={youth:38,street:42,amateur:50,academy:58}[type]||45;let chance=clamp(Math.round(base+ageBonus-typeDiff+50));let ok=r(1,100)<=chance;closeModal();if(ok){f.active=true;f.level=type;f.club=pick(FOOTBALL_CLUBS[type]);f.position=pos;f.skill=clamp(Math.round((t.sport||0)*.55+(state.fitness||50)*.25+r(5,20)));f.form=r(45,70);f.coachTrust=r(42,66);f.injuryRisk=r(8,18);if(type==='amateur'){f.salary=1200}else if(type==='academy'){f.salary=0}else if(type==='street'){f.salary=0}else f.salary=0;action('Try-out',`Ik deed try-out als ${pos} bij ${f.club}. Ik werd aangenomen.`,{Happiness:12,Fitness:3,Stamina:-10},0,'good');addLog(`<b>Football Career</b><br>Mijn kans was ongeveer ${chance}%. Ik zit nu bij ${f.club}.`,'good');}else{state.talents.sport=clamp((state.talents.sport||0)+2);action('Try-out',`Ik deed try-out als ${pos}, maar was nog niet goed genoeg. De coach zei dat ik sterker terug moest komen.`,{Happiness:-4,Fitness:1,Stamina:-10},0,'warn');addLog(`<b>Try-out</b><br>Mijn kans was ongeveer ${chance}%. Ik werd afgewezen, maar leerde ervan.`,'warn');}}
function footballTrainScreen(){ensureMega();let f=ensureFootball();showModal(`<div class="modalTop"><div class="avatar">🏋️</div><div class="modalTitle">Voetbaltraining</div></div><div class="modalBody"><button class="btn" onclick="footballTrain('condition')">🏃 Conditietraining</button><button class="btn" onclick="footballTrain('technique')">⚽ Techniektraining</button><button class="btn" onclick="footballTrain('strength')">💪 Krachttraining</button><button class="btn" onclick="footballTrain('tactics')">📋 Tactiek leren</button><button class="btn green" onclick="footballTrain('rest')">😴 Rust nemen</button><button class="btn alt" onclick="footballCareerScreen()">Terug</button></div>`)}
function footballTrain(kind){ensureMega();let f=ensureFootball(),t=state.talents;let txt='',stats={},risk=0;if(kind==='condition'){f.form=clamp(f.form+r(3,8));f.skill=clamp(f.skill+r(1,4));t.sport=clamp((t.sport||0)+3);txt='Ik deed conditietraining. Mijn longen brandden, maar mijn vorm ging omhoog.';stats={Fitness:5,Stamina:4,Health:1};risk=4}if(kind==='technique'){f.skill=clamp(f.skill+r(4,8));f.form=clamp(f.form+r(1,5));t.sport=clamp((t.sport||0)+4);txt='Ik werkte aan techniek: aannames, passing en afronden. De bal voelde beter aan mijn voet.';stats={Fitness:2,Stamina:-4};risk=3}if(kind==='strength'){f.injuryRisk=clamp(f.injuryRisk+r(1,4));f.skill=clamp(f.skill+r(2,5));t.sport=clamp((t.sport||0)+3);txt='Ik deed krachttraining. Ik werd sterker, maar mijn blessurerisico steeg een beetje.';stats={Fitness:6,Health:1,Stamina:-8};risk=7}if(kind==='tactics'){f.coachTrust=clamp(f.coachTrust+r(4,9));f.skill=clamp(f.skill+r(1,4));t.discipline=clamp((t.discipline||0)+3);txt='Ik bestudeerde tactiek. De coach merkte dat ik het spel beter begon te lezen.';stats={Smarts:3,Stamina:-2};risk=1}if(kind==='rest'){f.injuryRisk=clamp(f.injuryRisk-r(5,12));f.form=clamp(f.form-r(0,3));txt='Ik nam rust en liet mijn lichaam herstellen. Soms is niet trainen ook trainen.';stats={Health:5,Stamina:14,Happiness:2};risk=0}closeModal();if(r(1,100)<risk+Math.max(0,f.injuryRisk-70)){footballInjury('training');return}action('Voetbaltraining',txt,stats,0,'good')}
function footballMatch(){ensureMega();let f=ensureFootball(),t=state.talents;if(!f.active)return toast('Je hebt nog geen club.');if(f.injured)return toast('Je bent geblesseerd.');let matchPower=f.skill*.38+f.form*.22+f.coachTrust*.14+(state.fitness||50)*.12+(state.stamina||50)*.08+(t.discipline||0)*.06+r(-20,35);let great=matchPower>78,good=matchPower>58,bad=matchPower<35;f.matches++;f.form=clamp(f.form+(great?r(4,10):good?r(1,5):-r(3,9)));f.coachTrust=clamp(f.coachTrust+(great?r(5,10):good?r(1,4):-r(4,10)));let goals=0,assists=0;if(f.position==='Aanvaller')goals=great?r(1,3):(good&&Math.random()<.45?1:0);if(f.position==='Middenvelder')assists=great?r(1,3):(good&&Math.random()<.55?1:0);if(f.position==='Verdediger'&&great&&Math.random()<.25)goals=1;if(f.position==='Keeper'&&great)assists=0;f.goals+=goals;f.assists+=assists;let cash=0;if(f.level==='amateur')cash=r(50,250);if(f.level==='semi')cash=r(300,900);if(f.level==='pro')cash=r(1000,4500);if(f.level==='top')cash=r(3500,15000);let text=great?`Ik speelde fantastisch. ${goals?`Ik scoorde ${goals} keer. `:''}${assists?`Ik gaf ${assists} assist(s). `:''}De coach was zichtbaar tevreden.`:good?`Ik speelde een degelijke wedstrijd. ${goals?'Ik prikte er eentje in. ':''}${assists?'Ik gaf een assist. ':''}`:`Ik speelde zwak. Mijn timing zat verkeerd en de coach keek niet blij.`;let scoutChance=(great?0.30:good?0.10:0.01)+(f.level==='academy'?0.15:0);if(Math.random()<scoutChance&&state.age-(f.lastScoutAge??-99)>1){f.scout=true;f.lastScoutAge=state.age;addLog(`<b>Scout</b><br>Een scout zat op de tribune en noteerde mijn naam na de wedstrijd.`, 'good', false);}
 let injChance=f.injuryRisk*.004+(bad?0.04:0.015);closeModal();if(Math.random()<injChance){footballInjury('wedstrijd');return}action('Voetbalwedstrijd',text,{Happiness:great?11:good?5:-5,Fitness:2,Stamina:-14},cash,great||good?'good':'warn');footballMaybeProgress();}
function footballMaybeProgress(){let f=ensureFootball();if(!f.active)return;let score=f.skill+f.form+f.coachTrust+f.fame+(f.scout?20:0);if(f.level==='youth'&&state.age>=16&&score>210){f.level='amateur';f.club=pick(FOOTBALL_CLUBS.amateur);f.salary=1800;addLog(`<b>Transfer</b><br>Ik maakte de stap naar ${f.club}. Ik kreeg nu een kleine vergoeding.`, 'good', false)}else if((f.level==='amateur'||f.level==='academy')&&score>260){f.level='semi';f.club=pick(['FC Volendam Jong','Jong AZ Regionaal','West-Friesland Semi-Pro','Night City Strikers B']);f.salary=r(9600,24000);f.contract=true;state.job={title:'Semi-prof voetballer',salary:f.salary,req:'none',minAge:16,field:'Sport'};addLog(`<b>Contract</b><br>Ik tekende een semi-prof contract bij ${f.club}: ${money(f.salary)}/jaar.`, 'good', false)}else if(f.level==='semi'&&score>315){f.level='pro';f.club=pick(['FC Volendam','AZ','FC Utrecht','Ajax','PSV','Night City Strikers']);f.salary=r(36000,180000);f.contract=true;state.job={title:'Profvoetballer',salary:f.salary,req:'none',minAge:16,field:'Sport'};addLog(`<b>Profcontract</b><br>Ik werd prof bij ${f.club}. Salaris: ${money(f.salary)}/jaar.`, 'good', false)}else if(f.level==='pro'&&score>370&&f.fame>55){f.level='top';f.club=pick(['Ajax','PSV','Feyenoord','Borussia Dortmund','Arsenal','Night City United']);f.salary=r(250000,2400000);state.job={title:'Topvoetballer',salary:f.salary,req:'none',minAge:16,field:'Sport'};addLog(`<b>Toptransfer</b><br>Ik maakte een grote transfer naar ${f.club}. Salaris: ${money(f.salary)}/jaar.`, 'good', false)}}

const FOOTBALL_LEVEL_ORDER=['youth','street','amateur','academy','semi','pro','top'];
const FOOTBALL_TRANSFER_CLUBS={
  youth:['FC Enkhuizen O18','West-Friesland Talentteam','Oranje Jeugd Selectie','Hoorn Youth Academy'],
  street:['Havenplein Street XI','Night Court Ballers','Neon Cage FC','Parkplein Straatteam'],
  amateur:['VV Enkhuizen','CSV Jong Holland','West-Friesland FC','SV De Dijk Amateurs','FC Medemblik'],
  academy:['AZ Academy','Ajax Talentendag','FC Utrecht Academy','PSV Regionale Academy'],
  semi:['FC Volendam Jong','Jong AZ Regionaal','West-Friesland Semi-Pro','Night City Strikers B','Hollandia Semi-Pro'],
  pro:['FC Volendam','AZ','FC Utrecht','Sparta Rotterdam','Night City Strikers','Ajax'],
  top:['Ajax','PSV','Feyenoord','Borussia Dortmund','Arsenal','Night City United','FC Barcelona B']
};
const FOOTBALL_LEVEL_SALARY={youth:0,street:250,amateur:1800,academy:0,semi:18000,pro:90000,top:850000};
function footballNextLevel(level){let i=FOOTBALL_LEVEL_ORDER.indexOf(level);if(i<0)return 'youth';if(level==='street')return 'amateur';if(level==='academy')return 'semi';return FOOTBALL_LEVEL_ORDER[Math.min(FOOTBALL_LEVEL_ORDER.length-1,i+1)]}
function footballTransferScreen(){ensureMega();let f=ensureFootball();if(!f.active){toast('Je hebt nog geen club. Doe eerst een try-out.');return}let next=footballNextLevel(f.level);let current=FOOTBALL_LEVEL_LABEL[f.level]||f.level;let nextLabel=FOOTBALL_LEVEL_LABEL[next]||next;let score=footballTransferScore();let status=score>80?'grote kans':score>60?'redelijke kans':score>42?'twijfelgeval':'lastig';showModal(`<div class="modalTop"><div class="avatar">🔎</div><div class="modalTitle">Andere club zoeken</div></div><div class="modalBody"><div class="card"><b>Huidige club:</b> ${f.club||'geen'}<br><b>Huidig niveau:</b> ${current}<br><b>Transferprofiel:</b> ${status}<br><br>Je kans hangt af van Football Skill, vorm, coach vertrouwen, sporttalent, fame, leeftijd, scoutstatus en blessures.</div><button class="btn" onclick="footballApplyClub('same')">🔁 Andere club op zelfde niveau zoeken</button>${next!==f.level?`<button class="btn gold" onclick="footballApplyClub('up')">⬆️ Niveau omhoog proberen naar ${nextLabel}</button>`:''}<button class="btn" onclick="footballOpenTrials()">👀 Open proeftraining zoeken</button><button class="btn alt" onclick="footballCareerScreen()">Terug</button></div>`)}
function footballTransferScore(){let f=ensureFootball();let t=state.talents||{};let ageBonus=state.age<18?8:state.age<25?12:state.age<31?6:-8;let injuryPenalty=f.injured?35:0;return Math.round((f.skill||0)*.30+(f.form||0)*.20+(f.coachTrust||0)*.14+(t.sport||0)*.16+(f.fame||0)*.16+(f.scout?12:0)+ageBonus-injuryPenalty+r(-10,10));}
function footballApplyClub(mode){let f=ensureFootball();let target=mode==='up'?footballNextLevel(f.level):f.level;let score=footballTransferScore()-(mode==='up'?18:0);let chance=Math.max(8,Math.min(92,score));let roll=r(1,100);if(roll<=chance){let clubs=FOOTBALL_TRANSFER_CLUBS[target]||FOOTBALL_TRANSFER_CLUBS.amateur;let old=f.club;let newClub=pick(clubs);f.club=newClub;f.level=target;f.scout=false;f.form=clamp((f.form||50)+r(2,10));f.coachTrust=clamp(45+r(0,22));let base=FOOTBALL_LEVEL_SALARY[target]||0;let managerBonus=f.manager?1+(f.manager.bonus||0)/100:1;f.salary=Math.round(base*managerBonus*r(85,130)/100);f.contract=['semi','pro','top'].includes(target);if(f.contract){let title=target==='top'?'Topvoetballer':target==='pro'?'Profvoetballer':'Semi-prof voetballer';state.job={title,salary:f.salary,req:'none',minAge:16,field:'Sport'};}closeModal();action('Transfer',`${old?old+' liet me gaan. ':''}Ik kreeg een aanbod van ${newClub} en maakte de stap naar ${FOOTBALL_LEVEL_LABEL[target]||target}. ${f.salary?`Mijn vergoeding/salaris werd ${money(f.salary)}/jaar.`:'Het was nog vooral voor ervaring.'}`,{Happiness:12,Fitness:2},0,'good');return}
let near=roll<=chance+18;if(near){f.form=clamp((f.form||50)+r(-3,4));f.coachTrust=clamp((f.coachTrust||50)-r(1,5));closeModal();action('Proeftraining',`Ik mocht meetrainen, maar de club twijfelde. Ze vonden mijn niveau nog net niet overtuigend genoeg.`,{Happiness:-3,Smarts:1,Stamina:-8},0,'warn');return}
f.form=clamp((f.form||50)-r(4,12));f.coachTrust=clamp((f.coachTrust||50)-r(2,8));closeModal();action('Afwijzing',`Ik zocht een nieuwe club, maar kreeg een harde afwijzing. Mijn huidige coach hoorde ervan en was niet blij met mijn timing.`,{Happiness:-8,Stamina:-4},0,'bad')}
function footballOpenTrials(){let f=ensureFootball();let chance=Math.max(10,Math.min(80,footballTransferScore()-8));let ok=r(1,100)<=chance;if(ok){f.scout=true;f.form=clamp((f.form||50)+r(4,10));closeModal();action('Open proeftraining',`Ik deed mee aan een open proeftraining. Een scout vond mij interessant en zette mijn naam op een lijst.`,{Happiness:8,Fitness:2,Stamina:-10},0,'good');}else{f.form=clamp((f.form||50)-r(2,8));closeModal();action('Open proeftraining',`Ik probeerde mezelf te laten zien op een proeftraining, maar ik viel niet genoeg op tussen de andere spelers.`,{Happiness:-4,Stamina:-8},0,'warn')}}

function footballCoachTalk(){ensureMega();let f=ensureFootball();let ok=r(1,100)<55+(state.stats.Smarts||50)/3;f.coachTrust=clamp(f.coachTrust+(ok?r(4,12):-r(2,7)));closeModal();action('Coach',ok?'Ik sprak met de coach over mijn rol. Hij waardeerde mijn houding.':'Het gesprek met de coach liep stroef. Ik moet me meer bewijzen.',{Happiness:ok?4:-3,Smarts:1},0,ok?'good':'warn')}
function footballContractScreen(){ensureMega();let f=ensureFootball();let managerTxt=f.manager?`${f.manager.name} · bonus ${f.manager.bonus}% · drama ${f.manager.drama}%`:'geen manager';showModal(`<div class="modalTop"><div class="avatar">📄</div><div class="modalTitle">Contract & Manager</div></div><div class="modalBody"><div class="card"><b>Club:</b> ${f.club||'geen'}<br><b>Niveau:</b> ${FOOTBALL_LEVEL_LABEL[f.level]||f.level}<br><b>Salaris/vergoeding:</b> ${money(f.salary||0)}/jaar<br><b>Manager:</b> ${managerTxt}</div><button class="btn" onclick="footballHireManager('cheap')">Goedkope zaakwaarnemer (€300)</button><button class="btn" onclick="footballHireManager('solid')">Betrouwbare zaakwaarnemer (€1500)</button><button class="btn" onclick="footballHireManager('top')">Topmanager (€8000)</button><button class="btn" onclick="footballNegotiate()">💬 Contract onderhandelen</button><button class="btn alt" onclick="footballCareerScreen()">Terug</button></div>`)}
function footballHireManager(type){let map={cheap:{name:'Goedkope zaakwaarnemer',cost:300,bonus:4,drama:22},solid:{name:'Betrouwbare zaakwaarnemer',cost:1500,bonus:10,drama:10},top:{name:'Topmanager',cost:8000,bonus:22,drama:18}};let m=map[type];if(state.money<m.cost)return toast('Niet genoeg geld.');state.money-=m.cost;ensureFootball().manager=m;closeModal();action('Zaakwaarnemer',`Ik nam een ${m.name}. Mijn contractkansen werden beter, maar managers brengen ook drama mee.`,{Happiness:3,Smarts:1},0,'good')}
function footballNegotiate(){ensureMega();let f=ensureFootball();if(!f.active||!f.club)return toast('Geen club om mee te onderhandelen.');let chance=35+f.coachTrust*.25+f.fame*.25+(f.manager?f.manager.bonus:0);let ok=r(1,100)<chance;if(ok){let add=Math.max(200,Math.round((f.salary||800)*r(10,35)/100));f.salary=(f.salary||0)+add;if(f.contract&&state.job&&/voetbal/i.test(state.job.title))state.job.salary=f.salary;closeModal();action('Contract',`Mijn onderhandeling lukte. Ik kreeg ${money(add)} per jaar erbij.`,{Happiness:7},0,'good')}else{f.coachTrust=clamp(f.coachTrust-r(2,8));closeModal();action('Contract',`De club vond mijn eisen te hoog. De sfeer werd iets kouder.`,{Happiness:-4},0,'warn')}}
function footballRestRehab(){ensureMega();let f=ensureFootball();if(f.injured){f.injuryYears=Math.max(0,(f.injuryYears||1)-1);if(f.injuryYears<=0){f.injured=false;f.form=clamp(f.form-r(8,18));action('Revalidatie','Ik werkte aan mijn herstel en ben weer inzetbaar. Mijn vorm moet nog terugkomen.',{Health:8,Stamina:8,Happiness:4},-Math.min(state.money,250),'good');}else action('Revalidatie','Ik revalideerde. Het duurt nog even voordat ik terug ben.',{Health:5,Stamina:5},-Math.min(state.money,250),'warn');return}f.injuryRisk=clamp(f.injuryRisk-r(8,16));f.form=clamp(f.form-r(0,4));closeModal();action('Rust','Ik nam extra rust om blessures te voorkomen.',{Health:5,Stamina:12,Happiness:1},0,'good')}
function footballInjury(context){let f=ensureFootball();let severe=Math.random()<.28;f.injured=true;f.injuryYears=severe?r(1,2):1;f.form=clamp(f.form-r(15,35));f.injuryRisk=clamp(f.injuryRisk-r(8,20));closeModal();action('Blessure',`Tijdens ${context} raakte ik geblesseerd. Ik moet revalideren en mis wedstrijden.`,{Health:severe?-18:-9,Happiness:-10,Fitness:-8,Stamina:-12},0,'bad')}
function footballQuit(){let f=ensureFootball();let old=f.club;state.football={active:false,level:'none',club:null,position:null,skill:f.skill,form:40,coachTrust:0,injuryRisk:10,salary:0,fame:f.fame,matches:f.matches,goals:f.goals,assists:f.assists,scout:false,contract:false,injured:false,injuryYears:0,manager:null,lastMediaAge:-99,lastScoutAge:-99};if(state.job&&/voetbal/i.test(state.job.title))state.job=null;closeModal();action('Voetbal',`Ik stopte met mijn voetbalcarrière${old?' bij '+old:''}.`,{Happiness:-4,Stamina:8},0,'warn')}
function footballYearly(){if(!state||state.dead)return;let f=ensureFootball();if(!f.active)return;if(f.injured){f.injuryYears=Math.max(0,(f.injuryYears||1)-1);if(f.injuryYears<=0){f.injured=false;addLog('<b>Voetbal</b><br>Mijn blessure is hersteld. Ik kan weer spelen, maar mijn vorm moet terugkomen.','good',false)}else addLog(`<b>Voetbal</b><br>Ik ben nog geblesseerd. Herstel duurt nog ${f.injuryYears} jaar.`, 'warn', false)}f.form=clamp(f.form+r(-8,8));f.injuryRisk=clamp(f.injuryRisk+r(-4,5));if(f.salary&&!state.job){let gain=Math.round(f.salary*.15);state.money+=gain;addLog(`<b>Voetbalvergoeding</b><br>Mijn club betaalde ${money(gain)} aan vergoedingen/bonussen.`, 'good', false)}if(f.manager&&Math.random()*100<f.manager.drama){addLog(`<b>Zaakwaarnemer</b><br>${f.manager.name} zorgde voor gedoe rond mijn contract.`, 'warn', false);f.coachTrust=clamp(f.coachTrust-r(2,8));}if(f.matches>0&&state.age-(f.lastMediaAge??-99)>=2&&Math.random()<.18){f.lastMediaAge=state.age;let positive=f.form+f.fame+r(0,70)>100;if(positive){f.fame=clamp(f.fame+r(3,9));addLog('<b>Media</b><br>Een lokale sportpagina schreef positief over mijn seizoen.', 'good', false)}else{state.mental=state.mental||{};state.mental.stress=clamp((state.mental.stress||0)+r(3,8));addLog('<b>Media</b><br>Na een slechte reeks kreeg ik online kritiek. Dat raakte me meer dan ik wilde.', 'warn', false)}}footballMaybeProgress();}
function recoveryClinicScreen(){let a=ensureAddiction();let alcohol=a.alcohol||a.alcoholUse>3, drugs=a.drugs||a.drugUse>2, weed=a.weed||a.weedUse>3;showModal(`<div class="modalTop"><div class="avatar">🫂</div><div class="modalTitle">Afkick / AA</div></div><div class="modalBody"><div class="card"><b>Alcoholgebruik:</b> ${a.alcoholUse||0} ${a.alcohol?'· verslaafd':''}<br><b>Drugsgebruik:</b> ${a.drugUse||0} ${a.drugs?'· verslaafd':''}<br><b>Wietgebruik:</b> ${a.weedUse||0} ${a.weed?'· verslaafd':''}<br>${(!alcohol&&!drugs&&!weed)?'Je hebt geen groot probleem, maar preventief praten kan alsnog helpen.':'Hulp zoeken kan je gezondheid en controle herstellen.'}</div><button class="btn" onclick="recoveryAction('aa')">☕ AA meeting / praatgroep</button><button class="btn green" onclick="recoveryAction('clinic')">🏥 Afkickkliniek (€750)</button><button class="btn" onclick="recoveryAction('therapy')">🛋️ Verslavingsgesprek (€180)</button><button class="btn alt" onclick="closeModal()">Terug</button></div>`)}
function recoveryAction(kind){let a=ensureAddiction();let cost=kind==='clinic'?750:kind==='therapy'?180:0;if(state.money<cost)return toast('Niet genoeg geld.');state.money-=cost;if(kind==='aa'){a.alcoholUse=Math.max(0,(a.alcoholUse||0)-3);a.weedUse=Math.max(0,(a.weedUse||0)-1);if(a.alcohol&&Math.random()<.45)a.alcohol=false;closeModal();action('AA meeting','Ik ging naar een meeting en sprak eerlijk over mijn gebruik. Het loste niet alles op, maar ik voelde meer controle.',{Happiness:4,Health:2,Smarts:2,Stamina:3},0,'good');return}if(kind==='clinic'){a.alcoholUse=Math.max(0,(a.alcoholUse||0)-8);a.drugUse=Math.max(0,(a.drugUse||0)-8);a.weedUse=Math.max(0,(a.weedUse||0)-8);if(Math.random()<.7){a.alcohol=false;a.drugs=false;a.weed=false}closeModal();action('Afkickkliniek','Ik ging naar een afkickkliniek. Het was zwaar, duur en confronterend, maar mijn lichaam en hoofd kregen rust.',{Health:12,Happiness:4,Smarts:3,Stamina:8},0,'good');return}if(kind==='therapy'){a.alcoholUse=Math.max(0,(a.alcoholUse||0)-4);a.drugUse=Math.max(0,(a.drugUse||0)-4);a.weedUse=Math.max(0,(a.weedUse||0)-4);if(a.alcohol&&Math.random()<.35)a.alcohol=false;if(a.drugs&&Math.random()<.35)a.drugs=false;if(a.weed&&Math.random()<.35)a.weed=false;closeModal();action('Hulp zoeken','Ik had een serieus gesprek over mijn gebruik en maakte een plan om niet verder af te glijden.',{Health:5,Happiness:4,Smarts:3},0,'good')}}
function hospitalScreen(){ensureMega();let wounded=(state.stats.Health||50)<35||(state.mental.trauma||0)>20;showModal(`<div class="modalTop"><div class="avatar">🏥</div><div class="modalTitle">Hospital</div></div><div class="modalBody"><div class="card">Health: ${state.stats.Health}%<br>Trauma: ${state.mental.trauma||0}<br>${wounded?'Je herstel kan nuttig zijn.':'Je bent niet zwaar gewond.'}</div><button class="btn" onclick="hospitalAction('er')">🚑 Spoedbehandeling (€750)</button><button class="btn" onclick="hospitalAction('rehab')">🦾 Revalidatie (€350)</button>${state.world==='nightcity'?`<button class="btn" onclick="hospitalAction('cyber')">🤖 Cyberware reparatie (€1200)</button>`:''}<button class="btn alt" onclick="closeModal()">Terug</button></div>`)}
function hospitalAction(kind){ensureMega();let cost=kind==='cyber'?1200:kind==='er'?750:350;if(state.money<cost)return toast('Niet genoeg geld.');state.money-=cost;if(kind==='er'){state.stats.Health=clamp((state.stats.Health||50)+28);state.mental.trauma=Math.max(0,(state.mental.trauma||0)-6)}if(kind==='rehab'){state.fitness=clamp((state.fitness||50)+12);state.stamina=clamp((state.stamina||50)+18);state.mental.stress=Math.max(0,(state.mental.stress||0)-6)}if(kind==='cyber'){ensureNC();state.nc.cyberware=clamp((state.nc.cyberware||0)+5);state.nc.humanity=clamp((state.nc.humanity||100)-3);state.stats.Health=clamp((state.stats.Health||50)+12)}closeModal();action('Hospital',`Ik kreeg behandeling. Het kostte geld, maar mijn herstel ging vooruit.`,{Health:4,Happiness:2},0,'good')}
function megaYearlyEvents(){if(!state||state.dead)return;ensureMega();state.mental.stress=clamp((state.mental.stress||0)+r(-3,6)+(state.job?0:3));if(state.mental.stress>75&&Math.random()<.22){state.mental.burnout=clamp((state.mental.burnout||0)+r(4,12));addLog('<b>Stress</b><br>Mijn hoofd stond te lang onder druk. Burn-out klachten kwamen dichterbij.','warn',false)}(state.friends||[]).forEach(f=>{if(Math.random()<.035){f.rel=clamp((f.rel||50)+r(-12,10));addLog(`<b>Vrienden</b><br>${f.name} maakte een eigen keuze in het leven. Onze band veranderde.`,f.rel<35?'bad':'good',false)}});(state.businesses||[]).forEach(b=>{let fail=Math.random()*100<b.risk;if(fail){let loss=Math.min(state.money,Math.round(b.profit*r(1,4)));state.money-=loss;addLog(`<b>Business</b><br>${b.name} had een slecht jaar en kostte ${money(loss)}.`, 'bad', false)}else{let gain=Math.round(b.profit*r(60,150)/100);state.money+=gain;addLog(`<b>Business</b><br>${b.name} leverde ${money(gain)} op.`, 'good', false)}});footballYearly();if(state.football&&state.football.contract&&Math.random()<.28){let bonus=r(1000,9000);state.money+=bonus;state.football.goals+=r(0,3);addLog(`<b>Voetbal</b><br>Mijn seizoen leverde bonusgeld op: ${money(bonus)}.`, 'good', false)}if(state.age>=70&&state.legacy){state.legacy.fame=clamp((state.legacy.fame||0)+Math.round(netWorth()/150000)+(state.children||[]).length);}}

function vacation(){showModal(`<div class="modalTop"><div class="avatar">✈️</div><div class="modalTitle">Vakantie</div></div><div class="modalBody"><div class="card">Kies waar je heen gaat. Duurdere reizen geven vaak meer Happiness, maar kunnen ook meer stamina kosten.</div>${VACATION_OPTIONS.map((v,i)=>`<button class="btn ${state.money<v.cost?'locked':''}" onclick="${state.money>=v.cost?`takeVacation(${i})`:''}">${v.name}<br><span class="mini">Kosten: ${money(v.cost)}</span></button>`).join('')}<button class="btn alt" onclick="closeModal()">Terug</button></div>`)}
function takeVacation(i){let v=VACATION_OPTIONS[i];if(!v||state.money<v.cost)return toast('Niet genoeg geld voor deze vakantie.');if(v.jamaica)return startJamaicaVacation(v);closeModal();action('Vakantie',v.txt,v.stats,-v.cost,'good')}
function startJamaicaVacation(v){state.money-=v.cost;applyStats(v.stats||{});state.homeWorldBeforeVacation=state.world||'normal';state.vacation='jamaica';state.jamaica=state.jamaica||{days:0,vibe:50,beachRep:0,spent:0,memories:[]};state.jamaica.days=0;state.jamaica.spent+=v.cost;addLog(`<b>Jamaica Vacation</b><br>Ik betaalde ${money(v.cost)} en vloog naar Jamaica. Zodra ik aankwam veranderde mijn hele leven even naar zon, reggae en tropische chaos.`, 'good');closeModal();safeSave();render();openScreen('activities')}
function achievements(){showModal(`<div class="modalTop"><div class="avatar">🏆</div><div class="modalTitle">Achievements</div></div><div class="modalBody"><div class="card">${state.achievements.join('<br>')||'Nog niets behaald.'}</div><button class="btn" onclick="closeModal()">Sluiten</button></div>`)}function journal(){showModal(`<div class="modalTop"><div class="avatar">📖</div><div class="modalTitle">Life Journal</div></div><div class="modalBody"><textarea style="width:100%;height:330px;background:#15171b;color:white;border:1px solid #555;padding:8px">${state.log.map(e=>e.html.replace(/<br>/g,'\n').replace(/<[^>]*>/g,'')).reverse().join('\n\n')}</textarea><button class="btn" onclick="closeModal()">Sluiten</button></div>`)}
function timeTravel(){if(!state.snapshots||!state.snapshots.length)return toast('Nog geen vorig jaar opgeslagen.');state=state.snapshots.pop();state.dead=false;addLog('<b>Time Travel</b><br>Ik reisde één jaar terug en veranderde mijn pad.','good');safeSave();render()}function saveGame(){safeSave()}function exportSave(){let blob=new Blob([JSON.stringify(compact(),null,2)],{type:'application/json'});let a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='bitzlife-save-v92.json';a.click();setTimeout(()=>URL.revokeObjectURL(a.href),500)}function toggleMenu(force){if(force===false)$('menu').classList.remove('show');else $('menu').classList.toggle('show')}$('modalShade').addEventListener('click',e=>{if(e.target.id==='modalShade')closeModal()});


/* === v9.5 Marriage Name, Martial Arts & Bike Patch === */
(function(){
  function famLastName(){return (state&&state.name?state.name.split(' ').slice(-1)[0]:'Familie')||'Familie'}
  function firstOf(n){return (n||'').split(' ')[0]||n||''}
  function setLastName(full,last){let first=(full||'').split(' ')[0]||'Naam'; return first+' '+last;}
  function ensureV92(){
    if(!state)return;
    state.version='9.2';
    state.talents=state.talents||{};
    ['sport','thief','social','tech','combat','honesty','discipline','stress','drive','race','martial'].forEach(k=>state.talents[k]=state.talents[k]||0);
    state.martial=state.martial||{active:false,style:null,level:0,belt:'geen band',wins:0,losses:0,injuryRisk:8};
    state.parentProfile=state.parentProfile||{wealth:r(15,95),personality:pick(['zorgzaam','streng','zuinig','sportief','makkelijk','chaotisch'])};
    state.transport=state.transport||{};
    state.flags=state.flags||{};
    if(!state.license) state.license=false;
  }
  function hasBike(){ensureV92();return !!state.transport.bike || (state.items||[]).some(i=>/fiets/i.test(i.name||''));}
  const oldEnsureMega = window.ensureMega;
  window.ensureMega=function(){ if(typeof oldEnsureMega==='function')oldEnsureMega(); ensureV92(); };
  const oldMigrate = window.migrate;
  window.migrate=function(s){ s = typeof oldMigrate==='function'?oldMigrate(s):s; state=s; ensureV92(); return state; };
  const oldConfirm=window.confirmCharacterSetup;
  window.confirmCharacterSetup=function(gender){ oldConfirm(gender); ensureV92(); if(state.mother&&!state.flags.parentsDivorced) state.mother.name=setLastName(state.mother.name,famLastName()); if(state.father&&!state.flags.parentsDivorced) state.father.name=setLastName(state.father.name,famLastName()); safeSave(); render(); };

  // Add bike as item if missing
  if(window.DATA && Array.isArray(DATA.items) && !DATA.items.some(i=>i.name==='Fiets')){
    DATA.items.push({name:'Fiets',price:180,effect:{Happiness:2,Fitness:2,Stamina:1}});
  }
  const oldItemIcon=window.itemIcon;
  window.itemIcon=function(name){ if(/fiets/i.test(name||''))return '🚲'; return oldItemIcon?oldItemIcon(name):'🎁'; };

  const oldActivitiesHTML = window.activitiesHTML;
  window.activitiesHTML=function(){
    ensureV92();
    let html = oldActivitiesHTML ? oldActivitiesHTML() : '';
    const extra = `${row('🥊','Vechten',state.age>=5?'Vechten met vreemden of klasgenoten; risico op straf/blessure':'Kan vanaf 5 jaar','fightScreen()',state.age<5)}${row('🥋','Vechtsport',state.age>=5?'MMA, Karate, Judo, Taekwondo trainen':'Kan vanaf 5 jaar','martialArtsScreen()',state.age<5)}${row('🚲','Fiets',hasBike()?'Fietsen of je fiets bekijken':state.age<13?'Vraag je ouders om een fiets':'Koop zelf een fiets','bikeScreen()')}`;
    return html.replace('<div class="section">Gezondheid & plezier</div>','<div class="section">Gezondheid & plezier</div>'+extra);
  };

  const oldAssetsHTML = window.assetsHTML;
  window.assetsHTML=function(){
    ensureV92();
    let html=oldAssetsHTML?oldAssetsHTML():'';
    return html.replace(`${row('🛒','Items kopen','Spullen met kleine stat-bonussen','buyItemScreen()')}`, `${row('🛒','Items kopen','Spullen met kleine stat-bonussen','buyItemScreen()')}${row('🚲','Fiets kopen / vragen',hasBike()?'Je hebt een fiets':'Koop zelf of vraag je ouders','bikeScreen()')}`);
  };

  window.genderWord=function(p){return genderLabel?genderLabel(p):(p&&p.gender==='female'?'Vrouw':'Man')}

  window.propose=function(){
    ensureV92();
    if(!state.partner)return toast('Je hebt geen partner.');
    if(state.partner.married)return toast('Je bent al getrouwd.');
    let ok=Math.random()<state.partner.rel/110;
    if(!ok){state.partner.rel=clamp(state.partner.rel-12);closeModal();action('Trouwen',`${state.partner.name} zei nee tegen mijn huwelijksaanzoek.`,{Happiness:-12},0,'bad');return}
    state.partner.married=true;
    state.partner.marriedAge=state.age;
    const myLast=famLastName();
    const partnerLast=(state.partner.name||'').split(' ').slice(-1)[0]||myLast;
    showModal(`<div class="modalTop"><div class="avatar">💍</div><div class="modalTitle">Achternaam kiezen</div></div><div class="modalBody"><div class="card">${state.partner.name} zei ja. Jullie zijn getrouwd.<br><br>Kies jouw achternaam:</div><button class="btn" onclick="finishMarriageName('keep','${myLast.replace(/'/g,"\\'")}','${partnerLast.replace(/'/g,"\\'")}')">Mijn eigen achternaam behouden: ${myLast}</button><button class="btn gold" onclick="finishMarriageName('take','${myLast.replace(/'/g,"\\'")}','${partnerLast.replace(/'/g,"\\'")}')">Partnernaam overnemen: ${partnerLast}</button><button class="btn alt" onclick="finishMarriageName('keep','${myLast.replace(/'/g,"\\'")}','${partnerLast.replace(/'/g,"\\'")}')">Later regelen / eigen naam houden</button></div>`);
  };
  window.finishMarriageName=function(choice,myLast,partnerLast){
    ensureV92();
    let old=state.name;
    if(choice==='take'){
      state.name=setLastName(state.name,partnerLast);
      if(state.legacy)state.legacy.familyName=partnerLast;
    }
    closeModal();
    action('Trouwen', choice==='take'?`Ik trouwde met ${state.partner.name} en nam de achternaam ${partnerLast} over. Mijn naam veranderde van ${old} naar ${state.name}.`:`Ik trouwde met ${state.partner.name} en behield mijn eigen achternaam ${myLast}.`,{Happiness:16},-r(1200,8500),'good');
  };

  window.fightScreen=function(){
    ensureV92();
    if(state.age<5)return toast('Vechten kan vanaf 5 jaar.');
    let targets=[['classmate','Klasgenoot','Iemand op school kijkt uitdagend naar je.'],['stranger','Vreemde','Een vreemde loopt je expres aan.']];
    if(state.age<12)targets=[['classmate','Klasgenoot','Een kind op het plein daagt je uit.'],['stranger','Vreemd kind','Een onbekend kind begint ruzie.']];
    showModal(`<div class="modalTop"><div class="avatar">🥊</div><div class="modalTitle">Vechten</div></div><div class="modalBody"><div class="card">Vechten kan je zelfvertrouwen/combat verhogen, maar geeft risico op straf, blessures en relatieverlies.</div>${targets.map(t=>`<button class="btn red" onclick="doFight('${t[0]}')">🥊 Vecht met ${t[1]}<br><span class="mini">${t[2]}</span></button>`).join('')}<button class="btn alt" onclick="closeModal()">Terug</button></div>`);
  };
  window.doFight=function(target){
    ensureV92();
    let combat=(state.talents.combat||0)+(state.talents.martial||0)*.8+(state.fitness||50)*.35+(state.stamina||50)*.2;
    let difficulty = target==='classmate'?r(25,80):r(40,105);
    let win=combat+r(0,65)>difficulty;
    let injury = !win && Math.random()<.45 || Math.random()<.10;
    let trouble = Math.random() < (target==='classmate'?.35:.25);
    state.talents.combat=clamp((state.talents.combat||0)+r(2,7));
    state.talents.discipline=clamp((state.talents.discipline||0)-(trouble?2:0));
    let txt= win ? 'Ik won het gevecht en voelde me stoerder, maar het bleef een dom risico.' : 'Ik verloor het gevecht en voelde me kapot en beschaamd.';
    if(injury){txt+=' Ik raakte ook gewond.'; applyStats({Health:-r(6,20),Looks:-r(0,7),Stamina:-r(8,20)});}
    if(trouble){txt+=' Er kwam gedoe met ouders/school/politie over mijn gedrag.'; state.stats.Happiness=clamp(state.stats.Happiness-r(3,12));}
    closeModal(); action('Vechten',txt,{Happiness:win?3:-8,Fitness:1,Stamina:-12},0,win?'warn':'bad');
  };

  const MARTIAL_STYLES={mma:{name:'MMA',focus:'allround combat',combat:8,discipline:3,injury:14},karate:{name:'Karate',focus:'discipline en techniek',combat:5,discipline:7,injury:7},judo:{name:'Judo',focus:'balans en controle',combat:6,discipline:6,injury:8},taekwondo:{name:'Taekwondo',focus:'trappen en snelheid',combat:6,discipline:5,injury:9}};
  window.martialArtsScreen=function(){
    ensureV92();
    if(state.age<5)return toast('Vechtsport kan vanaf 5 jaar.');
    let m=state.martial||{};
    showModal(`<div class="modalTop"><div class="avatar">🥋</div><div class="modalTitle">Vechtsport</div></div><div class="modalBody"><div class="card"><b>Stijl:</b> ${m.style?MARTIAL_STYLES[m.style].name:'geen'}<br><b>Band/level:</b> ${m.belt||'geen band'} · level ${m.level||0}<br><b>Combat:</b> ${state.talents.combat||0}% ${skillBar(state.talents.combat||0)}<br><b>Discipline:</b> ${state.talents.discipline||0}% ${skillBar(state.talents.discipline||0)}</div>${Object.entries(MARTIAL_STYLES).map(([k,v])=>`<button class="btn" onclick="joinMartial('${k}')">🥋 ${v.name}<br><span class="mini">Focus: ${v.focus}</span></button>`).join('')}<button class="btn green" onclick="trainMartial()">Train huidige vechtsport</button><button class="btn" onclick="martialTournament()">Toernooi / sparring</button><button class="btn alt" onclick="closeModal()">Terug</button></div>`);
  };
  window.joinMartial=function(style){
    ensureV92();
    state.martial.active=true; state.martial.style=style; state.martial.level=state.martial.level||1; state.martial.belt=state.martial.belt||'witte band';
    closeModal(); action('Vechtsport',`Ik begon met ${MARTIAL_STYLES[style].name}. Focus: ${MARTIAL_STYLES[style].focus}.`,{Happiness:4,Fitness:3,Stamina:-5},-Math.min(state.money, state.age<13?0:35),'good');
  };
  window.trainMartial=function(){
    ensureV92();
    if(!state.martial.style)return toast('Kies eerst een vechtsport.');
    let s=MARTIAL_STYLES[state.martial.style];
    state.talents.combat=clamp((state.talents.combat||0)+r(2,s.combat));
    state.talents.discipline=clamp((state.talents.discipline||0)+r(2,s.discipline));
    state.talents.martial=clamp((state.talents.martial||0)+r(2,8));
    state.fitness=clamp((state.fitness||50)+r(1,5));
    state.stamina=clamp((state.stamina||50)-r(4,11));
    if(Math.random()*100<s.injury){closeModal(); action('Vechtsport',`Tijdens ${s.name}-training ging ik te hard. Ik raakte licht geblesseerd.`,{Health:-8,Happiness:-3,Stamina:-8},0,'warn'); return;}
    let belts=['witte band','gele band','oranje band','groene band','blauwe band','bruine band','zwarte band'];
    state.martial.level=clamp((state.martial.level||1)+(Math.random()<.22?1:0),1,7);
    state.martial.belt=belts[Math.min(6,(state.martial.level||1)-1)];
    closeModal(); action('Vechtsport',`Ik trainde ${s.name}. Mijn combat, discipline en zelfvertrouwen groeiden.`,{Happiness:3,Fitness:4,Stamina:-6},0,'good');
  };
  window.martialTournament=function(){
    ensureV92(); if(!state.martial.style)return toast('Kies eerst een vechtsport.');
    let power=(state.talents.combat||0)+(state.talents.discipline||0)*.5+(state.fitness||50)*.25+r(0,55);
    let win=power>r(55,145); state.stamina=clamp((state.stamina||50)-15);
    if(win){state.martial.wins=(state.martial.wins||0)+1; state.talents.combat=clamp((state.talents.combat||0)+5); closeModal(); action('Toernooi',`Ik won mijn partij. De trainer zei dat mijn techniek echt vooruitgaat.`,{Happiness:8,Fitness:2,Looks:1},0,'good');}
    else{state.martial.losses=(state.martial.losses||0)+1; closeModal(); action('Toernooi',`Ik verloor mijn partij, maar leerde wel waar mijn zwakke punten liggen.`,{Happiness:-4,Health:-3,Stamina:-8},0,'warn');}
  };

  window.bikeScreen=function(){
    ensureV92();
    let have=hasBike();
    showModal(`<div class="modalTop"><div class="avatar">🚲</div><div class="modalTitle">Fiets</div></div><div class="modalBody"><div class="card">${have?'Je hebt een fiets. Fietsen helpt fitness en vrijheid, vooral zonder auto.':'Je hebt nog geen fiets.'}</div>${have?`<button class="btn" onclick="rideBike()">🚲 Rondje fietsen</button>`:''}${!have&&state.age<13?`<button class="btn" onclick="askParentsBike()">Vraag je ouders om een fiets</button>`:''}${!have?`<button class="btn green" onclick="buyBikeSelf()">Zelf fiets kopen (€180)</button>`:''}<button class="btn alt" onclick="closeModal()">Terug</button></div>`);
  };
  window.parentBikeChance=function(){ensureV92();let prof=state.parentProfile;let rel=averageParentRel?averageParentRel():50;let base=rel*.45+(prof.wealth||50)*.45;let personality=prof.personality;let mod={zorgzaam:18,streng:-5,zuinig:-20,sportief:15,makkelijk:10,chaotisch:-8}[personality]||0;return clamp(Math.round(base+mod),5,95);}
  window.askParentsBike=function(){
    ensureV92(); if(hasBike())return toast('Je hebt al een fiets.');
    let chance=parentBikeChance(); let ok=Math.random()*100<chance;
    closeModal();
    if(ok){state.transport.bike=true;state.items.push({name:'Fiets',price:180,effect:{Fitness:2}});action('Fiets',`Ik vroeg mijn ouders om een fiets. Door hun ${state.parentProfile.personality} houding en geldsituatie zeiden ze ja. Ik kreeg een fiets.`,{Happiness:10,Fitness:2},0,'good');}
    else action('Fiets',`Ik vroeg mijn ouders om een fiets, maar ze zeiden nee. Hun ${state.parentProfile.personality} houding en geldsituatie hielpen niet mee.`,{Happiness:-5},0,'bad');
  };
  window.buyBikeSelf=function(){ensureV92(); if(hasBike())return toast('Je hebt al een fiets.'); if(state.money<180)return toast('Niet genoeg geld.'); state.money-=180; state.transport.bike=true; state.items.push({name:'Fiets',price:180,effect:{Fitness:2}}); closeModal(); action('Fiets',`Ik kocht zelf een fiets.`,{Happiness:5,Fitness:2},0,'good');}
  window.rideBike=function(){ensureV92(); if(!hasBike())return toast('Je hebt geen fiets.'); closeModal(); action('Fietsen',pick(['Ik fietste een rondje door de wijk en voelde mijn hoofd leeg worden.','Ik fietste naar het park en trapte net iets harder dan nodig.','Ik reed langs het water en voelde me even vrij.']),{Happiness:4,Fitness:4,Health:2,Stamina:-6},0,'good');}

  // Strengthen skill tree display to include martial
  const oldSkillTree=window.skillTreeScreen;
  window.skillTreeScreen=function(){ensureV92();let t=state.talents;showModal(`<div class="modalTop"><div class="avatar">📈</div><div class="modalTitle">Skill Tree</div></div><div class="modalBody"><div class="card">Je keuzes vormen je karakter. Skills bepalen kansen bij werk, voetbal, vechten, crime, Night City en sociale events.</div>${[['Sporttalent','sport','⚽'],['Dief-talent','thief','🕶️'],['Sociaal talent','social','🗣️'],['Tech Skill','tech','🖥️'],['Combat','combat','🥊'],['Martial Arts','martial','🥋'],['Drive Skill','drive','🚗'],['Race Skill','race','🏁'],['Eerlijkheid','honesty','⚖️'],['Discipline','discipline','🎯']].map(x=>`<div class="card"><b>${x[2]} ${x[0]}</b>${skillBar(t[x[1]]||0)}</div>`).join('')}<button class="btn alt" onclick="closeModal()">Terug</button></div>`)};

  // Render once more after load for upgraded UI
})();


/* === v9.5 Assets & Job Activities ===
   Fietsbezit wordt vanaf nu afgeleid van het echte item in inventory.
   Als je de fiets/auto/huis verkoopt, verdwijnt hij uit Assets en kun je niet meer fietsen. */
(function(){
  function isBikeItem(it){ return /fiets/i.test((it&&it.name)||''); }
  window.hasBike=function(){
    if(!state) return false;
    const realBike = (state.items||[]).some(isBikeItem);
    if(!realBike && state.transport) state.transport.bike=false;
    if(realBike && state.transport) state.transport.bike=true;
    return realBike;
  };
  window.sellItemFixed=function(i){
    let it=state.items[i];
    if(!it) return;
    let isBike=isBikeItem(it);
    let refund=Math.round((it.price||0)*.45);
    state.money += refund;
    state.items.splice(i,1);
    if(isBike && state.transport) state.transport.bike=false;
    closeModal();
    action(isBike?'Fiets':'Item', isBike?'Ik verkocht mijn fiets. Hij is nu weg uit mijn assets, dus ik kan er niet meer op fietsen.':`Ik verkocht ${it.name}.`, {Happiness:isBike?-1:-1}, 0, 'warn');
  };
  window.itemScreen=function(i){
    let it=state.items[i];
    if(!it) return;
    let isBike=isBikeItem(it);
    showModal(`<div class="modalTop"><div class="avatar">${it.icon||itemIcon(it.name)}</div><div class="modalTitle">${it.name}</div></div><div class="modalBody"><div class="card">Aankoopwaarde: ${money(it.price)}${isBike?'<br>Transport: fietsen beschikbaar zolang je deze fiets bezit.':''}</div>${isBike?`<button class="btn" onclick="rideBike()">🚲 Rondje fietsen</button>`:''}<button class="btn red" onclick="sellItemFixed(${i})">Verkopen</button><button class="btn alt" onclick="closeModal()">Terug</button></div>`);
  };
  const oldRideBike=window.rideBike;
  window.rideBike=function(){
    if(!hasBike()) return toast('Je hebt geen fiets meer. Koop of vraag eerst opnieuw een fiets.');
    return oldRideBike ? oldRideBike() : action('Fietsen','Ik fietste een rondje.',{Happiness:3,Fitness:3,Stamina:-5},0,'good');
  };
})();


/* === v10.2 De Gekke Steeg ===
   Absurdistische normale-wereld activiteit vanaf 16 jaar met mini-games en rewards. */
(function(){
  const oldActivitiesHTML_v102 = window.activitiesHTML;
  function inNormalWorld(){return (!state.vacation && state.world!=='nightcity' && !(state.jail&&state.jail.yearsLeft>0));}
  window.activitiesHTML=function(){
    let html = oldActivitiesHTML_v102 ? oldActivitiesHTML_v102() : '';
    if(!state || !inNormalWorld()) return html;
    const steegRow = row('🧱','De Gekke Steeg', state.age>=16?'Vanaf 16: rare encounters en mini-games':'Beschikbaar vanaf 16 jaar','gekkeSteegScreen()',state.age<16);
    if(html.includes('<div class="section">Relaties & familie</div>')) return html.replace('<div class="section">Relaties & familie</div>', steegRow+'<div class="section">Relaties & familie</div>');
    return html + steegRow;
  };

  const oldItemIcon_v102 = window.itemIcon;
  window.itemIcon=function(name){
    let t=(name||'').toLowerCase();
    if(t.includes('blikje bier')) return '🍺';
    if(t.includes('mandje')) return '🧺';
    if(t.includes('bami')) return '🍜';
    return oldItemIcon_v102 ? oldItemIcon_v102(name) : '🎁';
  };

  function steegState(){state.gekkeSteeg=state.gekkeSteeg||{runs:0,wins:0,bamiDodges:0,mandRespect:0,blikHits:0};return state.gekkeSteeg;}
  function steegReward(name,price,effect){
    state.items=state.items||[];
    if(!state.items.some(i=>i.name===name)) state.items.push({name,price,effect:effect||{Happiness:1}});
  }
  function steegResult(title,text,stats,cash,type,label,value,tone){
    closeModal();
    action(title,text,stats||{},cash||0,type||'good');
    if(window.showActionResult) showActionResult({title,text,label:label||'Steeg-status',value:value??70,tone:tone||''});
  }

  function steegResult(title,text,stats,cash,type,label,value,tone){
    state.money+=cash||0;applyStats(stats||{});
    addLog(`<b>${title}</b><br>${text}${cash?`<br>${cash>0?'+':'-'} ${money(Math.abs(cash))}`:''}`,type||'');render();
    if(window.showActionResult) showActionResult({title,text,label:label||'Steeg-status',value:value??70,tone:tone||''});
  }
  function steegContinue(nextFn){
    setTimeout(()=>{
      let btn=document.querySelector('#modal .resultOk .btn');
      if(btn){btn.textContent='Gelezen / Verder';btn.onclick=()=>{closeModal();nextFn&&nextFn();};}
    },20);
  }
  function steegActionThen(title,text,stats,cash,type,nextFn){
    action(title,text,stats||{},cash||0,type||'');
    steegContinue(nextFn);
  }

  window.gekkeSteegScreen=function(){
    if(state.age<16) return toast('De Gekke Steeg is pas vanaf 16 jaar.');
    if(!inNormalWorld()) return toast('De Gekke Steeg bestaat alleen in de normale wereld.');
    let s=steegState();
    showModal(`<div class="modalTop"><div class="avatar">🧱</div><div class="modalTitle">De Gekke Steeg</div></div><div class="modalBody"><div class="card">Een smalle steeg vol rare figuren, natte stoeptegels en dingen die uit ramen kunnen vallen.<br><br>Runs: ${s.runs||0}<br>Succesvolle exits: ${s.wins||0}</div><button class="btn red" onclick="startGekkeSteegRun()">Loop door De Gekke Steeg</button><button class="btn alt" onclick="closeModal()">Terug</button></div>`);
  };

  window.startGekkeSteegRun=function(){
    let s=steegState();s.runs=(s.runs||0)+1;s.current={score:0,bami:false,mand:false,blik:false};
    gekkeSteegBami();
  };

  window.gekkeSteegBami=function(){
    const opts=['Links springen','Rechts springen','Duiken'];
    const correct=r(0,2);
    window.__bamiCorrect=correct;
    showModal(`<div class="modalTop"><div class="avatar">🍜</div><div class="modalTitle">Pan bami!</div></div><div class="modalBody"><p>Je loopt de steeg in. Ineens gaat boven je een raam open en iemand gooit een pan bami naar buiten.</p><p><b>Mini-game:</b> ontwijk de bami.</p>${opts.map((o,i)=>`<button class="btn" onclick="gekkeSteegBamiChoice(${i})">${o}</button>`).join('')}</div>`);
  };
  window.gekkeSteegBamiChoice=function(i){
    let s=steegState();
    if(i===window.__bamiCorrect){s.current.score+=1;s.current.bami=true;s.bamiDodges=(s.bamiDodges||0)+1;closeModal();steegActionThen('De Gekke Steeg','Ik dook precies op tijd weg. De bami klapte achter mij op de stoep alsof iemand een snackbar had laten ontploffen.',{Happiness:3,Fitness:1,Stamina:-2},0,'good',gekkeSteegFightGuy);}
    else{closeModal();steegActionThen('De Gekke Steeg','Ik koos verkeerd en kreeg een halve pan bami over me heen. Warm, plakkerig en totaal vernederend.',{Health:-8,Happiness:-5,Looks:-3,Stamina:-4},0,'warn',gekkeSteegFightGuy);}
  };

  window.gekkeSteegFightGuy=function(){
    showModal(`<div class="modalTop"><div class="avatar">😡</div><div class="modalTitle">Kom op dan-meneer</div></div><div class="modalBody"><p>Verderop staat een boze man midden in de steeg. Hij roept: <b>“Kom op dan kanker jong!”</b></p><button class="btn green" onclick="gekkeSteegFightChoice('ignore')">Rustig doorlopen</button><button class="btn" onclick="gekkeSteegFightChoice('joke')">Grapje maken</button><button class="btn red" onclick="gekkeSteegFightChoice('fight')">Terugvechten</button></div>`);
  };
  window.gekkeSteegFightChoice=function(choice){
    let s=steegState();let combat=(state.talents?.combat||0)+(state.talents?.martial||0)+(state.fitness||50)/2;
    if(choice==='ignore'){s.current.score+=1;closeModal();steegActionThen('De Gekke Steeg','Ik liep rustig door en deed alsof ik een belangrijk telefoontje had. De boze man raakte vooral met zichzelf in gevecht.',{Smarts:2,Happiness:1},0,'good',gekkeSteegMand);return;}
    if(choice==='joke'){let ok=Math.random()<.58;closeModal();steegActionThen('De Gekke Steeg',ok?'Ik maakte een droge grap. De man keek boos, maar moest toch lachen en liet me door.':'Mijn grap viel compleet dood. De sfeer werd ongemakkelijk en ik liep snel door.',{Happiness:ok?4:-2,Smarts:1},0,ok?'good':'warn',gekkeSteegMand);return;}
    let win=Math.random() < Math.min(.78,.18+combat/180);
    if(win){s.current.score+=1;closeModal();steegActionThen('De Gekke Steeg','Ik vocht terug en kwam er verrassend goed vanaf. Niet slim, wel effectief.',{Happiness:4,Health:-3,Fitness:2,Stamina:-8},0,'warn',gekkeSteegMand);}
    else{closeModal();steegActionThen('De Gekke Steeg','Ik probeerde stoer te doen, maar werd hard aangepakt. Mijn lichaam zei meteen: slecht plan.',{Health:-22,Happiness:-8,Looks:-4,Stamina:-15},0,'bad',gekkeSteegMand);}
  };

  window.gekkeSteegMand=function(){
    showModal(`<div class="modalTop"><div class="avatar">🧺</div><div class="modalTitle">Meneer Mand</div></div><div class="modalBody"><p>Uit een portiek stapt Meneer Mand. Hij kijkt je recht aan en schreeuwt keihard:</p><p style="font-size:34px"><b>MAND!</b></p><button class="btn green" onclick="gekkeSteegMandChoice('correct')">Rustig knikken en “mand” terugzeggen</button><button class="btn" onclick="gekkeSteegMandChoice('loud')">Harder terugschreeuwen</button><button class="btn red" onclick="gekkeSteegMandChoice('run')">Wegrennen</button></div>`);
  };
  window.gekkeSteegMandChoice=function(choice){
    let s=steegState();
    if(choice==='correct'){s.current.score+=2;s.current.mand=true;s.mandRespect=(s.mandRespect||0)+1;closeModal();steegActionThen('Meneer Mand','Ik reageerde correct: rustig knikken, “mand” terugzeggen en doorlopen. Meneer Mand leek tevreden. Ik kwam zonder kleerscheuren verder.',{Happiness:5,Smarts:2},0,'good',gekkeSteegBlik);return;}
    if(choice==='loud'){closeModal();steegActionThen('Meneer Mand','Ik schreeuwde harder terug. De hele steeg viel stil. Meneer Mand respecteerde het niet, maar de duiven wel.',{Happiness:2,Smarts:-1,Stamina:-2},0,'warn',gekkeSteegBlik);return;}
    closeModal();steegActionThen('Meneer Mand','Ik rende weg, gleed bijna uit over bami en verloor alle waardigheid die ik nog had.',{Happiness:-4,Stamina:-7,Looks:-1},0,'warn',gekkeSteegBlik);
  };

  window.gekkeSteegBlik=function(){
    const target=r(0,2);window.__blikTarget=target;
    const labels=['Te vroeg gooien','Perfect mikken','Te laat gooien'];
    showModal(`<div class="modalTop"><div class="avatar">🥫</div><div class="modalTitle">Blik in het water</div></div><div class="modalBody"><p>Aan het einde van de steeg ligt een leeg blikje. De water-man wijst naar de gracht en zegt dat echte steeglopers hem erin gooien.</p><p><b>Mini-game:</b> kies het juiste moment.</p>${labels.map((l,i)=>`<button class="btn" onclick="gekkeSteegBlikChoice(${i})">${l}</button>`).join('')}</div>`);
  };
  window.gekkeSteegBlikChoice=function(i){
    let s=steegState();
    if(i===window.__blikTarget || i===1){s.current.score+=2;s.current.blik=true;s.blikHits=(s.blikHits||0)+1;closeModal();steegActionThen('Blik mini-game','Ik gooide het blik perfect in het water. De water-man knikte alsof ik net een Olympische finale had gewonnen.',{Happiness:6,Fitness:1,Smarts:1},0,'good',gekkeSteegExit);}
    else{closeModal();steegActionThen('Blik mini-game','Ik gooide mis. Het blik stuiterde terug alsof de steeg zelf me uitlachte.',{Happiness:-3,Stamina:-2},0,'warn',gekkeSteegExit);}
  };

  window.gekkeSteegExit=function(){
    let s=steegState();let score=(s.current&&s.current.score)||0;
    let rewardText='', prizes=[];
    s.rewards=s.rewards||{};
    if(score>=3){
      s.wins=(s.wins||0)+1;
      if(!s.rewards.firstPrize){
        s.rewards.firstPrize=true;
        steegReward('Blikje bier uit De Gekke Steeg',2,{Happiness:1});
        steegReward('Mandje van Tichelen',35,{Happiness:3,Looks:1});
        prizes=['🍺 Blikje bier uit De Gekke Steeg','🧺 Mandje van Tichelen'];
        rewardText=' Bij de uitgang kreeg ik mijn eerste steeg-prijzen.';
      }else{
        steegReward('Pan Bami uit De Gekke Steeg',4,{Happiness:1,Stamina:-1});
        prizes=['🍜 Pan Bami uit De Gekke Steeg'];
        rewardText=' Omdat ik de hoofdprijzen al had, kreeg ik deze keer bami mee. Logisch? Nee. Steeglogica? Ja.';
      }
    }else{
      steegReward('Bami-vlek herinnering',1,{Happiness:-1});
      prizes=['🍜 Bami-vlek herinnering'];
      rewardText=' Ik kreeg vooral bami-vlekken en een verhaal dat niemand normaal gaat vinden.';
    }
    closeModal();
    action('De Gekke Steeg verlaten',`Ik kwam de steeg uit met een score van ${score}/5.${rewardText}<br><br><b>Prijzen gekregen:</b><br>${prizes.join('<br>')}`,{Happiness:score>=3?8:1,Smarts:2,Stamina:-5},0,score>=3?'good':'warn');
    let btn=document.querySelector('#modal .resultOk .btn');if(btn){btn.textContent='Gelezen';}
    safeSave();
  };
})();

loadGame();

/* ---- next original inline script block ---- */

(function(){
  const oldItemIcon_v106 = window.itemIcon;
  const ICON_MAP_V106 = [
    [/jerk\s*kruiden/i,'🌶️'],
    [/reggae\s*shirt/i,'👕'],
    [/dread\s*hat/i,'🎩'],
    [/beach\s*bracelet/i,'📿'],
    [/rum\s*cake/i,'🍰'],
    [/houten\s*schildpad/i,'🐢'],
    [/jamaica\s*vlag/i,'🇯🇲'],
    [/island\s*sunglasses/i,'🕶️'],
    [/blue\s*mountain\s*coffee/i,'☕'],
    [/blikje\s*bier/i,'🍺'],
    [/mandje/i,'🧺'],
    [/bami/i,'🍜'],
    [/broodmes/i,'🔪'],
    [/fiets/i,'🚲']
  ];
  window.itemIcon = function(name){
    const t = String(name || '');
    for(const [rx, ico] of ICON_MAP_V106){ if(rx.test(t)) return ico; }
    return oldItemIcon_v106 ? oldItemIcon_v106(name) : '🎁';
  };
  // Upgrade oude saves/items zonder opgeslagen icoon naar dezelfde iconen als in de winkel.
  window.fixItemIconsV106 = function(){
    if(!window.state || !Array.isArray(state.items)) return;
    state.items.forEach(it => { if(it && !it.icon) it.icon = itemIcon(it.name); });
  };
  const oldAssetsHTML_v106 = window.assetsHTML;
  if(oldAssetsHTML_v106){
    window.assetsHTML = function(){ fixItemIconsV106(); return oldAssetsHTML_v106(); };
  }
  const oldBuyJamaicaItem_v106 = window.buyJamaicaItem;
  if(oldBuyJamaicaItem_v106){
    window.buyJamaicaItem = function(i){ oldBuyJamaicaItem_v106(i); fixItemIconsV106(); if(window.safeSave) safeSave(); };
  }
})();


/* === v10.7 Age 18 Housing Choice & Homelessness Patch === */
(function(){
  const oldMigrate = window.migrate || migrate;
  window.migrate = function(s){
    s = oldMigrate(s);
    s.flags = s.flags || {};
    s.homeless = !!s.homeless;
    s.livingWithParents = !!s.livingWithParents || (s.age < 18 && !(s.houses||[]).length);
    s.parentProfile = s.parentProfile || {
      wealth: Math.floor(30 + Math.random()*61),
      strictness: Math.floor(20 + Math.random()*61),
      patience: Math.floor(25 + Math.random()*66)
    };
    return s;
  };

  const oldFresh = window.fresh || fresh;
  window.fresh = function(gender, firstName, lastName){
    const s = oldFresh(gender, firstName, lastName);
    s.version = '10.7';
    s.homeless = false;
    s.livingWithParents = true;
    s.parentProfile = {
      wealth: Math.floor(30 + Math.random()*61),
      strictness: Math.floor(20 + Math.random()*61),
      patience: Math.floor(25 + Math.random()*66)
    };
    s.flags = s.flags || {};
    return s;
  };

  window.hasOwnHome107 = function(){ return !!((state.houses||[]).find(h=>h.primary) || (state.houses||[])[0]); };

  const oldLivingText = window.livingText || livingText;
  window.livingText = function(){
    if(state.homeless) return 'Dakloos · hoge stress en risico';
    if(state.livingWithParents && state.age>=18) return 'Woont langer bij ouders · geen huur';
    return oldLivingText();
  };

  window.needsAge18HousingChoice = function(){
    return state && state.age>=18 && !state.flags.age18HousingResolved && !state.homeless && !window.hasOwnHome107() && !isInJail() && state.vacation!=='jamaica';
  };

  window.showAge18HousingChoice = function(){
    state.flags.age18HousingResolved = true;
    safeSave();
    showModal(`<div class="modalTop"><div class="avatar">🏠</div><div class="modalTitle">18 jaar: waar ga je wonen?</div></div>
      <div class="modalBody"><p>Je bent 18 en hebt nog geen eigen huis. Je moet kiezen hoe je verder gaat.</p>
      <button class="btn" onclick="askParentsToStay107()">🙏 Vraag of je langer bij je ouders mag wonen</button>
      <button class="btn" onclick="joinArmy107()">🪖 Meld je aan bij het leger</button>
      <button class="btn red" onclick="becomeHomeless107()">🧥 Dakloos worden</button></div>`);
  };

  window.askParentsToStay107 = function(){
    const rel = Math.round(((state.mother?.rel||50)+(state.father?.rel||50))/2);
    const p = state.parentProfile || {wealth:50, strictness:45, patience:50};
    const chance = Math.max(10, Math.min(92, rel*0.45 + p.wealth*0.25 + p.patience*0.25 - p.strictness*0.20 + (state.stats.Smarts||50)*0.10));
    if(Math.random()*100 < chance){
      state.livingWithParents = true;
      state.homeless = false;
      addRel(state.mother, 3); addRel(state.father, 2);
      closeModal();
      action('Thuis blijven', `Ik vroeg of ik langer bij mijn ouders mocht wonen. Ze vonden het goed, zolang ik mijn best doe om iets op te bouwen.`, {Happiness:6, Smarts:1}, 0, 'good');
    } else {
      addRel(state.mother, -4); addRel(state.father, -4);
      showModal(`<div class="modalTop"><div class="avatar">😬</div><div class="modalTitle">Ouders zeggen nee</div></div>
        <div class="modalBody"><p>Mijn ouders vonden dat ik nu echt zelf verantwoordelijkheid moest nemen.</p>
        <button class="btn" onclick="joinArmy107()">🪖 Dan meld ik me aan bij het leger</button>
        <button class="btn red" onclick="becomeHomeless107()">🧥 Dan word ik dakloos</button></div>`);
    }
  };

  window.joinArmy107 = function(){
    state.homeless = false;
    state.livingWithParents = false;
    state.job = {id:'army_private', title:'Soldaat bij het leger', field:'Leger', salary:26000, minAge:18, req:'Rijping, discipline en fysieke inzet', performance:50, stress:35, colleagues:[], boss:null};
    state.jobYears = 0;
    state.careerLevel = 0;
    state.talents = state.talents || {};
    state.talents.discipline = Math.min(100,(state.talents.discipline||0)+8);
    closeModal();
    action('Leger', 'Ik meldde me aan bij het leger. Ik kreeg onderdak, salaris en een harde les in discipline.', {Health:2, Smarts:2, Happiness:-1}, 0, 'good');
  };

  window.becomeHomeless107 = function(){
    state.homeless = true;
    state.livingWithParents = false;
    state.houses = [];
    closeModal();
    action('Dakloos', 'Ik had geen huis en geen veilige plek. De dagen werden zwaarder en de verleiding van drank of drugs werd groter.', {Happiness:-18, Health:-8, Looks:-4}, 0, 'bad');
  };

  window.homelessHelpScreen107 = function(){
    if(!state.homeless) return toast('Je bent niet dakloos.');
    showModal(`<div class="modalTop"><div class="avatar">🧥</div><div class="modalTitle">Dakloos</div></div>
      <div class="modalBody"><button class="btn" onclick="homelessShelter107()">🏠 Opvang zoeken</button>
      <button class="btn" onclick="homelessTempWork107()">💶 Tijdelijk werk zoeken</button>
      <button class="btn" onclick="homelessAskHelp107()">🙏 Hulp vragen aan familie</button>
      <button class="btn alt" onclick="closeModal()">Terug</button></div>`);
  };
  window.homelessShelter107 = function(){
    const ok = Math.random() < .55;
    if(ok){ state.homeless=false; state.livingWithParents=false; closeModal(); action('Opvang', 'Ik vond tijdelijk een opvangplek. Het was niet luxe, maar ik sliep veilig.', {Happiness:8, Health:6}, 0, 'good'); }
    else { closeModal(); action('Opvang', 'Ik probeerde opvang te regelen, maar alles zat vol. De nacht voelde lang.', {Happiness:-6, Health:-3}, 0, 'bad'); }
  };
  window.homelessTempWork107 = function(){
    const earned = Math.floor(20+Math.random()*61);
    closeModal(); action('Tijdelijk werk', `Ik deed losse klusjes en verdiende ${money(earned)}.`, {Happiness:2, Health:-2}, earned, 'good');
  };
  window.homelessAskHelp107 = function(){
    const rel = Math.round(((state.mother?.rel||50)+(state.father?.rel||50))/2);
    if(Math.random()*100 < rel){ state.homeless=false; state.livingWithParents=true; addRel(state.mother,-2); addRel(state.father,-2); closeModal(); action('Familiehulp', 'Ik vroeg mijn ouders om hulp. Ze lieten me toch weer tijdelijk thuis slapen.', {Happiness:10, Health:5}, 0, 'good'); }
    else { addRel(state.mother,-3); addRel(state.father,-3); closeModal(); action('Familiehulp', 'Ik vroeg om hulp, maar thuis bleef de deur dicht. Dat kwam hard binnen.', {Happiness:-8}, 0, 'bad'); }
  };

  const oldActivitiesHTML = window.activitiesHTML || activitiesHTML;
  window.activitiesHTML = function(){
    let html = oldActivitiesHTML();
    if(state.homeless && state.jail?.yearsLeft<=0 && state.vacation!=='jamaica' && state.world!=='nightcity'){
      html += `<div class="section">Dakloos</div>${row('🧥','Dakloos overleven','Opvang, losse klusjes of familiehulp zoeken','homelessHelpScreen107()')}`;
    }
    return html;
  };

  const oldAgeUp = window.ageUp || ageUp;
  window.ageUp = function(){
    const beforeAge = state.age;
    oldAgeUp();
    if(!state || state.dead) return;
    if(state.homeless){
      applyStats({Happiness:-8, Health:-5, Looks:-2});
      state.stamina = clamp((state.stamina||50)-8);
      ensureAddiction();
      addLog(`<b>Dakloos</b><br>Het leven op straat vrat aan mijn energie. Als ik nu veel drank, drugs of wiet gebruik, raak ik veel sneller afhankelijk.`, 'bad', false);
    }
    if(window.needsAge18HousingChoice()) showAge18HousingChoice();
    safeSave(); render();
  };

  // show choice immediately on old saves loaded at 18+ without home
  setTimeout(()=>{ try{ if(window.needsAge18HousingChoice && needsAge18HousingChoice()) showAge18HousingChoice(); }catch(e){} }, 600);
})();

