// v10.9 Doctor World Fix: normal / Jamaica / Night City aware doctor system
(function(){
  function worldLabel109(){
    if(state && state.vacation==='jamaica') return 'jamaica';
    if(state && state.world==='nightcity') return 'nightcity';
    return 'normal';
  }
  function canPay109(cost){ return (state.money||0) >= cost; }
  function doctorOptionBtn109(icon,title,sub,fn,locked){
    return `<button class="btn ${locked?'locked':''}" onclick="${locked?'':fn}">${icon} ${title}<br><span class="mini">${sub}</span></button>`;
  }
  window.doctorVisit = function(){
    if(!state || state.dead) return toast('Je bent overleden.');
    if(state.jail && state.jail.yearsLeft>0){
      showModal(`<div class="modalTop"><div class="avatar">🏥</div><div class="modalTitle">Infirmary</div></div><div class="modalBody"><div class="card">Je zit vast. Je kunt alleen naar de gevangenis-infirmary.</div>${doctorOptionBtn109('🩹','Gevangenis-infirmary','Gratis, maar beperkt herstel','doctorTreat109(\'prison\')',false)}<button class="btn alt" onclick="closeModal()">Terug</button></div>`);
      return;
    }
    const w=worldLabel109();
    if(w==='jamaica'){
      showModal(`<div class="modalTop"><div class="avatar">🌴</div><div class="modalTitle">Jamaica Clinic</div></div><div class="modalBody"><div class="card">Op Jamaica kun je naar een resort clinic of een lokale island doctor. Handig bij snorkelbeten, kater, tropische koorts of ongelukjes.</div>${doctorOptionBtn109('🏨','Resort clinic','€350 · snel herstel, duurder','doctorTreat109(\'jamaica_resort\')',!canPay109(350))}${doctorOptionBtn109('🩺','Island doctor','€140 · goedkoper, soms bijzonder advies','doctorTreat109(\'jamaica_local\')',!canPay109(140))}${doctorOptionBtn109('🥥','Rust + kokoswater','€25 · klein herstel zonder echte dokter','doctorTreat109(\'jamaica_rest\')',!canPay109(25))}<button class="btn alt" onclick="closeModal()">Terug</button></div>`);
      return;
    }
    if(w==='nightcity'){
      ensureNC && ensureNC();
      showModal(`<div class="modalTop"><div class="avatar">🦾</div><div class="modalTitle glitch">Night City Clinic</div></div><div class="modalBody"><div class="card">In Night City ga je niet gewoon naar de huisarts. Je kiest tussen een dure trauma clinic of een shady ripperdoc. Health omhoog, maar soms met Heat/Humanity gevolgen.</div>${doctorOptionBtn109('🚑','Trauma clinic','€1200 · sterk herstel, weinig gedoe','doctorTreat109(\'nc_trauma\')',!canPay109(1200))}${doctorOptionBtn109('🦾','Ripperdoc patch-up','€650 · cyberpunk herstel, Humanity-risico','doctorTreat109(\'nc_ripper\')',!canPay109(650))}${doctorOptionBtn109('💊','Black market meds','€180 · goedkoop, riskant','doctorTreat109(\'nc_blackmeds\')',!canPay109(180))}<button class="btn alt" onclick="closeModal()">Terug</button></div>`);
      return;
    }
    showModal(`<div class="modalTop"><div class="avatar">🏥</div><div class="modalTitle">Dokter</div></div><div class="modalBody"><div class="card">Gezondheid: ${clamp(state.stats.Health||50)}%<br>Stamina: ${clamp(state.stamina||50)}%</div>${doctorOptionBtn109('👨‍⚕️','Huisarts','€120 · normale check-up','doctorTreat109(\'normal_gp\')',!canPay109(120))}${doctorOptionBtn109('🏥','Ziekenhuis','€500 · groter herstel','doctorTreat109(\'normal_hospital\')',!canPay109(500))}${doctorOptionBtn109('🛌','Rust nemen','Gratis · klein herstel','doctorTreat109(\'normal_rest\')',false)}<button class="btn alt" onclick="closeModal()">Terug</button></div>`);
  };
  window.doctorTreat109 = function(kind){
    let cost=0, stats={}, text='', type='good';
    if(kind==='prison'){
      text=pick(['Ik ging naar de gevangenis-infirmary. Ze deden het minimale, maar ik voelde me iets minder kapot.','De infirmary gaf me een simpele behandeling. Niet warm, wel nuttig.']);
      stats={Health:8,Stamina:4,Happiness:-1};
    }
    if(kind==='jamaica_resort'){
      cost=350; text=pick(['De resort clinic checkte mijn wond, gaf me zalf en zei dat ik minder stoer moest doen bij vissen.','Ik liet me behandelen bij de resort clinic. Duur, maar mijn Jamaica-dag was nog niet verloren.','De dokter zei dat tropische vakantie en domme keuzes vaak samen reizen. Ik knikte alsof ik ervan leerde.']);
      stats={Health:20,Stamina:10,Happiness:2};
    }
    if(kind==='jamaica_local'){
      cost=140; text=pick(['De island doctor keek rustig, gaf me behandeling en zei: “Respect the sea, mon.”','Een lokale dokter hielp me met mijn klachten. Goedkoper dan het resort en veel meer sfeer.','Ik kreeg een behandeling en een levensles tegelijk. Mijn health ging omhoog en mijn ego iets omlaag.']);
      stats={Health:14,Stamina:7,Smarts:1};
    }
    if(kind==='jamaica_rest'){
      cost=25; text=pick(['Ik nam rust, kokoswater en schaduw. Geen wondermiddel, maar mijn lichaam kwam bij.','Ik ging even plat in de schaduw met kokoswater. Mijn stamina kroop langzaam terug.']);
      stats={Health:4,Stamina:10,Happiness:1};
    }
    if(kind==='nc_trauma'){
      cost=1200; text=pick(['De trauma clinic scande me alsof ik een kapotte machine was. Duur, effectief, koud.','Ik betaalde voor een snelle behandeling. Night City laat je bloeden, maar verkoopt je ook pleisters.']);
      stats={Health:28,Stamina:14,Happiness:-1}; if(state.nc) state.nc.heat=clamp((state.nc.heat||0)+1);
    }
    if(kind==='nc_ripper'){
      cost=650; text=pick(['De ripperdoc zette me weer in elkaar met tape, chrome en twijfelachtige humor.','De ripperdoc repareerde mijn lichaam, maar ik voelde me net iets minder menselijk.']);
      stats={Health:20,Stamina:10,Smarts:1}; if(state.nc){state.nc.humanity=clamp((state.nc.humanity||100)-r(1,4)); state.nc.cyberware=clamp((state.nc.cyberware||0)+1)}
    }
    if(kind==='nc_blackmeds'){
      cost=180; const bad=Math.random()<.28; text=bad? 'Ik nam black market meds. Mijn lichaam kalmeerde even, maar daarna voelde alles verkeerd.' : 'Ik kocht black market meds. Niet slim, wel effectief genoeg om door te lopen.';
      stats=bad?{Health:-6,Stamina:8,Happiness:-5}:{Health:8,Stamina:12,Happiness:-1}; type=bad?'warn':'good'; if(state.nc) state.nc.heat=clamp((state.nc.heat||0)+r(1,4));
    }
    if(kind==='normal_gp'){
      cost=120; text=pick(['Ik ging naar de huisarts. Niet spannend, wel verstandig.','De dokter keek me aan alsof ik eerder had moeten komen. Eerlijk: hij had gelijk.','Ik kreeg advies, een check-up en het gevoel dat mijn lichaam nog niet helemaal afgeschreven was.']);
      stats={Health:12,Stamina:5,Smarts:1};
    }
    if(kind==='normal_hospital'){
      cost=500; text=pick(['In het ziekenhuis werd ik goed nagekeken. Duur grapje, maar mijn health ging flink omhoog.','Ik kreeg een serieuze behandeling en voelde me daarna eindelijk minder wrak.']);
      stats={Health:25,Stamina:10,Happiness:-1};
    }
    if(kind==='normal_rest'){
      text=pick(['Ik nam een dag rust. Geen heldengedoe, gewoon herstellen.','Ik bleef thuis, dronk water en deed even alsof slaap mijn persoonlijkheid was.']);
      stats={Health:4,Stamina:12,Happiness:2};
    }
    if(cost && !canPay109(cost)) return toast('Niet genoeg geld voor deze behandeling.');
    closeModal();
    action(kind.includes('nc_')?'Night City clinic':kind.includes('jamaica')?'Jamaica dokter':kind==='prison'?'Infirmary':'Dokter', text, stats, -cost, type);
  };
})();


