      showModal(`<div class="modalTop"><div class="avatar">🏥</div><div class="modalTitle">Ziekenhuis / Dokter</div></div><div class="modalBody"><div class="card">Je hebt een actieve ziekte. Kies behandeling of ga terug.</div>${rows}<button class="btn alt" onclick="closeModal()">Terug</button></div>`);
