    if((kind==='fight'||kind==='hit'||kind==='punch') && (!isInSchool || !isInSchool())) return toast('Je kunt niet met klasgenoten vechten als je niet op school zit.');
    return oldClassmateAction ? oldClassmateAction(i,kind) : null;
