    if(k==='talk'){c.rel=clamp(c.rel+r(3,8)); closeModal(); action('Collega',`Ik praatte met ${c.name} over werk, roddels en waarom de printer altijd liegt.`,{Happiness:2},0,'good');}
    if(k==='help'){c.rel=clamp(c.rel+r(5,12)); closeModal(); action('Collega',`Ik hielp ${c.name} met een klus. De werkdag voelde ineens minder als straf.`,{Smarts:1,Happiness:2,Stamina:-2},0,'good');}
    if(k==='argue'){c.rel=clamp(c.rel-r(8,18)); closeModal(); action('Collega',`Ik kreeg ruzie met ${c.name}. De sfeer op werk werd kouder dan koffie uit een vergeten mok.`,{Happiness:-4,Stamina:-2},0,'warn');}
