      showModal(`<div class="modalTop"><div class="avatar">🥊</div><div class="modalTitle">Kickbox → UFC Career</div></div><div class="modalBody"><div class="card">Beschikbaar vanaf 15 jaar. Vechtsport vanaf jonge leeftijd helpt je kansen.</div><button class="btn alt" onclick="closeModal()">Terug</button></div>`);
