/* v11.6 Doctor parent payment + flu auto-cure fix */
(function(){
  function ensureHealth116(){
    if(!state) return;
    state.flags = state.flags || {};
    state.illnesses = state.illnesses || [];
  }

  function illnessCost116(ill){
    let cost = ill && ill.cost ? ill.cost : 120;
    const world = state.vacation === 'jamaica' ? 'jamaica' : (state.world || 'normal');
    if(world === 'nightcity') cost = Math.round(cost * 1.8);
    if(world === 'jamaica') cost = Math.round(cost * 1.35);
    return cost;
  }

  function illnessIsFlu116(ill){
    return ((ill && ill.name) || '').toLowerCase().includes('griep');
  }

  // Override treatment: under 18 parents pay all doctor/hospital costs.
  window.treatIllnessV115 = function(i){
    ensureHealth116();
    const ill = state.illnesses[i];
    if(!ill || ill.cured) return toast('Deze ziekte is al behandeld.');
    const cost = illnessCost116(ill);
    const parentsPay = state.age < 18;

    if(!parentsPay && state.money < cost){
      return toast('Niet genoeg geld voor deze behandeling.');
    }

    if(!parentsPay) state.money -= cost;

    const world = state.vacation === 'jamaica' ? 'jamaica' : (state.world || 'normal');
    const bonus = world === 'nightcity' ? 0.08 : world === 'jamaica' ? 0.02 : 0.04;
    const chance = (ill.heal || 0.72) + bonus;

    if(Math.random() < chance){
      ill.cured = true;
      applyStats({Health:r(8,18), Stamina:r(4,12), Happiness:3});
      action(
        'Behandeling',
        parentsPay
          ? `Mijn ouders betaalden ${money(cost)} voor de behandeling van ${ill.name}. De behandeling sloeg aan.`
          : `De behandeling voor ${ill.name} sloeg aan. Je betaalde ${money(cost)} en voelt je eindelijk weer menselijk.`,
        {Health:0},
        0,
        'good'
      );
    } else {
      applyStats({Health:-r(2,6), Happiness:-3});
      action(
        'Behandeling',
        parentsPay
          ? `Mijn ouders betaalden ${money(cost)} voor de behandeling van ${ill.name}, maar het hielp nog niet genoeg.`
          : `De behandeling voor ${ill.name} hielp nog niet genoeg. Je betaalde ${money(cost)} en moet later opnieuw herstellen.`,
        {Health:0},
        0,
        'warn'
      );
    }

    safeSave();
    render();
  };

  // Replace doctor screen for active illnesses so it clearly says parents pay under 18.
  const previousDoctorVisit116 = window.doctorVisit;
  window.doctorVisit = function(){
    ensureHealth116();
    if(state.jail && state.jail.yearsLeft > 0 && previousDoctorVisit116) return previousDoctorVisit116();

    const active = (state.illnesses || []).filter(x => !x.cured);
    if(active.length){
      const rows = active.map((ill) => {
        const idx = state.illnesses.indexOf(ill);
        const cost = illnessCost116(ill);
        const payText = state.age < 18 ? `Ouders betalen · waarde ${money(cost)}` : `Kosten: ${money(cost)}`;
        return `<button class="btn" onclick="treatIllnessV115(${idx})">🏥 Behandel ${ill.name}<br><span class="mini">${payText} · zonder behandeling zakt Health</span></button>`;
      }).join('');
      showModal(`<div class="modalTop"><div class="avatar">🏥</div><div class="modalTitle">Ziekenhuis / Dokter</div></div><div class="modalBody"><div class="card">${state.age < 18 ? 'Je bent minderjarig: je ouders betalen je dokterskosten.' : 'Je betaalt je eigen behandeling.'}</div>${rows}<button class="btn alt" onclick="closeModal()">Terug</button></div>`);
      return;
    }

    return previousDoctorVisit116 ? previousDoctorVisit116() : action('Dokter','Je ging naar de dokter en voelde je iets beter.',{Health:8,Stamina:4}, state.age < 18 ? 0 : -120,'good');
  };

  // Flu/griep: normal ages auto-cure at next birthday, but 70+ keeps it longer.
  function autoCureFluAfterBirthday116(){
    ensureHealth116();
    (state.illnesses || []).forEach(ill => {
      if(!ill || ill.cured || !illnessIsFlu116(ill)) return;

      const yearsSick = Math.max(0, (state.age || 0) - (ill.ageStart ?? state.age));

      if(state.age < 70 && yearsSick >= 1){
        ill.cured = true;
        applyStats({Health:5, Stamina:4});
        addLog('<b>Herstel</b><br>Mijn griep ging na een jaar vanzelf over. Ik voelde me weer een stuk fitter.', 'good', false);
      } else if(state.age >= 70 && yearsSick >= 1){
        // Older bodies recover slower: no instant cure, but small chance each year.
        if(Math.random() < 0.35){
          ill.cured = true;
          applyStats({Health:4, Stamina:3});
          addLog('<b>Herstel</b><br>De griep bleef langer hangen door mijn leeftijd, maar ik knapte uiteindelijk toch op.', 'good', false);
        } else {
          addLog('<b>Griep</b><br>Door mijn leeftijd bleef de griep langer hangen dan normaal.', 'warn', false);
        }
      }
    });
  }

  // Wrap current ageUp after v11.5 wrapper.
  const previousAgeUp116 = window.ageUp;
  window.ageUp = function(){
    previousAgeUp116();
    if(!state || state.dead) return;
    autoCureFluAfterBirthday116();
    safeSave();
    render();
  };

  // Small helper message if user opens doctor as minor with no illness.
  window.doctorMinorCheck116 = function(){
    if(state.age < 18){
      action('Dokter', 'Mijn ouders regelden en betaalden de dokterskosten voor mij.', {Health:6, Stamina:3}, 0, 'good');
    } else if(previousDoctorVisit116) {
      previousDoctorVisit116();
    }
  };
})();

