/* v11.7 illness sensitivity display/balance helper */
(function(){
  function ensureSensitivity117(){
    if(!state) return;
    state.healthSensitivity = state.healthSensitivity ?? (Math.random()<0.18?1.35:Math.random()<0.42?1.12:Math.random()<0.72?0.92:0.72);
  }
  function sensitivityLabel117(){
    ensureSensitivity117();
    const s=state.healthSensitivity||1;
    if(s>=1.25)return 'hoog';
    if(s>=1.05)return 'iets verhoogd';
    if(s<=0.82)return 'laag';
    return 'normaal';
  }
  const oldDoctor117 = window.doctorVisit;
  window.doctorVisit = function(){
    ensureSensitivity117();
    const active=(state.illnesses||[]).filter(x=>!x.cured);
    if(!active.length && oldDoctor117){
      showModal(`<div class="modalTop"><div class="avatar">🏥</div><div class="modalTitle">Dokter / Gezondheid</div></div><div class="modalBody"><div class="card">Ziektegevoeligheid: <b>${sensitivityLabel117()}</b><br>Je leeftijd en Health bepalen nu sterker je ziektekans. De basisziektekans is verlaagd.</div><button class="btn" onclick="closeModal();doctorVisit117Continue()">Naar dokter</button><button class="btn alt" onclick="closeModal()">Terug</button></div>`);
      return;
    }
    return oldDoctor117 ? oldDoctor117() : null;
  };
  window.doctorVisit117Continue=function(){
    if(oldDoctor117) oldDoctor117();
  };
})();

