/* v12.5 Storage quota fix */
(function(){
  const SAVE_KEY_125 = 'bitzlife_v125_storage_quota_fix';

  function pruneForSave125(obj){
    const s = JSON.parse(JSON.stringify(obj || {}));

    // Keep saves small. Huge logs/snapshots/items were causing quota errors in mobile browser storage.
    if(Array.isArray(s.log)) s.log = s.log.slice(-80);
    if(Array.isArray(s.snapshots)) s.snapshots = s.snapshots.slice(-1);
    if(Array.isArray(s.items)) s.items = s.items.slice(-120);
    if(Array.isArray(s.friends)) s.friends = s.friends.slice(-60);
    if(Array.isArray(s.flings)) s.flings = s.flings.slice(-60);
    if(Array.isArray(s.colleagues)) s.colleagues = s.colleagues.slice(-40);
    if(Array.isArray(s.children)) s.children = s.children.slice(-40);
    if(Array.isArray(s.siblings)) s.siblings = s.siblings.slice(-40);

    if(s.jamaica && Array.isArray(s.jamaica.memories)) s.jamaica.memories = s.jamaica.memories.slice(-20);
    if(s.japan && Array.isArray(s.japan.memories)) s.japan.memories = s.japan.memories.slice(-20);

    // Remove bulky/debug/temporary fields if they exist.
    delete s._debug;
    delete s.debug;
    delete s.temp;
    delete s.cache;

    return s;
  }

  function clearOldBitzLifeSaves125(){
    try{
      const keep = new Set([SAVE_KEY_125]);
      const keys = [];
      for(let i=0;i<localStorage.length;i++){
        const k = localStorage.key(i);
        if(k && /^(bitzlife|bitlife|bitz_life)/i.test(k) && !keep.has(k)) keys.push(k);
      }
      keys.forEach(k => {
        try{ localStorage.removeItem(k); }catch(e){}
      });
    }catch(e){}
  }

  window.saveGame = function(){
    if(!state) return;
    try{
      const small = pruneForSave125(state);
      localStorage.setItem(SAVE_KEY_125, JSON.stringify(small));
      // Also update current in-memory state with trimmed parts so future saves stay small.
      if(Array.isArray(state.log)) state.log = state.log.slice(-80);
      if(Array.isArray(state.snapshots)) state.snapshots = state.snapshots.slice(-1);
      if(state.jamaica && Array.isArray(state.jamaica.memories)) state.jamaica.memories = state.jamaica.memories.slice(-20);
      if(state.japan && Array.isArray(state.japan.memories)) state.japan.memories = state.japan.memories.slice(-20);
      return true;
    }catch(err){
      console.warn('[BitzLife v12.5] save quota cleanup', err);
      try{
        clearOldBitzLifeSaves125();
        const smaller = pruneForSave125(state);
        if(Array.isArray(smaller.log)) smaller.log = smaller.log.slice(-35);
        if(Array.isArray(smaller.items)) smaller.items = smaller.items.slice(-60);
        if(Array.isArray(smaller.friends)) smaller.friends = smaller.friends.slice(-30);
        if(Array.isArray(smaller.flings)) smaller.flings = smaller.flings.slice(-30);
        localStorage.setItem(SAVE_KEY_125, JSON.stringify(smaller));
        if(Array.isArray(state.log)) state.log = state.log.slice(-35);
        return true;
      }catch(err2){
        console.error('[BitzLife v12.5] save still failed', err2);
        try{ sessionStorage.setItem(SAVE_KEY_125, JSON.stringify(pruneForSave125(state))); return true; }catch(e){}
        return false;
      }
    }
  };

  window.safeSave = function(){
    try{
      return window.saveGame();
    }catch(e){
      console.error('[BitzLife v12.5] safeSave failed silently', e);
      return false;
    }
  };

  // Make global function names point to patched versions.
  try{ saveGame = window.saveGame; }catch(e){}
  try{ safeSave = window.safeSave; }catch(e){}

  // Patch load to prefer new smaller save, but still fallback to existing old loader.
  const oldLoad125 = window.loadGame || (typeof loadGame === 'function' ? loadGame : null);
  window.loadGame = function(manual){
    try{
      const raw = localStorage.getItem(SAVE_KEY_125) || sessionStorage.getItem(SAVE_KEY_125);
      if(raw){
        state = JSON.parse(raw);
        if(typeof migrate === 'function') migrate();
        if(typeof render === 'function') render();
        if(manual && typeof toast === 'function') toast('Game geladen');
        return true;
      }
    }catch(e){ console.warn('[BitzLife v12.5] new load failed', e); }

    if(oldLoad125){
      try{
        const ok = oldLoad125(manual);
        // Immediately resave in smaller v12.5 format.
        try{ window.safeSave(); }catch(e){}
        return ok;
      }catch(e){
        console.warn('[BitzLife v12.5] old load failed', e);
      }
    }
    if(manual && typeof toast === 'function') toast('Geen save gevonden');
    return false;
  };
  try{ loadGame = window.loadGame; }catch(e){}

  // Clean once at startup.
  setTimeout(()=>{ try{ clearOldBitzLifeSaves125(); if(state) window.safeSave(); }catch(e){} }, 500);
})();

