/* v12.8 Loans & Study Finance */
(function(){
  function ensureFinance128(){
    if(!state) return;
    state.finance = state.finance || {};
    state.finance.loans = state.finance.loans || [];
    state.finance.studyDebt = state.finance.studyDebt || 0;
    state.finance.studyFinanceActive = !!state.finance.studyFinanceActive;
    state.finance.studyFinanceYears = state.finance.studyFinanceYears || 0;
    state.finance.loanScore = state.finance.loanScore ?? 50;
  }

  function totalDebt128(){
    ensureFinance128();
    return Math.round((state.finance.studyDebt||0) + (state.finance.loans||[]).reduce((a,l)=>a+(l.balance||0),0));
  }

  function loanRow128(l,i){
    return `<div class="card"><b>${l.name}</b><br>Schuld: ${money(l.balance||0)}<br>Rente: ${Math.round((l.interest||0)*100)}% per jaar<br>Maandlast: ${money(l.monthly||0)}<br><button class="btn" onclick="payLoan128(${i})">💸 Extra aflossen</button></div>`;
  }

  window.financeScreen128 = function(){
    ensureFinance128();
    const loans = state.finance.loans || [];
    showModal(`<div class="modalTop"><div class="avatar">🏦</div><div class="modalTitle">Lenen & Studiefinanciering</div></div>
    <div class="modalBody">
      <div class="card"><b>Overzicht</b><br>Totale schuld: ${money(totalDebt128())}<br>Studieschuld: ${money(state.finance.studyDebt||0)}<br>Studiefinanciering: ${state.finance.studyFinanceActive?'actief':'niet actief'}<br>Kredietscore: ${state.finance.loanScore||50}%</div>
      ${state.age<18?`<div class="card">Lenen en studiefinanciering zijn beschikbaar vanaf 18 jaar.</div>`:`
        <button class="btn" onclick="takeLoan128('small')">🏦 Kleine lening nemen<br><span class="mini">€500 - €2.000, hogere rente</span></button>
        <button class="btn" onclick="takeLoan128('normal')">💳 Persoonlijke lening<br><span class="mini">€2.500 - €10.000, afhankelijk van inkomen</span></button>
        <button class="btn" onclick="takeStudyDebt128()">🎓 Studielening nemen<br><span class="mini">€750 - €2.500 erbij als studieschuld</span></button>
        <button class="btn green" onclick="toggleStudyFinance128()">📚 Studiefinanciering ${state.finance.studyFinanceActive?'stoppen':'aanvragen'}<br><span class="mini">Alleen logisch als je studeert</span></button>
      `}
      <div class="section">Lopende leningen</div>
      ${loans.length?loans.map(loanRow128).join(''):'<div class="card">Geen normale leningen.</div>'}
      <button class="btn alt" onclick="closeModal()">Terug</button>
    </div>`);
  };

  window.takeLoan128 = function(type){
    ensureFinance128();
    if(state.age<18) return toast('Lenen kan pas vanaf 18 jaar.');
    const income = state.job ? (state.job.salary || state.job.pay || 0) : 0;
    const currentDebt = totalDebt128();
    const score = clamp((state.finance.loanScore||50) + (income>15000?15:0) - Math.floor(currentDebt/5000)*8);
    const max = type==='small' ? 2000 : Math.max(2500, Math.min(10000, Math.round((income||12000)/3)));
    const min = type==='small' ? 500 : 2500;
    if(score < 20 && type!=='small') return toast('Je kredietscore is te laag voor een grote lening.');
    const amount = r(min,max);
    const interest = type==='small' ? 0.12 : 0.07;
    const monthly = Math.round(amount * (type==='small'?0.09:0.055));
    state.money += amount;
    state.finance.loans.push({
      name:type==='small'?'Kleine lening':'Persoonlijke lening',
      balance:amount,
      original:amount,
      interest,
      monthly,
      ageTaken:state.age
    });
    state.finance.loanScore = clamp((state.finance.loanScore||50)-r(3,9));
    closeModal();
    action('Lening',`Ik nam een ${type==='small'?'kleine lening':'persoonlijke lening'} van ${money(amount)}. Mijn geld steeg, maar mijn schuld ook.`,{Happiness:4,Smarts:-1},0,'warn');
  };

  window.takeStudyDebt128 = function(){
    ensureFinance128();
    if(state.age<18) return toast('Studielening kan pas vanaf 18 jaar.');
    const studying = !!(state.education && (state.education.studying || state.education.level));
    const amount = r(750,2500);
    state.money += amount;
    state.finance.studyDebt += amount;
    state.finance.loanScore = clamp((state.finance.loanScore||50)-2);
    closeModal();
    action('Studielening',`Ik nam ${money(amount)} studielening. ${studying?'Het hielp met studiekosten.':'Eigenlijk studeerde ik niet actief, dus dit voelde meer als gevaarlijk makkelijk geld.'}`,{Happiness:3,Smarts:studying?2:-1},0,'warn');
  };

  window.toggleStudyFinance128 = function(){
    ensureFinance128();
    if(state.age<18) return toast('Studiefinanciering kan pas vanaf 18 jaar.');
    if(state.finance.studyFinanceActive){
      state.finance.studyFinanceActive = false;
      closeModal();
      action('Studiefinanciering',`Ik zette mijn studiefinanciering stop.`,{Happiness:-1},0,'warn');
      return;
    }
    const studying = !!(state.education && (state.education.studying || state.education.level));
    if(!studying && !confirm('Je lijkt niet actief te studeren. Toch studiefinanciering aanvragen?')) return;
    state.finance.studyFinanceActive = true;
    state.finance.studyFinanceYears = 0;
    closeModal();
    action('Studiefinanciering',`Ik vroeg studiefinanciering aan. Vanaf nu krijg ik jaarlijks geld zolang het actief blijft.`,{Happiness:6,Smarts:1},0,'good');
  };

  window.payLoan128 = function(i){
    ensureFinance128();
    const l = state.finance.loans[i];
    if(!l) return;
    const amount = Math.min(l.balance, Math.max(50, Math.floor(state.money*0.25)));
    if(amount<=0 || state.money<amount) return toast('Niet genoeg geld om extra af te lossen.');
    state.money -= amount;
    l.balance -= amount;
    if(l.balance<=0){
      state.finance.loans.splice(i,1);
      state.finance.loanScore = clamp((state.finance.loanScore||50)+8);
      closeModal();
      action('Lening afgelost',`Ik loste mijn lening volledig af. Mijn kredietscore werd beter.`,{Happiness:7,Smarts:2},0,'good');
    } else {
      state.finance.loanScore = clamp((state.finance.loanScore||50)+2);
      closeModal();
      action('Aflossen',`Ik loste ${money(amount)} extra af. Er staat nog ${money(l.balance)} open.`,{Happiness:2},0,'good');
    }
    safeSave(); render();
  };

  function yearlyFinance128(){
    ensureFinance128();
    if(state.dead) return;

    // study finance yearly payment
    if(state.finance.studyFinanceActive){
      const studying = !!(state.education && (state.education.studying || state.education.level));
      const grant = studying ? r(1800,4200) : r(800,1800);
      state.money += grant;
      state.finance.studyFinanceYears++;
      addLog(`<b>Studiefinanciering</b><br>Ik kreeg ${money(grant)} studiefinanciering${studying?' voor mijn studie.':' terwijl ik niet echt actief studeerde.'}`, 'good', false);
      // if not studying too long, convert part to debt
      if(!studying && state.finance.studyFinanceYears>1){
        const penalty = r(500,1500);
        state.finance.studyDebt += penalty;
        addLog(`<b>Studiefinanciering controle</b><br>Omdat mijn studie niet goed liep, werd ${money(penalty)} bij mijn studieschuld gezet.`, 'warn', false);
      }
    }

    // interest and payments
    (state.finance.loans||[]).forEach(l=>{
      const interest = Math.round((l.balance||0)*(l.interest||0.05));
      l.balance += interest;
      const pay = Math.min(l.balance, l.monthly||0);
      if(pay>0 && state.money>=pay){
        state.money -= pay;
        l.balance -= pay;
        state.finance.loanScore = clamp((state.finance.loanScore||50)+1);
        addLog(`<b>Lening</b><br>Ik betaalde ${money(pay)} aan ${l.name}. Rente dit jaar: ${money(interest)}.`, 'warn', false);
      } else if(pay>0) {
        state.finance.loanScore = clamp((state.finance.loanScore||50)-8);
        l.missed = (l.missed||0)+1;
        addLog(`<b>Gemiste betaling</b><br>Ik kon mijn lening niet betalen. Mijn kredietscore zakte.`, 'bad', false);
        if(l.missed>=3 && Math.random()<0.35){
          applyStats({Happiness:-8,Smarts:-1});
          addLog(`<b>Incasso</b><br>Door meerdere gemiste betalingen kreeg ik incassostress.`, 'bad', false);
        }
      }
    });
    state.finance.loans = (state.finance.loans||[]).filter(l=>l.balance>0);

    // study debt grows slightly
    if((state.finance.studyDebt||0)>0){
      const add = Math.round(state.finance.studyDebt*0.01);
      state.finance.studyDebt += add;
      if(add>0) addLog(`<b>Studieschuld</b><br>Mijn studieschuld groeide met ${money(add)} rente/administratie.`, 'warn', false);
    }
  }

  // Add finance to activities and assets
  const oldActivities128 = window.activitiesHTML || (typeof activitiesHTML==='function'?activitiesHTML:null);
  window.activitiesHTML = function(){
    let h = oldActivities128 ? oldActivities128() : '';
    if(state && !state.jail?.yearsLeft && !h.includes('Lenen & Studiefinanciering')){
      const block = `<div class="section">Geld & schulden</div>${row('🏦','Lenen & Studiefinanciering',state.age>=18?'Lening, studieschuld en studiefinanciering':'Vanaf 18 jaar','financeScreen128()',state.age<18)}`;
      if(h.includes('<div class="section">Vrije tijd</div>')) h = h.replace('<div class="section">Vrije tijd</div>', block+'<div class="section">Vrije tijd</div>');
      else h += block;
    }
    return h;
  };
  try{ activitiesHTML = window.activitiesHTML; }catch(e){}

  const oldAssets128 = window.assetsHTML || (typeof assetsHTML==='function'?assetsHTML:null);
  window.assetsHTML = function(){
    ensureFinance128();
    let h = oldAssets128 ? oldAssets128() : '';
    if(!h.includes('Schulden overzicht')){
      h += `<div class="section">Schulden overzicht</div>
      <div class="card"><b>Totale schuld:</b> ${money(totalDebt128())}<br><b>Studieschuld:</b> ${money(state.finance.studyDebt||0)}<br><b>Leningen:</b> ${money((state.finance.loans||[]).reduce((a,l)=>a+(l.balance||0),0))}<br><button class="btn" onclick="financeScreen128()">🏦 Beheer leningen</button></div>`;
    }
    return h;
  };
  try{ assetsHTML = window.assetsHTML; }catch(e){}

  const oldAge128 = window.ageUp || (typeof ageUp==='function'?ageUp:null);
  window.ageUp = function(){
    if(oldAge128) oldAge128();
    yearlyFinance128();
    safeSave(); render();
  };
  try{ ageUp = window.ageUp; }catch(e){}

  const oldRender128 = window.render || (typeof render==='function'?render:null);
  window.render = function(){
    ensureFinance128();
    return oldRender128 ? oldRender128() : null;
  };
})();

