/* v12.9 Study finance only while in school + parent rent option */
(function(){
  function ensure129(){
    if(!state) return;
    state.finance = state.finance || {};
    state.finance.loans = state.finance.loans || [];
    state.finance.studyDebt = state.finance.studyDebt || 0;
    state.flags = state.flags || {};
    state.housing = state.housing || {};
  }

  function isStudent129(){
    // Strict: alleen actief als je echt op school/studie zit.
    try{
      if(typeof isInSchool === 'function' && isInSchool()) return true;
    }catch(e){}
    if(state.education && (state.education.studying === true || state.education.active === true || state.education.inSchool === true)) return true;
    if(state.school && (state.school.active === true || state.school.enrolled === true)) return true;
    // Age-based fallback: onder 18 ben je meestal schoolgaand als er geen drop-out flag staat.
    if(state.age < 18 && !state.flags.droppedOut && !state.flags.leftSchool) return true;
    return false;
  }

  function livingWithParents129(){
    return !!(state.flags.livingWithParents || state.housing.type === 'parents' || state.home === 'parents');
  }

  function setLivingWithParents129(rent){
    state.flags.livingWithParents = true;
    state.homeless = false;
    state.housing = state.housing || {};
    state.housing.type = 'parents';
    state.housing.name = rent > 0 ? 'Bij ouders wonen met kostgeld' : 'Bij ouders wonen';
    state.housing.rent = rent || 0;
    state.housing.parentRent = rent || 0;
    state.home = 'parents';
  }

  function hasOwnHome129(){
    try{
      if(state.houses && state.houses.length) return true;
      if(state.house) return true;
      if(state.home && state.home !== 'parents' && state.home !== 'homeless') return true;
      if(state.housing && state.housing.type && !['parents','homeless'].includes(state.housing.type)) return true;
    }catch(e){}
    return false;
  }

  // Override study finance toggle from v12.8.
  window.toggleStudyFinance128 = function(){
    ensure129();
    if(state.age < 18) return toast('Studiefinanciering kan pas vanaf 18 jaar.');
    if(state.finance.studyFinanceActive){
      state.finance.studyFinanceActive = false;
      closeModal();
      action('Studiefinanciering', 'Ik zette mijn studiefinanciering stop.', {Happiness:-1}, 0, 'warn');
      safeSave(); render();
      return;
    }
    if(!isStudent129()){
      return toast('Studiefinanciering kan alleen zolang je echt op school/studie zit.');
    }
    state.finance.studyFinanceActive = true;
    state.finance.studyFinanceYears = 0;
    closeModal();
    action('Studiefinanciering', 'Ik vroeg studiefinanciering aan omdat ik op school/studie zit. Vanaf nu krijg ik jaarlijks geld zolang ik student blijf.', {Happiness:6,Smarts:1}, 0, 'good');
    safeSave(); render();
  };

  // Patch finance screen wording and lock.
  const oldFinance129 = window.financeScreen128;
  window.financeScreen128 = function(){
    ensure129();
    const loans = state.finance.loans || [];
    const student = isStudent129();
    const totalDebt = Math.round((state.finance.studyDebt||0) + loans.reduce((a,l)=>a+(l.balance||0),0));
    showModal(`<div class="modalTop"><div class="avatar">🏦</div><div class="modalTitle">Lenen & Studiefinanciering</div></div>
    <div class="modalBody">
      <div class="card"><b>Overzicht</b><br>Totale schuld: ${money(totalDebt)}<br>Studieschuld: ${money(state.finance.studyDebt||0)}<br>School/studie actief: ${student?'ja':'nee'}<br>Studiefinanciering: ${state.finance.studyFinanceActive?'actief':'niet actief'}<br>Kredietscore: ${state.finance.loanScore||50}%</div>
      ${state.age<18?`<div class="card">Lenen en studiefinanciering zijn beschikbaar vanaf 18 jaar.</div>`:`
        <button class="btn" onclick="takeLoan128('small')">🏦 Kleine lening nemen<br><span class="mini">€500 - €2.000, hogere rente</span></button>
        <button class="btn" onclick="takeLoan128('normal')">💳 Persoonlijke lening<br><span class="mini">€2.500 - €10.000, afhankelijk van inkomen</span></button>
        <button class="btn ${student?'':'locked'}" onclick="${student?`takeStudyDebt128()`:''}">🎓 Studielening nemen<br><span class="mini">${student?'€750 - €2.500 erbij als studieschuld':'Alleen zolang je op school/studie zit'}</span></button>
        <button class="btn green ${student||state.finance.studyFinanceActive?'':'locked'}" onclick="${student||state.finance.studyFinanceActive?`toggleStudyFinance128()`:''}">📚 Studiefinanciering ${state.finance.studyFinanceActive?'stoppen':'aanvragen'}<br><span class="mini">${student?'Alleen zolang je student blijft':'Niet beschikbaar: je zit niet op school'}</span></button>
      `}
      <div class="section">Lopende leningen</div>
      ${loans.length?loans.map((l,i)=>`<div class="card"><b>${l.name}</b><br>Schuld: ${money(l.balance||0)}<br>Rente: ${Math.round((l.interest||0)*100)}% per jaar<br>Maandlast: ${money(l.monthly||0)}<br><button class="btn" onclick="payLoan128(${i})">💸 Extra aflossen</button></div>`).join(''):'<div class="card">Geen normale leningen.</div>'}
      <button class="btn alt" onclick="closeModal()">Terug</button>
    </div>`);
  };

  // Override study debt too: alleen school.
  window.takeStudyDebt128 = function(){
    ensure129();
    if(state.age < 18) return toast('Studielening kan pas vanaf 18 jaar.');
    if(!isStudent129()) return toast('Studielening kan alleen zolang je echt op school/studie zit.');
    const amount = r(750,2500);
    state.money += amount;
    state.finance.studyDebt += amount;
    state.finance.loanScore = clamp((state.finance.loanScore||50)-2);
    closeModal();
    action('Studielening', `Ik nam ${money(amount)} studielening. Dit kan zolang ik op school/studie zit.`, {Happiness:3,Smarts:2}, 0, 'warn');
    safeSave(); render();
  };

  // Parent housing choice after 18: free, €350 rent, or no.
  function parentStayDecision129(){
    const relAvg = Math.round(((state.mother?.rel??50) + (state.father?.rel??50))/2);
    const wealth = state.familyWealth ?? state.parentsWealth ?? state.flags.parentWealth ?? r(25,80);
    const strict = state.flags.strictParents ?? (Math.random()<0.35);
    const badBehavior = (state.crime?.heat||0) + (state.flags.schoolTrouble||0) + (state.flags.parentTrouble||0);
    let score = relAvg + (wealth/2) - badBehavior - (strict?15:0) + r(-20,20);

    if(score >= 70) return {result:'free', rent:0};
    if(score >= 40) return {result:'rent', rent:350};
    return {result:'no', rent:0};
  }

  window.askParentsStay129 = function(){
    ensure129();
    const d = parentStayDecision129();
    closeModal();
    if(d.result === 'free'){
      setLivingWithParents129(0);
      action('Bij ouders wonen', 'Mijn ouders zeiden dat ik langer thuis mag blijven wonen zonder huur te betalen. Dat geeft ademruimte.', {Happiness:8}, 0, 'good');
    } else if(d.result === 'rent'){
      setLivingWithParents129(350);
      action('Bij ouders wonen', 'Mijn ouders zeiden dat ik mag blijven, maar wel tegenover €350 huur/kostgeld per maand.', {Happiness:3}, 0, 'warn');
    } else {
      state.flags.livingWithParents = false;
      state.homeless = true;
      state.home = 'homeless';
      state.housing = {type:'homeless', name:'Dakloos'};
      action('Niet thuis blijven', 'Mijn ouders zeiden nee. Ik kon niet langer thuis blijven wonen en werd dakloos.', {Happiness:-18,Health:-5,Looks:-3}, 0, 'bad');
    }
    safeSave(); render();
  };

  // Override old age-18 choice if available; otherwise add our own check.
  window.showAge18HousingChoice129 = function(){
    if(state.flags.age18HousingChoiceDone129) return;
    state.flags.age18HousingChoiceDone129 = true;
    showModal(`<div class="modalTop"><div class="avatar">🏠</div><div class="modalTitle">18 jaar: woonkeuze</div></div>
    <div class="modalBody">
      <div class="card">Je bent 18 en hebt geen eigen woning. Wat doe je?</div>
      <button class="btn" onclick="askParentsStay129()">👨‍👩‍👧 Vraag of je langer bij je ouders mag wonen<br><span class="mini">Kan gratis, €350 huur/kostgeld, of nee worden</span></button>
      <button class="btn" onclick="joinArmyFromHousing129()">🪖 Meld je aan bij het leger</button>
      <button class="btn red" onclick="becomeHomeless129()">🧥 Dakloos worden</button>
    </div>`);
  };

  window.joinArmyFromHousing129 = function(){
    closeModal();
    state.job = {title:'Soldaat', salary:26000, type:'army', fixed:true};
    state.homeless = false;
    state.flags.livingWithParents = false;
    action('Leger', 'Ik meldde me aan bij het leger. Ik kreeg werk, discipline en een dak boven mijn hoofd.', {Happiness:4,Health:3,Smarts:1}, 0, 'good');
    safeSave(); render();
  };

  window.becomeHomeless129 = function(){
    closeModal();
    state.homeless = true;
    state.home = 'homeless';
    state.housing = {type:'homeless', name:'Dakloos'};
    action('Dakloos', 'Ik werd dakloos. Mijn Happiness, Health en stabiliteit kwamen onder druk te staan.', {Happiness:-18,Health:-5,Looks:-3}, 0, 'bad');
    safeSave(); render();
  };

  function maybeAge18Housing129(){
    if(!state || state.dead) return;
    if(state.age !== 18) return;
    if(hasOwnHome129() || livingWithParents129()) return;
    if(state.flags.age18HousingChoiceDone129) return;
    setTimeout(()=>{ try{ showAge18HousingChoice129(); }catch(e){ console.warn(e); } }, 250);
  }

  // Parent rent yearly payment
  function yearlyParentRent129(){
    if(livingWithParents129() && (state.housing?.parentRent||0)>0){
      const rent = state.housing.parentRent;
      if(state.money >= rent*12){
        state.money -= rent*12;
        addLog(`<b>Kostgeld</b><br>Ik betaalde ${money(rent*12)} kostgeld/huur aan mijn ouders dit jaar.`, 'warn', false);
      } else {
        const relLoss = r(5,14);
        if(state.mother) state.mother.rel = clamp((state.mother.rel||50)-relLoss);
        if(state.father) state.father.rel = clamp((state.father.rel||50)-relLoss);
        addLog(`<b>Kostgeld gemist</b><br>Ik kon de €350 per maand niet goed betalen. Mijn ouders werden minder blij.`, 'bad', false);
        if(Math.random()<0.35){
          state.homeless = true;
          state.flags.livingWithParents = false;
          state.home = 'homeless';
          state.housing = {type:'homeless', name:'Dakloos'};
          addLog(`<b>Uit huis gezet</b><br>Omdat ik het kostgeld niet betaalde, moest ik alsnog vertrekken.`, 'bad', false);
        }
      }
    }
  }

  // Stop study finance automatically if school stops.
  function enforceStudyFinance129(){
    ensure129();
    if(state.finance.studyFinanceActive && !isStudent129()){
      state.finance.studyFinanceActive = false;
      addLog('<b>Studiefinanciering gestopt</b><br>Omdat ik niet meer op school/studie zit, werd mijn studiefinanciering stopgezet.', 'warn', false);
    }
  }

  const oldAge129 = window.ageUp || (typeof ageUp==='function'?ageUp:null);
  window.ageUp = function(){
    if(oldAge129) oldAge129();
    enforceStudyFinance129();
    yearlyParentRent129();
    maybeAge18Housing129();
    safeSave(); render();
  };
  try{ ageUp = window.ageUp; }catch(e){}

  const oldRender129 = window.render || (typeof render==='function'?render:null);
  window.render = function(){
    ensure129();
    return oldRender129 ? oldRender129() : null;
  };
})();

