/* v13.3 Club number -> Fling fix */
(function(){
  function ensure133(){
    if(!state) return;
    state.friends = state.friends || [];
    state.flings = state.flings || [];
  }

  window.addFling133 = function(person, source){
    ensure133();
    if(!person || !person.name) return;
    const existing = state.flings.find(f => f.name === person.name);
    const fling = {
      name: person.name,
      age: person.age || state.age,
      gender: person.gender || 'female',
      icon: person.icon || (person.gender==='male'?'👨':'👩'),
      rel: person.rel ?? person.chem ?? r(35,72),
      chem: person.chem ?? person.rel ?? r(45,78),
      status: 'fling',
      from: source || person.from || 'telefoonnummer',
      source: source || person.source || 'telefoonnummer',
      stalkRisk: person.stalkRisk || 0
    };
    if(existing){
      Object.assign(existing, fling, {chem: Math.max(existing.chem||0, fling.chem||0), rel: Math.max(existing.rel||0, fling.rel||0)});
    } else {
      state.flings.push(fling);
    }

    // If older code already placed this number/contact in friends, remove that duplicate.
    state.friends = state.friends.filter(f => !(f && f.name === person.name && /uitgaan|nummer|fling|club/i.test(String(f.from||f.source||''))));
  };

  // Cleanup old wrong saves: club numbers that accidentally landed under friends become flings.
  window.fixClubFriendsToFlings133 = function(){
    ensure133();
    const move = [];
    state.friends = state.friends.filter(f => {
      if(f && f.gender === 'female' && /uitgaan|nummer|club/i.test(String(f.from||f.source||''))){
        move.push(f);
        return false;
      }
      return true;
    });
    move.forEach(f => addFling133({...f, status:'fling', chem:f.chem||f.rel||55}, f.from||'uitgaan'));
    if(move.length){
      try{ addLog(`<b>Fling fix</b><br>${move.length} uitgaan-contact(en) verplaatst van Friends naar Flings.`, 'good', false); }catch(e){}
    }
    return move.length;
  };

  // Override/guard the existing club flirt action when it exists.
  const oldClubTry133 = window.clubTryGirl || (typeof clubTryGirl === 'function' ? clubTryGirl : null);
  if(oldClubTry133){
    window.clubTryGirl = function(clubIndex, girlIndex, tryOns){
      // Let old one-night-stand path behave normally.
      if(tryOns) return oldClubTry133(clubIndex, girlIndex, tryOns);
      const beforeFriends = (state.friends||[]).map(f=>f&&f.name);
      const beforeFlings = (state.flings||[]).map(f=>f&&f.name);
      const ret = oldClubTry133(clubIndex, girlIndex, tryOns);
      try{
        ensure133();
        // Move any newly added female club/uitgaan contact from friends to flings.
        const newWrong = state.friends.filter(f => f && !beforeFriends.includes(f.name) && f.gender==='female' && /uitgaan|club|nummer/i.test(String(f.from||f.source||'')));
        newWrong.forEach(f => addFling133({...f, status:'fling', chem:f.chem||f.rel||55}, f.from||'uitgaan'));
        if(newWrong.length){
          state.friends = state.friends.filter(f => !newWrong.some(x=>x.name===f.name));
          safeSave(); render();
        }
      }catch(e){ console.warn('[v13.3 club fling guard]', e); }
      return ret;
    };
    try{ clubTryGirl = window.clubTryGirl; }catch(e){}
  }

  // Also guard the generic action function after any click.
  const oldAction133 = window.action || (typeof action === 'function' ? action : null);
  if(oldAction133){
    window.action = function(title, text, stats, cash, type){
      const ret = oldAction133(title, text, stats, cash, type);
      try{
        if(/Uitgaan|Night City contact|nummer/i.test(String(title)+' '+String(text))){
          fixClubFriendsToFlings133();
          safeSave();
        }
      }catch(e){}
      return ret;
    };
    try{ action = window.action; }catch(e){}
  }

  // Run on load/render for existing save.
  const oldRender133 = window.render || (typeof render === 'function' ? render : null);
  window.render = function(){
    try{ fixClubFriendsToFlings133(); }catch(e){}
    return oldRender133 ? oldRender133() : null;
  };
  try{ render = window.render; }catch(e){}

  setTimeout(()=>{ try{ fixClubFriendsToFlings133(); safeSave(); render(); }catch(e){} }, 400);
})();

