    const filters=['all','Bijbaan','Retail','Horeca','Logistiek','ICT','Overheid','Sociaal werk','Zorg','Techniek','Management'];
    const filterBtns = `<div class="card"><b>Filter banen</b><br>${filters.map(f=>`<button class="btn ${filter===f?'green':''}" onclick="workScreen134('${f}')">${f==='all'?'Alles':f}</button>`).join('')}</div>`;

    let jobs = DATA.jobs;
    if(filter && filter!=='all') jobs = jobs.filter(j => (j.field||'') === filter || (filter==='Management' && /management|leiding/i.test(j.field||'')));

    let list=jobs.map(j=>{
      let ok=state.age>=j.minAge&&eduScore(eduRank())>=eduScore(j.edu)&&state.stats.Smarts>=j.smart;
      let req=ok?`${j.field} · ${money(j.salary)}/jaar`:`Locked: ${jobRequirement(j)} · ${money(j.salary)}/jaar`;
      return `<button class="btn ${ok?'':'locked'}" onclick="${ok?`startJobInterview('${j.id}')`:''}">${j.title}<br><span class="mini">${req}</span></button>`;
    }).join('');

    showModal(`<div class="modalTop"><div class="avatar">💼</div><div class="modalTitle">Werk richtingen</div></div><div class="modalBody">${cur}${filterBtns}<p>Solliciteren:</p>${list || '<div class="card">Geen banen in deze filter.</div>'}<button class="btn alt" onclick="closeModal()">Terug</button></div>`);
