/* v13.6 Remove visible Text Pack menu, keep texts integrated */
(function(){
  // Override the v13.5 activities injection so the extra menu is not shown.
  const previousActivities136 = window.activitiesHTML || (typeof activitiesHTML === 'function' ? activitiesHTML : null);

  window.activitiesHTML = function(){
    let h = previousActivities136 ? previousActivities136() : '';

    // Remove the visible menu section/button that v13.5 added.
    h = h.replace(
      /<div class="section">Meer variatie<\/div>\s*<div class="row[^>]*onclick="textPackScreen135\(\)"[\s\S]*?<\/div>\s*<\/div>\s*<\/div>/,
      ''
    );

    // Fallback cleanup if row markup differs slightly.
    h = h.replace(/<div class="section">Meer variatie<\/div>/g, '');
    h = h.replace(/<div class="row[^>]*textPackScreen135\(\)[\s\S]*?300\+ random teksten[\s\S]*?<\/div>\s*<\/div>\s*<\/div>/g, '');

    return h;
  };
  try{ activitiesHTML = window.activitiesHTML; }catch(e){}

  // Disable opening the menu directly, but keep the text pack functions/action integration alive.
  window.textPackScreen135 = function(){
    if(typeof toast === 'function') toast('Teksten zitten nu automatisch verwerkt in het spel.');
  };
  try{ textPackScreen135 = window.textPackScreen135; }catch(e){}

  // Refresh current Activities screen if open.
  setTimeout(()=>{
    try{
      const scr=document.getElementById('screen');
      const title=document.getElementById('screenTitle');
      const content=document.getElementById('screenContent');
      if(scr && scr.classList.contains('show') && title && /activit/i.test(title.textContent||'') && content){
        content.innerHTML = activitiesHTML();
      }
      safeSave();
      render();
    }catch(e){}
  },300);
})();

