/* v13.8 Cyberware Expansion - buy multiple different cyberwares + upgrade levels */
(function(){
  function ensureCyber138(){
    if(!state) return;
    state.nc = state.nc || {streetCred:0,heat:0,humanity:100,cyberware:0,techSkill:0,combatSkill:0,corporateTrust:0};
    state.nc.cyberwareOwned = state.nc.cyberwareOwned || {};
    state.nc.humanity = clamp(state.nc.humanity ?? 100);
    state.nc.cyberware = clamp(state.nc.cyberware ?? 0);
    state.nc.techSkill = clamp(state.nc.techSkill ?? 0);
    state.nc.combatSkill = clamp(state.nc.combatSkill ?? 0);
  }

  const CYBERWARE_138 = [
    {id:'optic_scan',icon:'👁️',name:'Optische scanner',cost:1500,boost:6,humanity:2,stat:'tech',desc:'Betere scans, kleine tech boost.'},
    {id:'reflex_boost',icon:'⚡',name:'Reflex booster',cost:3500,boost:9,humanity:4,stat:'combat',desc:'Sneller reageren in fights/races.'},
    {id:'neural_slot',icon:'🧠',name:'Neural memory slot',cost:4500,boost:12,humanity:6,stat:'tech',desc:'Meer netrunning en learning power.'},
    {id:'subdermal_armor',icon:'🛡️',name:'Subdermal armor',cost:6000,boost:12,humanity:7,stat:'combat',desc:'Meer overlevingskans bij Night City geweld.'},
    {id:'smart_link',icon:'🎯',name:'Smart-link targeting',cost:7200,boost:14,humanity:8,stat:'combat',desc:'Meer combat score en straatcred vibe.'},
    {id:'leg_actuators',icon:'🦿',name:'Leg actuators',cost:8500,boost:15,humanity:8,stat:'combat',desc:'Meer mobility bij rennen, races en gevaar.'},
    {id:'netrunner_deck',icon:'💻',name:'Netrunner deck implant',cost:11000,boost:18,humanity:10,stat:'tech',desc:'Grote tech boost, hogere mentale belasting.'},
    {id:'pain_editor',icon:'💉',name:'Pain editor',cost:14500,boost:20,humanity:12,stat:'combat',desc:'Minder snel neer bij geweld, maar minder menselijk gevoel.'},
    {id:'sandevistan',icon:'🌀',name:'Sandevistan prototype',cost:35000,boost:24,humanity:18,stat:'combat',desc:'Extreem sterk, extreem duur, groot Humanity-risico.'},
    {id:'corpo_blackchip',icon:'🏢',name:'Corpo blackchip',cost:52000,boost:28,humanity:22,stat:'tech',desc:'Illegale corpo-grade upgrade. Veel power, veel risico.'}
  ];

  function cyberPower138(){
    ensureCyber138();
    let total = 0;
    Object.values(state.nc.cyberwareOwned||{}).forEach(o=>{ total += (o.boost||0) * (o.level||1); });
    state.nc.cyberware = clamp(total);
    return total;
  }

  function cyberOwnedList138(){
    ensureCyber138();
    const owned = Object.values(state.nc.cyberwareOwned||{});
    if(!owned.length) return '<div class="card">Nog geen cyberware geïnstalleerd.</div>';
    return owned.map(o=>`<div class="card"><b>${o.icon||'🦾'} ${o.name}</b><br>Level: ${o.level||1}/3<br>Power: +${(o.boost||0)*(o.level||1)}<br>Humanity impact totaal: -${(o.humanity||0)*(o.level||1)}</div>`).join('');
  }

  function cyberButton138(c){
    ensureCyber138();
    const owned = state.nc.cyberwareOwned[c.id];
    const lvl = owned ? owned.level || 1 : 0;
    const maxed = lvl >= 3;
    const price = owned ? Math.round(c.cost * (1 + lvl * 0.75)) : c.cost;
    const hum = owned ? Math.round(c.humanity * (1 + lvl * 0.45)) : c.humanity;
    const label = owned ? (maxed ? 'Max level' : `Upgrade naar level ${lvl+1}`) : 'Kopen';
    return `<button class="btn ${maxed?'locked':''}" onclick="${maxed?'':`buyCyberware138('${c.id}')`}">${c.icon} ${c.name}<br><span class="mini">${label} · ${money(price)} · Humanity -${hum}<br>${c.desc}</span></button>`;
  }

  window.ncRipperdoc = function(){
    ensureCyber138();
    cyberPower138();
    showModal(`<div class="modalTop"><div class="avatar">🦾</div><div class="modalTitle glitch">Ripperdoc / Cyberware</div></div>
    <div class="modalBody">
      ${typeof ncStatsHTML==='function'?ncStatsHTML():''}
      <div class="card"><b>Cyberware systeem</b><br>Je kunt nu meerdere verschillende cyberwares kopen en elk onderdeel tot level 3 upgraden.<br><br>Let op: lage Humanity verhoogt de kans op cyberpsychosis-events.</div>
      <div class="section">Geïnstalleerd</div>
      ${cyberOwnedList138()}
      <div class="section">Kopen / upgraden</div>
      ${CYBERWARE_138.map(cyberButton138).join('')}
      <button class="btn alt" onclick="closeModal()">Terug</button>
    </div>`);
  };
  try{ ncRipperdoc = window.ncRipperdoc; }catch(e){}

  window.buyCyberware138 = function(id){
    ensureCyber138();
    const c = CYBERWARE_138.find(x=>x.id===id);
    if(!c) return toast('Cyberware niet gevonden.');
    const owned = state.nc.cyberwareOwned[c.id];
    const lvl = owned ? owned.level || 1 : 0;
    if(lvl >= 3) return toast('Deze cyberware is al max level.');
    const price = owned ? Math.round(c.cost * (1 + lvl * 0.75)) : c.cost;
    const hum = owned ? Math.round(c.humanity * (1 + lvl * 0.45)) : c.humanity;
    if(state.money < price) return toast('Niet genoeg geld voor deze cyberware.');

    state.money -= price;
    if(!owned){
      state.nc.cyberwareOwned[c.id] = {...c, level:1};
    } else {
      owned.level = lvl + 1;
    }

    if(c.stat === 'tech') state.nc.techSkill = clamp((state.nc.techSkill||0) + Math.ceil(c.boost/3));
    if(c.stat === 'combat') state.nc.combatSkill = clamp((state.nc.combatSkill||0) + Math.ceil(c.boost/3));
    state.nc.humanity = clamp((state.nc.humanity||100) - hum);
    cyberPower138();

    closeModal();
    const levelNow = state.nc.cyberwareOwned[c.id].level || 1;
    action('Cyberware', `De ripperdoc ${levelNow===1?'installeerde':'upgrade'} ${c.name} naar level ${levelNow}. Je voelt je sterker, maar iets minder menselijk.`, {Smarts:c.stat==='tech'?2:0, Health:c.stat==='combat'?1:0}, 0, 'warn');

    if(state.nc.humanity < 35 && Math.random() < 0.18){
      action('Humanity warning', 'Na de cyberware merkte ik dat geluiden harder binnenkwamen en mensen verder weg voelden. Misschien moet ik rustiger aan doen.', {Happiness:-7, Smarts:-2}, 0, 'bad');
    }
    if(state.nc.humanity < 20 && Math.random() < 0.25){
      action('Cyberpsychosis', 'Ik hoorde mijn naam uit een kapotte reclamezuil. Night City voelde ineens alsof het terugkeek.', {Happiness:-12, Smarts:-4, Health:-2}, 0, 'bad');
    }
    safeSave(); render();
  };

  // Old inline handlers still call buyCyberware(name,cost,boost,humanityLoss). Keep it working by mapping to new item names.
  window.buyCyberware = function(name,cost,boost,humanityLoss){
    const c = CYBERWARE_138.find(x => x.name === name || name.includes(x.name) || x.name.includes(name));
    if(c) return buyCyberware138(c.id);

    ensureCyber138();
    if(state.money < cost) return toast('Niet genoeg geld voor cyberware.');
    state.money -= cost;
    const id = 'custom_' + String(name).toLowerCase().replace(/[^a-z0-9]+/g,'_');
    const owned = state.nc.cyberwareOwned[id];
    if(owned && (owned.level||1) >= 3) return toast('Deze cyberware is al max level.');
    if(!owned) state.nc.cyberwareOwned[id] = {id,name,icon:'🦾',cost,boost,humanity:humanityLoss,stat:'tech',level:1,desc:'Custom cyberware'};
    else owned.level = (owned.level||1)+1;
    state.nc.techSkill = clamp((state.nc.techSkill||0)+Math.ceil(boost/3));
    state.nc.humanity = clamp((state.nc.humanity||100)-humanityLoss);
    cyberPower138();
    closeModal();
    action('Cyberware', `De ripperdoc installeerde ${name}.`, {Smarts:2,Health:1}, 0, 'warn');
    safeSave(); render();
  };
  try{ buyCyberware = window.buyCyberware; }catch(e){}

  const oldRender138 = window.render || (typeof render==='function'?render:null);
  window.render = function(){
    try{ ensureCyber138(); cyberPower138(); }catch(e){}
    return oldRender138 ? oldRender138() : null;
  };
  try{ render = window.render; }catch(e){}
})();

