/* v14.0 Stable character looks: same skin/hair over life stages */
(function(){
  const SKINS140 = ['🏻','🏼','🏽','🏾','🏿'];
  const HAIRS140 = ['dark','blond','red','curly','grey'];
  const pick140 = a => a[Math.floor(Math.random()*a.length)];
  const g140 = g => /female|girl|vrouw|meis/i.test(String(g)) ? 'female' : 'male';

  function ageStage140(age){
    age = Number(age||0);
    if(age <= 1) return 'baby';
    if(age < 13) return 'child';
    if(age < 20) return 'teen';
    if(age < 65) return 'adult';
    return 'elder';
  }

  function makeTraits140(gender){
    gender = g140(gender);
    return {
      gender,
      skin: pick140(SKINS140),
      hair: pick140(HAIRS140.filter(h => h !== 'grey')),
      beard: gender === 'male' && Math.random() < 0.28,
      style: pick140(['casual','normal','work','tech','sport'])
    };
  }

  function iconFromTraits140(traits, age){
    traits = traits || makeTraits140('male');
    const gender = g140(traits.gender);
    const skin = traits.skin || '🏼';
    const hair = traits.hair || 'dark';
    const stage = ageStage140(age);

    if(stage === 'baby') return '👶' + skin;
    if(stage === 'child'){
      if(gender === 'female') return '👧' + skin;
      return '👦' + skin;
    }

    if(stage === 'elder'){
      if(gender === 'female') return '👵' + skin;
      return '👴' + skin;
    }

    // Teen/adult keep same skin + hair vibe.
    if(gender === 'female'){
      if(hair === 'blond') return '👱' + skin + '‍♀️';
      if(hair === 'red') return '👩' + skin + '‍🦰';
      if(hair === 'curly') return '👩' + skin + '‍🦱';
      if(hair === 'grey') return '👩' + skin + '‍🦳';
      if(traits.style === 'work') return '👩' + skin + '‍💼';
      if(traits.style === 'tech') return '👩' + skin + '‍💻';
      return '👩' + skin;
    }

    if(traits.beard && stage === 'adult'){
      // Beard emoji supports skin tone but not stable hair color; only use for bearded trait.
      return '🧔' + skin;
    }
    if(hair === 'blond') return '👱' + skin + '‍♂️';
    if(hair === 'red') return '👨' + skin + '‍🦰';
    if(hair === 'curly') return '👨' + skin + '‍🦱';
    if(hair === 'grey') return '👨' + skin + '‍🦳';
    if(traits.style === 'work') return '👨' + skin + '‍💼';
    if(traits.style === 'tech') return '👨' + skin + '‍💻';
    return '👨' + skin;
  }

  window.ensureStableLook140 = function(person, forcedGender){
    if(!person) return null;
    const gender = g140(person.gender || forcedGender || 'male');

    // If v13.9 already assigned random icon, convert once to stable traits.
    if(!person.lookTraits140){
      person.lookTraits140 = makeTraits140(gender);

      // Try to preserve rough skin tone from existing emoji if possible.
      const old = String(person.icon||'');
      const skin = SKINS140.find(s => old.includes(s));
      if(skin) person.lookTraits140.skin = skin;

      if(/👱/.test(old)) person.lookTraits140.hair = 'blond';
      else if(/🦰/.test(old)) person.lookTraits140.hair = 'red';
      else if(/🦱/.test(old)) person.lookTraits140.hair = 'curly';
      else if(/🦳|👵|👴/.test(old)) person.lookTraits140.hair = 'grey';
      if(/🧔/.test(old)) person.lookTraits140.beard = true;

      person.lookStage140 = null;
    }

    person.lookTraits140.gender = gender;
    const stage = ageStage140(person.age ?? state?.age ?? 20);

    // Only change sprite when age stage changes, not every render.
    if(person.lookStage140 !== stage || !person.icon){
      person.icon = iconFromTraits140(person.lookTraits140, person.age ?? state?.age ?? 20);
      person.lookStage140 = stage;
    }
    return person.icon;
  };

  window.assignStableLooks140 = function(){
    if(!state) return;

    // Player
    state.lookTraits140 = state.lookTraits140 || makeTraits140(state.gender || 'male');
    state.lookTraits140.gender = g140(state.gender || 'male');
    const playerStage = ageStage140(state.age || 0);
    if(state.lookStage140 !== playerStage || !state.icon){
      state.icon = iconFromTraits140(state.lookTraits140, state.age || 0);
      state.lookStage140 = playerStage;
    }

    // Single people
    if(state.mother) ensureStableLook140(state.mother, 'female');
    if(state.father) ensureStableLook140(state.father, 'male');
    if(state.partner) ensureStableLook140(state.partner, state.partner.gender || 'female');

    // Groups
    const groups = [
      state.friends, state.flings, state.exes, state.colleagues,
      state.children, state.siblings,
      state.school && state.school.classmates
    ].filter(Array.isArray);

    groups.forEach(list => list.forEach(p => ensureStableLook140(p, p && p.gender)));
  };

  // HumanIcon is still random for brand new generated NPCs, but once stored on a person, assignStableLooks140 locks it.
  window.humanIcon = function(gender, age){
    const traits = makeTraits140(gender);
    return iconFromTraits140(traits, age || 20);
  };
  try{ humanIcon = window.humanIcon; }catch(e){}

  // Patch confirm start so player traits are created once and then stable.
  const prevConfirm140 = window.confirmCharacterSetup || (typeof confirmCharacterSetup === 'function' ? confirmCharacterSetup : null);
  window.confirmCharacterSetup = function(gender){
    gender = g140(gender);
    const first = (document.getElementById('startFirstName')?.value || '').trim();
    const last = (document.getElementById('startLastName')?.value || '').trim();
    try{
      if(prevConfirm140) prevConfirm140(gender);
      if(state){
        state.lookTraits140 = makeTraits140(gender);
        state.lookStage140 = null;
        state.icon = iconFromTraits140(state.lookTraits140, state.age || 0);
        if(state.mother){ state.mother.lookTraits140 = makeTraits140('female'); state.mother.lookStage140 = null; ensureStableLook140(state.mother,'female'); }
        if(state.father){ state.father.lookTraits140 = makeTraits140('male'); state.father.lookStage140 = null; ensureStableLook140(state.father,'male'); }
        assignStableLooks140();
        safeSave(); render();
      }
    }catch(e){
      alert('Starten lukt niet: '+e.message);
    }
  };
  try{ confirmCharacterSetup = window.confirmCharacterSetup; }catch(e){}

  const prevRender140 = window.render || (typeof render === 'function' ? render : null);
  window.render = function(){
    try{ assignStableLooks140(); }catch(e){ console.warn('[v14 stable looks]', e); }
    return prevRender140 ? prevRender140() : null;
  };
  try{ render = window.render; }catch(e){}

  const prevAge140 = window.ageUp || (typeof ageUp === 'function' ? ageUp : null);
  window.ageUp = function(){
    if(prevAge140) prevAge140();
    try{
      assignStableLooks140();
      safeSave();
      render();
    }catch(e){}
  };
  try{ ageUp = window.ageUp; }catch(e){}

  setTimeout(()=>{ try{ assignStableLooks140(); safeSave(); render(); }catch(e){} }, 500);
})();

