    if(!state.lookTraits144){
      state.lookTraits144=normalizeTraits144(state, state.gender||'male');
      state.lookStage144=null;
      changed=true;
    }
    state.lookTraits144.gender=g144(state.gender||'male');
    const pst=stage144(state.age||0);
