    action(auto?'Uitgewerkt':'Ontnuchterd',hang?'Ik werd weer nuchter, maar voelde me wat traag en droog in mijn mond.':'Ik werd weer nuchter en keerde terug naar de normale wereld.',{Happiness:hang?-2:1,Health:hang?-1:0,Stamina:hang?-4:1},0,hang?'warn':'good');
    safeSave(); render(); openScreen('activities');
