/* v14.7 Save Persistence Fix */
(function(){
  const MASTER='bitzlife_master_save';
  const BACKUP='bitzlife_master_save_backup';
  const A='bitzlife_autosave_slot_a';
  const B='bitzlife_autosave_slot_b';
  const LEGACY=['bitzlife_v146_weed_trip_mode','bitzlife_v145_save_system_audit','bitzlife_v144_avatar_lock_fix','bitzlife_v143_random_start_button_hardfix','bitzlife_v142_start_random_sprite_lock','bitzlife_v141_stable_sprite_random_names','bitzlife_v140_stable_character_looks','bitzlife_v139_names_avatar_variety','bitzlife_v138_cyberware_expansion','bitzlife_v137_crime_expansion'];

  function cpy(o){return JSON.parse(JSON.stringify(o||{}));}
  function trim(s){
    s=cpy(s); s.version='14.7'; s.savedAt=Date.now(); s.saveId=s.saveId||('save_'+Date.now()+'_'+Math.random().toString(36).slice(2));
    if(Array.isArray(s.log))s.log=s.log.slice(-120);
    if(Array.isArray(s.snapshots))s.snapshots=s.snapshots.slice(-2).map(x=>{if(x&&Array.isArray(x.log))x.log=x.log.slice(-25);if(x)x.snapshots=[];return x;});
    const caps={items:200,friends:100,flings:100,exes:90,colleagues:80,children:80,siblings:80,pets:60,cars:50,houses:50,achievements:120};
    Object.entries(caps).forEach(([k,n])=>{if(Array.isArray(s[k]))s[k]=s[k].slice(-n);});
    if(s.japan&&Array.isArray(s.japan.memories))s.japan.memories=s.japan.memories.slice(-35);
    if(s.jamaica&&Array.isArray(s.jamaica.memories))s.jamaica.memories=s.jamaica.memories.slice(-35);
    delete s.debug;delete s._debug;delete s.cache;delete s.temp;
    return s;
  }
  function prep(){
    if(!state)return null;
    try{if(typeof lockAllAvatars144==='function')lockAllAvatars144();}catch(e){}
    return trim(state);
  }
  window.saveGame=function(){
    if(!state)return false;
    let data=prep(); if(!data)return false;
    const tries=[
      ()=>{let old=localStorage.getItem(MASTER)||''; if(old)localStorage.setItem(BACKUP,old); localStorage.setItem(MASTER,JSON.stringify(data)); localStorage.setItem(A,JSON.stringify(data)); sessionStorage.setItem(MASTER,JSON.stringify(data));},
      ()=>{data=trim(data);data.snapshots=[];data.log=(data.log||[]).slice(-60);localStorage.setItem(MASTER,JSON.stringify(data));localStorage.setItem(B,JSON.stringify(data));sessionStorage.setItem(MASTER,JSON.stringify(data));},
      ()=>{data.log=(data.log||[]).slice(-25);data.snapshots=[];if(Array.isArray(data.items))data.items=data.items.slice(-80);localStorage.setItem(MASTER,JSON.stringify(data));},
      ()=>sessionStorage.setItem(MASTER,JSON.stringify(data))
    ];
    for(const t of tries){try{t();return true;}catch(e){console.warn('[v14.7 save retry]',e);}}
    return false;
  };
  window.safeSave=function(){try{return saveGame();}catch(e){console.warn('[v14.7 safeSave]',e);return false;}};
  try{saveGame=window.saveGame;safeSave=window.safeSave;}catch(e){}

  function read(k){try{const raw=localStorage.getItem(k)||sessionStorage.getItem(k);if(!raw)return null;const o=JSON.parse(raw);if(!o||typeof o!=='object')return null;o._sourceKey147=k;return o;}catch(e){return null;}}
  function score(s){if(!s)return-1;return (Number(s.savedAt||0)/100000000)+(Number(s.age||0)*1000)+(Array.isArray(s.log)?s.log.length:0)+(s.name?500:0)+(s.dead?-100:0);}
  function bestSave(){
    const keys=[MASTER,BACKUP,A,B,...LEGACY];
    try{for(let i=0;i<localStorage.length;i++){const k=localStorage.key(i);if(k&&/^(bitzlife|bitlife|bitz_life)/i.test(k)&&!keys.includes(k))keys.push(k);}}catch(e){}
    let best=null; keys.forEach(k=>{const s=read(k); if(score(s)>score(best))best=s;}); return best;
  }
  function apply(o,show){
    try{state=typeof migrate==='function'?migrate(o):o;state=trim(state);try{if(typeof lockAllAvatars144==='function')lockAllAvatars144();}catch(e){};safeSave();if(typeof render==='function')render();if(show&&typeof toast==='function')toast('Save geladen');return true;}catch(e){console.warn('[v14.7 load apply]',e);return false;}
  }
  window.loadGame=function(show){
    const s=bestSave();
    if(s)return apply(s,show);
    state=null; if(typeof openCharacterSetup==='function')openCharacterSetup(); if(show&&typeof toast==='function')toast('Geen save gevonden'); return false;
  };
  try{loadGame=window.loadGame;}catch(e){}

  window.saveStatus147=function(){
    const s=bestSave();
    const size=(()=>{try{return Math.round(new Blob([JSON.stringify(prep()||{})]).size/1024);}catch(e){return'?';}})();
    let n=0;try{for(let i=0;i<localStorage.length;i++){const k=localStorage.key(i);if(k&&/^(bitzlife|bitlife|bitz_life)/i.test(k))n++;}}catch(e){}
    showModal(`<div class="modalTop"><div class="avatar">💾</div><div class="modalTitle">Save status</div></div><div class="modalBody"><div class="card"><b>Master key:</b><br>${MASTER}<br><br><b>Beste save:</b><br>${s?(s.name||'zonder naam')+' · leeftijd '+(s.age||0)+'<br>Bron: '+s._sourceKey147:'geen'}<br><br><b>Grootte:</b> ${size} KB<br><b>BitzLife saves:</b> ${n}</div><button class="btn green" onclick="saveGame();toast('Save opgeslagen')">💾 Save nu</button><button class="btn" onclick="loadGame(true)">📂 Load beste save</button><button class="btn" onclick="exportSave()">📤 Export JSON</button><button class="btn" onclick="importSave145?importSave145():toast('Import niet beschikbaar')">📥 Import JSON</button><button class="btn alt" onclick="closeModal()">Terug</button></div>`);
  };

  const oldToggle=window.toggleMenu||(typeof toggleMenu==='function'?toggleMenu:null);
  if(oldToggle){window.toggleMenu=function(force){const ret=oldToggle(force);setTimeout(()=>{try{const m=document.getElementById('menu');if(m&&!document.getElementById('saveStatusBtn147')){const b=document.createElement('button');b.id='saveStatusBtn147';b.className='btn';b.textContent='Save status';b.onclick=()=>saveStatus147();const close=[...m.querySelectorAll('button')].find(x=>/Close/i.test(x.textContent||''));if(close)m.insertBefore(b,close);else m.appendChild(b);}}catch(e){}},30);return ret;};try{toggleMenu=window.toggleMenu;}catch(e){}}

  window.addEventListener('pagehide',()=>{try{safeSave();}catch(e){}});
  window.addEventListener('beforeunload',()=>{try{safeSave();}catch(e){}});
  document.addEventListener('visibilitychange',()=>{try{if(document.hidden)safeSave();}catch(e){}});

  const oldAge=window.ageUp||(typeof ageUp==='function'?ageUp:null);
  window.ageUp=function(){if(oldAge)oldAge();try{safeSave();}catch(e){}};
  try{ageUp=window.ageUp;}catch(e){}

  setTimeout(()=>{try{const real=state&&state.log&&state.log.length>0&&state.name&&state.age>0;const s=bestSave();if(s&&!real)apply(s,false);else if(state)safeSave();}catch(e){}},400);
})();

