/* v14.8 Gaming reactions */
(function(){
  function ensureGame148(){
    if(!state) return;
    state.gaming = state.gaming || {rage:0,fun:0,skill:0};
  }

  const rageLines148 = [
    'Kanker spel, kut Rocket League!',
    'Wat is dit voor scripted onzin man?',
    'Mijn teammate heeft letterlijk twee linkerhanden.',
    'Bro, die hitbox klopt voor geen meter.',
    'Ik zweer dit spel wil gewoon niet dat ik win.',
    'Hoe kan hij die bal missen, hij stond ernaast!',
    'Ik drukte gewoon op de knop man, dit spel liegt.',
    'Kut game, maar nog één potje dan.',
    'Ik ben niet boos, het spel is gewoon kanker irritant.',
    'Dit is precies waarom ranked slecht is voor je bloeddruk.'
  ];

  const happyLines148 = [
    'Wat een leuk spel eigenlijk.',
    'Oké, deze pot was echt lekker.',
    'Dit voelt eindelijk fair en soepel.',
    'Ik had gewoon plezier, zonder te tryharden.',
    'Die goal/actie voelde echt clean.',
    'Ik snap weer waarom ik games leuk vind.',
    'Lekker potje, precies goede vibe.',
    'Ik speelde relaxed en alles klikte.',
    'Zelfs verliezen voelde niet erg deze keer.',
    'Dit spel kan dus wél leuk zijn.'
  ];

  const neutralLines148 = [
    'Ik ging gamen en vergat even de tijd.',
    'Ik speelde een paar potjes en zat er redelijk in.',
    'Het was niet geweldig, niet slecht, gewoon game-avond.',
    'Ik probeerde rustig te blijven, met wisselend succes.',
    'Ik had goede momenten en domme fouten door elkaar.'
  ];

  window.gamingReactionScreen148 = function(){
    ensureGame148();
    showModal(`<div class="modalTop"><div class="avatar">🎮</div><div class="modalTitle">Gamen</div></div>
    <div class="modalBody">
      <div class="card"><b>Gaming reactie</b><br>Kies hoe je reageert tijdens het gamen.</div>
      <button class="btn red" onclick="gamingReaction148('rage')">😡 Ragen<br><span class="mini">“Kanker spel, kut Rocket League!”</span></button>
      <button class="btn green" onclick="gamingReaction148('fun')">😄 Positief reageren<br><span class="mini">“Wat een leuk spel.”</span></button>
      <button class="btn" onclick="gamingReaction148('neutral')">🎮 Gewoon doorspelen</button>
      <button class="btn alt" onclick="closeModal()">Terug</button>
    </div>`);
  };

  window.gamingReaction148 = function(kind){
    ensureGame148();
    closeModal();

    if(kind === 'rage'){
      const line = pick(rageLines148);
      state.gaming.rage = (state.gaming.rage||0) + 1;
      const extra = state.gaming.rage >= 5 ? '<br><br>Ik merk dat ik steeds vaker tilt tijdens gamen. Misschien moet ik soms pauze nemen.' : '';
      action('Gaming rage', `${line}${extra}`, {Happiness:-5,Health:-1,Stamina:-4,Smarts:-1}, 0, 'bad');
      return;
    }

    if(kind === 'fun'){
      const line = pick(happyLines148);
      state.gaming.fun = (state.gaming.fun||0) + 1;
      state.gaming.skill = clamp((state.gaming.skill||0)+1);
      action('Leuk potje', line, {Happiness:7,Stamina:-2,Smarts:1}, 0, 'good');
      return;
    }

    const line = pick(neutralLines148);
    state.gaming.skill = clamp((state.gaming.skill||0)+1);
    action('Gamen', line, {Happiness:2,Stamina:-3}, 0, 'good');
  };

  const oldActivities148 = window.activitiesHTML || (typeof activitiesHTML === 'function' ? activitiesHTML : null);
  window.activitiesHTML = function(){
    let h = oldActivities148 ? oldActivities148() : '';
    if(state && !(state.weedTrip && state.weedTrip.active) && !h.includes('Gaming reactie')){
      h += `<div class="section">Gamen</div>${row('🎮','Gaming reactie','Ragen, positief reageren of gewoon doorspelen','gamingReactionScreen148()')}`;
    }
    return h;
  };
  try{ activitiesHTML = window.activitiesHTML; }catch(e){}

  const oldWeedGaming148 = window.weedGaming146;
  if(oldWeedGaming148){
    window.weedGaming146 = function(){
      if(Math.random() < 0.55) return gamingReactionScreen148();
      return oldWeedGaming148();
    };
    try{ weedGaming146 = window.weedGaming146; }catch(e){}
  }

  setTimeout(()=>{ try{ safeSave(); }catch(e){} },300);
})();

