/* v14.9 Friend gaming reaction integrated in Chillen met vrienden -> Gamen */
(function(){
  function ensureFriendGaming149(){
    if(!state)return;
    state.gaming = state.gaming || {rage:0,fun:0,skill:0};
    state.friends = state.friends || [];
  }

  window.friendGamingReactionScreen149 = function(friendName, friendIndex){
    ensureFriendGaming149();
    friendName = friendName || 'vrienden';
    window.__friendGaming149 = {name:friendName, index:Number.isFinite(+friendIndex)?+friendIndex:null};
    showModal(`<div class="modalTop"><div class="avatar">🖥️</div><div class="modalTitle">Gamen met ${friendName}</div></div>
    <div class="modalBody">
      <div class="card">Jullie gaan gamen. Hoe reageer jij tijdens de potjes?</div>
      <button class="btn red" onclick="friendGamingReaction149('rage')">😡 Ragen<br><span class="mini">“Kanker spel, kut Rocket League!”</span></button>
      <button class="btn green" onclick="friendGamingReaction149('fun')">😄 Positief reageren<br><span class="mini">“Wat een leuk spel.”</span></button>
      <button class="btn" onclick="friendGamingReaction149('neutral')">🎮 Gewoon doorspelen</button>
      <button class="btn alt" onclick="chillWithFriendsScreen()">Terug</button>
    </div>`);
  };

  window.friendGamingReaction149 = function(kind){
    ensureFriendGaming149();
    const ctx = window.__friendGaming149 || {};
    const f = Number.isFinite(ctx.index) ? state.friends[ctx.index] : null;
    const name = ctx.name || (f?f.name:'vrienden');
    closeModal();

    if(kind === 'rage'){
      const lines = [
        `Ik ging gamen met ${name} en riep: “Kanker spel, kut Rocket League!”`,
        `Ik tiltte compleet tijdens het gamen met ${name}. Kut spel, kut hitbox, kut ranked.`,
        `Ik werd veel te fanatiek met ${name} en schold op de game alsof die mij persoonlijk haatte.`,
        `Ik riep dat het spel scripted was. ${name} moest lachen, maar ik was echt pissig.`,
        `Ik zei “nog één potje”, maar bedoelde eigenlijk nog vijf potjes boos worden.`
      ];
      if(f) addRel(f, -r(1,4));
      state.gaming.rage = (state.gaming.rage||0)+1;
      action('Gamen met vrienden', pick(lines), {Happiness:-4,Health:-1,Stamina:-5,Smarts:-1}, 0, 'bad');
      return;
    }

    if(kind === 'fun'){
      const lines = [
        `Ik ging gamen met ${name} en zei: “Wat een leuk spel eigenlijk.” Het bleef gezellig.`,
        `Ik speelde relaxed met ${name}. Zelfs verliezen voelde niet erg.`,
        `Ik had een lekker potje met ${name}. Goede vibe, veel lachen, weinig tilt.`,
        `Ik bleef positief tijdens het gamen met ${name}. Daardoor werd het juist leuker.`,
        `Ik maakte een mooie actie en ${name} hypete me alsof het Champions League was.`
      ];
      if(f) addRel(f, r(3,8));
      state.gaming.fun = (state.gaming.fun||0)+1;
      state.gaming.skill = clamp((state.gaming.skill||0)+1);
      action('Gamen met vrienden', pick(lines), {Happiness:8,Stamina:-3,Smarts:1}, 0, 'good');
      return;
    }

    const lines = [
      `Ik ging gamen met ${name}. We werden fanatiek, maar het bleef normaal.`,
      `Ik speelde een paar potjes met ${name}. Niet geweldig, niet slecht, gewoon gezellig.`,
      `Ik ging online met ${name}. We wonnen wat, verloren wat en deden alsof dat tactiek was.`,
      `Ik speelde rustig door met ${name}. Soms is gewoon gamen genoeg.`
    ];
    if(f) addRel(f, r(1,5));
    state.gaming.skill = clamp((state.gaming.skill||0)+1);
    action('Gamen met vrienden', pick(lines), {Happiness:5,Stamina:-4}, 0, 'good');
  };

  const oldChill149 = window.chillWithFriends || (typeof chillWithFriends === 'function' ? chillWithFriends : null);
  window.chillWithFriends = function(kind){
    ensureFriendGaming149();
    if(kind === 'game'){
      const idx = state.friends && state.friends.length ? Math.floor(Math.random()*state.friends.length) : null;
      const f = idx !== null ? state.friends[idx] : null;
      const name = f ? f.name : 'een paar gasten uit de buurt';
      return friendGamingReactionScreen149(name, idx);
    }
    return oldChill149 ? oldChill149(kind) : null;
  };
  try{ chillWithFriends = window.chillWithFriends; }catch(e){}

  // Remove duplicate "Gaming reactie" from Activities if user only wants it via chill screen.
  const oldActivities149 = window.activitiesHTML || (typeof activitiesHTML === 'function' ? activitiesHTML : null);
  window.activitiesHTML = function(){
    let h = oldActivities149 ? oldActivities149() : '';
    // Keep normal game option if already present, but mark it secondary. The friend modal is now the main route.
    return h;
  };
  try{ activitiesHTML = window.activitiesHTML; }catch(e){}

  setTimeout(()=>{ try{ safeSave(); }catch(e){} },300);
})();

