  window.ncDistrictAction151 = function(d,a){
    ensureNC151();
    if(d==='mega' && a==='home'){ closeModal(); return homeLifeScreen(); }
    if(d==='alley' && a==='fixer') return ncFixerBoard151();
    if(d==='ripper' && a==='ripper'){ closeModal(); return (window.ncRipperdoc?ncRipperdoc():toast('Ripperdoc niet gevonden')); }
    if(d==='corpo' && a==='club') return ncAfterDark151('corpoClub');
    if(d==='alley' && a==='sexwork') return ncSexLife151('redlight');
    if(d==='alley' && a==='drugs') return ncDrugMenu151();
    if(d==='ripper' && a==='therapy') return ncHumanityTherapy151();

    let txt='', stats={}, cash=0, type='good';
    if(d==='neon' && a==='shop'){ cash=-Math.min(state.money,r(20,120)); txt='Ik struinde over Neon Market en kocht iets dat waarschijnlijk niet helemaal legaal geïmporteerd was.'; stats={Happiness:4,Smarts:1}; }
    if(d==='neon' && a==='food'){ cash=-Math.min(state.money,r(8,35)); txt='Ik at street food onder knipperende reclameborden. Vet, warm en precies fout genoeg om goed te zijn.'; stats={Happiness:5,Health:1}; }
    if(d==='neon' && a==='meet'){
      const g=Math.random()<.5?'female':'male';
      const name=p151(DATE_NAMES[g]||DATA.firstNames)+' '+p151(DATA.lastNames);
      if(Math.random()<.5){ state.friends.push({name,age:r(Math.max(18,state.age-3),state.age+5),gender:g,icon:humanIcon(g,state.age),rel:r(30,65),from:'Night City'}); txt=`Ik ontmoette ${name} op Neon Market. Niet meteen beste vrienden, maar er was een klik.`; }
      else { state.flings.push({name,age:r(Math.max(18,state.age-3),state.age+5),gender:g,icon:humanIcon(g,state.age),rel:r(25,55),chem:r(40,75),from:'Night City',status:'fling'}); txt=`Ik wisselde nummers uit met ${name}. Het voelt meer als fling dan gewone vriendschap.`; }
      stats={Happiness:5};
    }
    if(d==='neon' && a==='scam'){ let ok=Math.random()>.45; cash=ok?r(100,900):-Math.min(state.money,r(80,500)); txt=ok?'Ik draaide een snelle deal op Neon Market en liep weg met winst. Niet netjes, wel effectief.':'Ik dacht slim te zijn, maar werd zelf gescamd. Night City lachte me uit.'; stats={Happiness:ok?5:-6,Smarts:ok?2:1}; type=ok?'good':'bad'; state.nc.heat=clampNC151(state.nc.heat+(ok?4:2)); }
    if(d==='mega' && a==='neighbor'){ txt=p151(['Mijn megablock-buurman vroeg of ik een geluid hoorde dat er niet was. We deden alsof dat normaal was.','Er was ruzie in de gang. Ik koos verstandig voor mijn eigen deur dicht.','Een buur gaf me eten dat beter smaakte dan het eruitzag.']); stats={Happiness:r(-1,5),Smarts:1}; }
    if(d==='mega' && a==='lift'){ txt='De lift bleef hangen tussen twee verdiepingen. Iemand begon te praten over crypto, wat het erger maakte.'; stats={Happiness:-2,Stamina:-2,Smarts:1}; }
    if(d==='mega' && a==='package'){ let ok=Math.random()<.6; txt=ok?'Ik leverde een verdacht pakket af zonder vragen te stellen. De fixer-app gaf me street cred.':'Ik opende een verdacht pakket en kreeg direct spijt. Heat omhoog, stress omhoog.'; stats={Happiness:ok?3:-5,Smarts:1}; cash=ok?r(60,250):0; state.nc.streetCred=clampNC151(state.nc.streetCred+(ok?3:0)); state.nc.heat=clampNC151(state.nc.heat+(ok?2:8)); type=ok?'good':'warn'; }
    if(d==='corpo' && a==='deal'){ let ok=Math.random()<.55; txt=ok?'Ik sloot een gladde corpo-deal. Veel glimlachen, weinig vertrouwen, wel geld.':'De corpo-deal draaide tegen me. Ik werd gebruikt als pion en voelde me vies.'; cash=ok?r(400,2600):-Math.min(state.money,r(150,900)); stats={Happiness:ok?3:-8,Smarts:2}; state.nc.factions.corpoSec=clampNC151(state.nc.factions.corpoSec+(ok?5:-4)); type=ok?'good':'bad'; }
    if(d==='corpo' && a==='blackmail'){ let ok=Math.random()<.42; txt=ok?'Ik vond genoeg info om iemand subtiel onder druk te zetten. Gevaarlijk, maar winstgevend.':'Ik probeerde chantage, maar mijn target was beter beveiligd dan verwacht. Heat omhoog.'; cash=ok?r(600,4200):-Math.min(state.money,r(200,1000)); stats={Happiness:ok?2:-9,Smarts:ok?3:1}; state.nc.heat=clampNC151(state.nc.heat+(ok?12:22)); type=ok?'warn':'bad'; }
    if(d==='corpo' && a==='job'){ txt='Ik netwerkte in het Corpo District. Iedereen klonk nep, maar er zaten echte kansen tussen.'; stats={Smarts:3,Happiness:-1}; state.nc.factions.corpoSec=clampNC151(state.nc.factions.corpoSec+2); }
    if(d==='alley' && a==='fight'){ let ok=Math.random()<((state.fitness||50)+(state.stamina||50)+(state.nc.streetCred||0))/220; txt=ok?'Ik won een underground fight. Pijnlijke knokkels, meer street cred.':'Ik verloor een underground fight en voelde elk stuk beton in die steeg.'; stats={Happiness:ok?7:-8,Health:ok?-3:-14,Fitness:2,Stamina:-10}; cash=ok?r(250,1800):-Math.min(state.money,r(50,400)); state.nc.streetCred=clampNC151(state.nc.streetCred+(ok?7:1)); type=ok?'good':'bad'; }
    if(d==='ripper' && a==='blackmed'){ cash=-Math.min(state.money,r(80,450)); txt='Ik nam black market meds. Mijn lichaam voelde sneller beter, maar mijn hoofd vertrouwde het niet helemaal.'; stats={Health:8,Happiness:-2,Smarts:-1}; state.nc.heat=clampNC151(state.nc.heat+3); type='warn'; }
    if(d==='ripper' && a==='scan'){ cash=-Math.min(state.money,r(30,120)); txt=`Body scan gedaan. Humanity ${state.nc.humanity}%, Heat ${state.nc.heat}%. De machine zei niets geruststellends.`; stats={Smarts:2}; }
    txt += ncRandomDanger151(d);
    closeModal(); action('Night City',txt,stats,cash,type); safeSave(); render();
  };

