  window.ncResolveGig151 = function(choice){
    ensureNC151();
    const gig = window.__ncGig151;
    if(!gig) return closeModal();
    let txt='', stats={}, cash=0, type='good';
    const kind = gig.kind;
    function rep(f,d){ state.nc.fixers[f].rep = clampNC151((state.nc.fixers[f].rep||0)+d); }
    if(kind==='package'){
      if(choice==='deliver'){txt='Ik leverde het pakket af zonder vragen. Rex vond me betrouwbaar.';cash=r(180,700);state.nc.streetCred=clampNC151(state.nc.streetCred+4);rep('rex',5);}
      if(choice==='open'){txt='Ik opende het pakket. Het was niet slim, maar ik vond bruikbare info.';cash=r(40,200);state.nc.heat=clampNC151(state.nc.heat+8);stats={Smarts:3};rep('rex',-4);}
      if(choice==='sell'){txt='Ik verkocht het pakket zelf. Veel winst, maar Rex gaat dit onthouden.';cash=r(900,3500);state.nc.heat=clampNC151(state.nc.heat+15);rep('rex',-12);type='warn';}
      if(choice==='police'){txt='Ik tipte de politie. Heat ging omlaag, maar op straat noemen ze dat laf.';state.nc.heat=clampNC151(state.nc.heat-12);state.nc.streetCred=clampNC151(state.nc.streetCred-8);rep('rex',-15);stats={Happiness:-3,Smarts:2};}
    }
    if(kind==='data'){
      if(choice==='hack'){let ok=Math.random()<((state.nc.netrunner.skill+state.nc.netrunner.deck*12+state.stats.Smarts)/160);txt=ok?'Ik brak door de security en pakte de data shard. Clean hack.':'Black ICE beet terug. Ik kwam weg, maar trace en hoofdpijn bleven hangen.';cash=ok?r(600,2600):0;state.nc.netrunner.skill+=ok?3:1;state.nc.netrunner.trace=clampNC151(state.nc.netrunner.trace+(ok?8:24));stats={Smarts:ok?4:-2,Happiness:ok?4:-6};type=ok?'good':'bad';rep('mila',ok?6:-3);}
      if(choice==='buy'){cash=-Math.min(state.money,r(200,800));txt='Ik kocht toegang in plaats van zelf te hacken. Minder stoer, wel effectief.';state.nc.netrunner.data+=1;rep('mila',2);}
      if(choice==='sell2'){txt='Ik verkocht dezelfde data aan twee partijen. Slim of dom, dat weet ik later pas.';cash=r(1600,5200);state.nc.heat=clampNC151(state.nc.heat+24);state.nc.netrunner.trace=clampNC151(state.nc.netrunner.trace+20);type='warn';rep('mila',-8);}
      if(choice==='abort'){txt='Ik brak de data-gig af. Geen winst, maar ook geen trace.';stats={Happiness:-1,Smarts:1};}
    }
    if(kind==='escort'){
      if(choice==='safe'){txt='Ik koos de veilige route. Saai, maar de VIP kwam heel aan.';cash=r(250,900);state.nc.factions.corpoSec=clampNC151(state.nc.factions.corpoSec+4);rep('voss',4);}
      if(choice==='fast'){let ok=Math.random()<((state.talents?.drive||0)+(state.talents?.race||0)+(state.stamina||50))/150;txt=ok?'Ik reed absurd snel en schudde iedereen af. Red Circuit respecteerde het.':'Ik nam te veel risico en eindigde met schade, stress en geschreeuw.';cash=ok?r(800,2600):-Math.min(state.money,r(200,1200));state.nc.factions.redCircuit=clampNC151(state.nc.factions.redCircuit+(ok?8:-4));stats={Happiness:ok?7:-7,Health:ok?-1:-6,Stamina:-8};type=ok?'good':'bad';}
      if(choice==='betray'){txt='Ik verkocht de VIP-route door. Veel geld, maar CorpoSec zet me op een lijst.';cash=r(2200,7000);state.nc.factions.corpoSec=clampNC151(state.nc.factions.corpoSec-18);state.nc.heat=clampNC151(state.nc.heat+25);type='bad';}
      if(choice==='talk'){txt='Ik praatte de VIP rustig. Niet spectaculair, wel professioneel.';cash=r(300,1200);stats={Smarts:2,Happiness:2};rep('voss',5);}
    }
    if(kind==='debt'){
      if(choice==='talk'){txt='Ik praatte de schuld los zonder geweld. Minder geld, meer menselijkheid.';cash=r(100,600);state.nc.humanity=clampNC151(state.nc.humanity+3);rep('rex',2);}
      if(choice==='threat'){txt='Ik dreigde en kreeg het geld. Effectief, maar ik voelde me erna kouder.';cash=r(700,3000);state.nc.humanity=clampNC151(state.nc.humanity-4);state.nc.heat=clampNC151(state.nc.heat+10);type='warn';rep('rex',5);}
      if(choice==='walk'){txt='Ik weigerde de klus. Slecht voor mijn fixer-rep, goed voor mijn geweten.';state.nc.humanity=clampNC151(state.nc.humanity+6);rep('rex',-8);stats={Happiness:2};}
      if(choice==='frame'){txt='Ik frame-de iemand anders. Slim, smerig en gevaarlijk.';cash=r(1200,4200);state.nc.humanity=clampNC151(state.nc.humanity-8);state.nc.heat=clampNC151(state.nc.heat+22);type='bad';}
    }
    txt += ncRandomDanger151('gig');
    closeModal(); action('Fixer gig',txt,stats,cash,type); safeSave(); render();
  };

