  window.ncDrink151 = function(kind){
    ensureNC151();
    if(state.age<18) return toast('Drinken kan pas vanaf 18.');
    let price = kind==='hard'?r(25,90):r(8,35);
    if(state.money<price) return toast('Niet genoeg geld.');
    state.money-=price;
    state.addictions.alcohol.uses++;
    state.addictions.alcohol.risk=clampNC151((state.addictions.alcohol.risk||0)+(kind==='hard'?7:3));
    state.nc.party.alcohol++;
    let blackout = kind==='hard' && Math.random()<((state.addictions.alcohol.risk||0)/160+0.08);
    let txt = kind==='hard'?'Ik nam sterke drank in een Night City club. De avond werd harder, duurder en waziger.':'Ik dronk in de club. Gezellig, neon, muziek, even los.';
    let stats = {Happiness:kind==='hard'?5:4,Health:kind==='hard'?-4:-1,Stamina:kind==='hard'?-8:-3,Smarts:kind==='hard'?-2:0};
    let type = kind==='hard'?'warn':'good';
    if(blackout){ state.nc.party.blackouts++; txt+='<br><br>Black-out: ik herinner me stukken van de avond niet. Mijn telefoon stond vol rare berichten.'; stats.Happiness-=8; stats.Health-=4; type='bad'; }
    closeModal(); action('Night City drank',txt,stats,0,type); safeSave(); render();
  };

