/* v15.6 Child yearly living costs */
(function(){
  function ensureChildCosts156(){
    if(!state) return;
    state.flags = state.flags || {};
    state.children = state.children || [];
  }

  function childYearCost156(child){
    const age = Number(child.age || 0);
    // Jaarlijkse kosten: eten, kleding, schoolspullen, opvang, sport, cadeaus, zorg, vervoer.
    if(age <= 3) return r(2600,5200);      // baby/peuter: luiers, opvang, spullen
    if(age <= 11) return r(2200,4600);     // basisschool
    if(age <= 17) return r(3000,6200);     // tiener: kleding, eten, school, telefoon, sport
    if(age <= 22) return r(1200,3800);     // thuiswonend/studerend kind kan nog kosten geven
    return 0;                              // volwassen uit huis: geen standaard jaarlijkse kosten
  }

  function childCostLabel156(child){
    const age = Number(child.age || 0);
    if(age <= 3) return 'baby/peuter-kosten';
    if(age <= 11) return 'kind-kosten';
    if(age <= 17) return 'tiener-kosten';
    if(age <= 22) return 'studie/thuiswonend-kind-kosten';
    return 'volwassen kind';
  }

  window.applyChildYearlyCosts156 = function(){
    ensureChildCosts156();
    const kids = (state.children || []).filter(c => Number(c.age || 0) <= 22);
    if(!kids.length || state.age < 16) return 0;

    let total = 0;
    let lines = [];
    kids.forEach(c => {
      const cost = childYearCost156(c);
      if(cost > 0){
        total += cost;
        lines.push(`${c.name || 'Kind'} (${c.age || 0}) · ${childCostLabel156(c)}: ${money(cost)}`);
      }
    });

    if(total <= 0) return 0;

    state.money -= total;

    // Stress impact wordt zwaarder als je weinig geld hebt.
    const stress = state.money < 0 ? -8 : total > 9000 ? -5 : -3;
    applyStats({Happiness:stress, Stamina:-2, Smarts:1});

    addLog(
      `<b>Kinderen / levenskosten</b><br>Kinderen kosten dit jaar extra geld voor eten, kleding, school, opvang, zorg en activiteiten.<br><br>${lines.join('<br>')}<br><br><b>Totaal:</b> ${money(total)}`,
      state.money < 0 ? 'bad' : 'warn',
      false
    );

    // Als je hierdoor rood komt te staan, schuld toevoegen zodat het merkbaar blijft.
    if(state.money < 0){
      const debtAdd = Math.abs(state.money);
      state.debts = (state.debts || 0) + debtAdd;
      state.money = 0;
      addLog(`<b>Roodstand</b><br>Door gezinskosten moest ik ${money(debtAdd)} lenen/bijschrijven als schuld.`, 'bad', false);
    }

    return total;
  };

  const oldYearlyAssets156 = window.yearlyAssets || (typeof yearlyAssets === 'function' ? yearlyAssets : null);
  window.yearlyAssets = function(){
    if(oldYearlyAssets156) oldYearlyAssets156();
    try{ applyChildYearlyCosts156(); }catch(e){ console.warn('[v15.6 child costs]', e); }
  };
  try{ yearlyAssets = window.yearlyAssets; }catch(e){}

  // Extra status in relationships/family screen if possible.
  window.childCostInfo156 = function(){
    ensureChildCosts156();
    const kids = (state.children || []).filter(c => Number(c.age || 0) <= 22);
    if(!kids.length) return '<div class="card">Geen jaarlijkse kindkosten.</div>';
    const estimate = kids.reduce((sum,c)=>{
      const age = Number(c.age||0);
      if(age <= 3) return sum + 3900;
      if(age <= 11) return sum + 3400;
      if(age <= 17) return sum + 4600;
      if(age <= 22) return sum + 2400;
      return sum;
    },0);
    return `<div class="card"><b>Geschatte kindkosten per jaar</b><br>${kids.length} kind(eren) onder/ongeveer afhankelijk.<br>Gemiddelde schatting: ${money(estimate)} per jaar.<br><span class="mini">Werkelijke kosten verschillen per jaar en leeftijd.</span></div>`;
  };

  const oldRelationships156 = window.relationshipsHTML || (typeof relationshipsHTML === 'function' ? relationshipsHTML : null);
  window.relationshipsHTML = function(){
    let h = oldRelationships156 ? oldRelationships156() : '';
    if((state.children||[]).length && !h.includes('Geschatte kindkosten per jaar')){
      h += `<div class="section">Gezinskosten</div>${childCostInfo156()}`;
    }
    return h;
  };
  try{ relationshipsHTML = window.relationshipsHTML; }catch(e){}

  setTimeout(()=>{ try{ ensureChildCosts156(); safeSave(); }catch(e){} },300);
})();

