/* v15.7 Parenting & Family Life Update */
(function(){
  const CHILD_TRAITS157=[
    ['calm','rustig','🧘','minder drama, meer stabiliteit'],
    ['busy','druk','⚡','veel energie, vaker chaos'],
    ['smart','slim','🧠','school gaat makkelijker'],
    ['sporty','sportief','⚽','wil vaker sporten/hobby'],
    ['rebellious','rebels','😈','meer ruzie en grenzen testen'],
    ['social','sociaal','🗣️','vriendjes en sociale events'],
    ['sensitive','gevoelig','🥺','meer steun nodig'],
    ['gamer','gamer','🎮','gamekamer/hobby events'],
    ['creative','creatief','🎨','kunst, muziek en fantasie']
  ].map(x=>({id:x[0],name:x[1],icon:x[2],desc:x[3]}));
  const pick157=a=>a[Math.floor(Math.random()*a.length)];
  const clamp157=v=>Math.max(0,Math.min(100,Math.round(v||0)));

  function ensureChild157(c){
    if(!c)return c;
    c.rel=clamp157(c.rel??r(45,75));
    c.happiness=clamp157(c.happiness??r(45,75));
    c.school=clamp157(c.school??r(40,75));
    c.behavior=clamp157(c.behavior??r(40,75));
    c.health=clamp157(c.health??r(65,90));
    c.parentingNotes=c.parentingNotes||[];
    if(!c.trait){
      const age=Number(c.age||0);
      let pool=age<4?CHILD_TRAITS157.filter(t=>['calm','busy','sensitive'].includes(t.id)):CHILD_TRAITS157;
      c.trait=pick157(pool);
    }
    if(typeof c.trait==='string')c.trait=CHILD_TRAITS157.find(t=>t.id===c.trait||t.name===c.trait)||CHILD_TRAITS157[0];
    return c;
  }
  function ensureParenting157(){
    if(!state)return;
    state.children=state.children||[];
    state.flags=state.flags||{};
    state.parenting=state.parenting||{stress:0,pride:0,schoolCalls:0,drama:0};
    state.children.forEach(ensureChild157);
  }
  function childStage157(c){
    const a=Number(c.age||0);
    if(a<=3)return 'baby/peuter';
    if(a<=11)return 'basisschool';
    if(a<=17)return 'tiener';
    if(a<=22)return 'jongvolwassen';
    return 'volwassen';
  }
  function changeChild157(c,d){
    ensureChild157(c);
    Object.entries(d||{}).forEach(([k,v])=>{if(['rel','happiness','school','behavior','health'].includes(k))c[k]=clamp157((c[k]||50)+v);});
  }
  function addChildNote157(c,txt){
    ensureChild157(c);
    c.parentingNotes.push({age:state.age,txt});
    c.parentingNotes=c.parentingNotes.slice(-10);
  }
  function partnerReact157(good=true){
    if(!state.partner||Math.random()>0.45)return '';
    if(good){state.partner.rel=clamp157((state.partner.rel||60)+r(1,4));return `<br><br>${state.partner.name} vond dat ik goed met de kinderen omging. Relatie werd iets sterker.`;}
    state.partner.rel=clamp157((state.partner.rel||60)-r(2,6));
    state.parenting.stress=clamp157((state.parenting.stress||0)+4);
    return `<br><br>${state.partner.name} vond mijn aanpak niet sterk. Dat gaf spanning tussen ons.`;
  }
  function childLine157(c){
    ensureChild157(c);
    return `${c.icon||'🧒'} <b>${c.name}</b> (${c.age||0})<br>Trait: ${c.trait.icon} ${c.trait.name}<br>Relatie ${c.rel}% · Geluk ${c.happiness}% · School ${c.school}% · Gedrag ${c.behavior}% · Gezondheid ${c.health}%`;
  }

  window.parentingMain157=function(){
    ensureParenting157();
    if(!(state.children||[]).length)return toast('Je hebt nog geen kinderen.');
    const kids=state.children.map((c,i)=>`<button class="btn" onclick="childDetail157(${i})">${c.icon||'🧒'} ${c.name} (${c.age||0})<br><span class="mini">${c.trait.icon} ${c.trait.name} · relatie ${c.rel}% · school ${c.school}% · gedrag ${c.behavior}%</span></button>`).join('');
    showModal(`<div class="modalTop"><div class="avatar">👨‍👩‍👧</div><div class="modalTitle">Parenting & Family Life</div></div><div class="modalBody">
    <div class="card"><b>Gezinsstatus</b><br>Parenting stress: ${state.parenting.stress||0}%<br>Trots/pride: ${state.parenting.pride||0}%<br>Schoolcalls: ${state.parenting.schoolCalls||0}<br>Gezinsdrama: ${state.parenting.drama||0}</div>
    <div class="section">Kinderen</div>${kids}
    <div class="section">Gezinsacties</div>
    <button class="btn" onclick="familyDay157()">🌳 Familiedag organiseren<br><span class="mini">iedereen mee, kost geld, relatie omhoog</span></button>
    <button class="btn" onclick="familyTalk157()">🫂 Gezinsgesprek<br><span class="mini">stress omlaag, gedrag/relatie kans omhoog</span></button>
    <button class="btn" onclick="familyBudget157()">💸 Gezinsbudget bekijken<br><span class="mini">kindkosten en opvoedkeuzes</span></button>
    <button class="btn alt" onclick="closeModal()">Terug</button></div>`);
  };

  window.childDetail157=function(i){
    ensureParenting157();
    const c=state.children[i]; if(!c)return toast('Kind niet gevonden.'); ensureChild157(c);
    const notes=(c.parentingNotes||[]).slice(-4).reverse().map(n=>`<div class="mini">Leeftijd ${n.age}: ${n.txt}</div>`).join('')||'<div class="mini">Nog geen notities.</div>';
    showModal(`<div class="modalTop"><div class="avatar">${c.icon||'🧒'}</div><div class="modalTitle">${c.name}</div></div><div class="modalBody">
    <div class="card">${childLine157(c)}<br><br><b>Fase:</b> ${childStage157(c)}<br><b>Trait effect:</b> ${c.trait.desc}</div>
    <div class="section">Opvoeden</div>
    <button class="btn" onclick="childAction157(${i},'time')">🧸 Tijd doorbrengen</button>
    <button class="btn" onclick="childAction157(${i},'school')">📚 Helpen met school</button>
    <button class="btn" onclick="childAction157(${i},'strict')">☝️ Streng toespreken</button>
    <button class="btn" onclick="childAction157(${i},'gift')">🎁 Cadeau kopen</button>
    <button class="btn" onclick="childAction157(${i},'hobby')">⚽ Sport/hobby betalen</button>
    <button class="btn" onclick="childAction157(${i},'doctor')">🏥 Naar dokter brengen</button>
    <button class="btn" onclick="childAction157(${i},'quality')">❤️ Quality time</button>
    <button class="btn" onclick="childAction157(${i},'fight')">🗣️ Ruzie oplossen</button>
    <div class="section">Laatste notities</div><div class="card">${notes}</div>
    <button class="btn alt" onclick="parentingMain157()">Terug</button></div>`);
  };

  window.childAction157=function(i,kind){
    ensureParenting157();
    const c=state.children[i]; if(!c)return toast('Kind niet gevonden.'); ensureChild157(c);
    let txt='',stats={},cash=0,type='good',good=true;
    if(kind==='time'){txt=`Ik bracht bewust tijd door met ${c.name}. Voor ${childStage157(c)} was dat precies wat nodig was.`;changeChild157(c,{rel:7,happiness:6,behavior:2});stats={Happiness:5,Stamina:-3};addChildNote157(c,'Tijd samen doorgebracht.');}
    if(kind==='school'){if(Number(c.age||0)<4){txt=`${c.name} is nog te jong voor schoolwerk, maar we oefenden spelenderwijs.`;changeChild157(c,{rel:3,happiness:3});stats={Happiness:2};}else{txt=`Ik hielp ${c.name} met school. Het kostte geduld, maar schoolprestaties gingen omhoog.`;changeChild157(c,{school:8,rel:3,happiness:2});stats={Smarts:2,Stamina:-4};}addChildNote157(c,'Geholpen met school/leren.');}
    if(kind==='strict'){let works=c.trait.id!=='rebellious'?Math.random()<0.7:Math.random()<0.42;txt=works?`Ik sprak ${c.name} streng maar duidelijk toe. Niet leuk, wel effectief.`:`Ik probeerde streng te zijn tegen ${c.name}, maar het escaleerde in discussie.`;changeChild157(c,{behavior:works?8:-3,rel:works?-1:-6,happiness:works?-2:-5});stats={Happiness:works?-1:-4,Smarts:1};type=works?'warn':'bad';good=works;addChildNote157(c,works?'Streng toespreken werkte.':'Streng toespreken werkte slecht.');}
    if(kind==='gift'){cash=-Math.min(state.money,r(20,160));txt=`Ik kocht een cadeau voor ${c.name}. Leuk moment, maar opvoeden is geen webshop.`;changeChild157(c,{happiness:8,rel:5,behavior:Math.random()<0.35?-2:1});stats={Happiness:3};addChildNote157(c,'Cadeau gekregen.');}
    if(kind==='hobby'){let cost=c.trait.id==='sporty'?r(180,480):r(90,320);if(state.money<cost)return childCostChoice157(i,'hobby',cost);state.money-=cost;txt=`Ik betaalde sport/hobby voor ${c.name}. Dat gaf ontwikkeling en zelfvertrouwen.`;changeChild157(c,{happiness:7,behavior:3,health:c.trait.id==='sporty'?5:1});stats={Happiness:4};addChildNote157(c,'Sport/hobby betaald.');}
    if(kind==='doctor'){let cost=r(35,240);if(state.money<cost)return childCostChoice157(i,'doctor',cost);state.money-=cost;txt=`Ik bracht ${c.name} naar de dokter/controle. Beter zeker weten dan laten lopen.`;changeChild157(c,{health:12,rel:2,happiness:-1});stats={Smarts:1,Stamina:-2};addChildNote157(c,'Naar dokter/controle geweest.');}
    if(kind==='quality'){let cost=r(0,70);if(state.money<cost)return childCostChoice157(i,'quality',cost);state.money-=cost;txt=`Ik had quality time met ${c.name}. Geen groot gebaar, wel echte aandacht.`;changeChild157(c,{rel:10,happiness:7,behavior:2});stats={Happiness:7,Stamina:-3};addChildNote157(c,'Quality time gehad.');}
    if(kind==='fight'){let works=Math.random()<((c.rel||50)+(c.behavior||50)+(state.stats?.Smarts||50))/230;txt=works?`Ik loste ruzie met ${c.name} rustig op. We begrepen elkaar beter.`:`Ik probeerde ruzie met ${c.name} op te lossen, maar het bleef hangen.`;changeChild157(c,{rel:works?8:-4,happiness:works?4:-4,behavior:works?4:-2});stats={Happiness:works?3:-4,Smarts:1};type=works?'good':'warn';good=works;addChildNote157(c,works?'Ruzie goed opgelost.':'Ruzie bleef hangen.');}
    txt+=partnerReact157(good);
    closeModal();action('Opvoeding',txt,stats,cash,type);safeSave();render();
  };

  window.childCostChoice157=function(i,kind,cost){
    const c=state.children[i]; if(!c)return;
    showModal(`<div class="modalTop"><div class="avatar">💸</div><div class="modalTitle">Kostenkeuze voor ${c.name}</div></div><div class="modalBody">
    <div class="card">Deze keuze kost ongeveer ${money(cost)}. Je hebt niet genoeg vrij geld of wil bewuster kiezen.</div>
    <button class="btn" onclick="resolveChildCostChoice157(${i},'${kind}','cheap',${cost})">♻️ Goedkoop/tweedehands oplossen</button>
    <button class="btn" onclick="resolveChildCostChoice157(${i},'${kind}','borrow',${cost})">💳 Lenen/betalen als schuld</button>
    <button class="btn red" onclick="resolveChildCostChoice157(${i},'${kind}','refuse',${cost})">❌ Weigeren</button>
    <button class="btn alt" onclick="childDetail157(${i})">Terug</button></div>`);
  };
  window.resolveChildCostChoice157=function(i,kind,choice,cost){
    ensureParenting157(); const c=state.children[i]; if(!c)return;
    let txt='',stats={},type='warn';
    if(choice==='cheap'){let pay=Math.min(state.money,Math.round(cost*.35));state.money-=pay;txt=`Ik loste het goedkoop/tweedehands op voor ${c.name}. Niet perfect, maar beter dan niks.`;changeChild157(c,{happiness:2,rel:2,health:kind==='doctor'?4:0,behavior:1});stats={Smarts:2,Happiness:1};type='good';}
    if(choice==='borrow'){state.debts=(state.debts||0)+cost;txt=`Ik betaalde voor ${c.name}, maar moest ${money(cost)} als schuld bijschrijven.`;changeChild157(c,{happiness:6,rel:4,health:kind==='doctor'?10:0,behavior:2});stats={Happiness:-2,Smarts:1};}
    if(choice==='refuse'){txt=`Ik weigerde de kosten voor ${c.name}. Soms moet je nee zeggen, maar dit kwam hard aan.`;changeChild157(c,{happiness:-8,rel:-7,behavior:-3,health:kind==='doctor'?-6:0});stats={Happiness:-4};type='bad';state.parenting.stress=clamp157((state.parenting.stress||0)+6);}
    addChildNote157(c,txt.replace(/<[^>]*>/g,'')); closeModal();action('Kindkosten keuze',txt,stats,0,type);safeSave();render();
  };

  window.familyDay157=function(){
    ensureParenting157(); const kids=state.children||[]; if(!kids.length)return toast('Geen kinderen.');
    const cost=35+kids.length*r(20,80); if(state.money<cost)return toast('Niet genoeg geld voor familiedag.');
    state.money-=cost; kids.forEach(c=>changeChild157(c,{rel:5,happiness:7,behavior:1})); state.parenting.pride=clamp157((state.parenting.pride||0)+5);
    let txt=`Ik organiseerde een familiedag. Het kostte ${money(cost)}, maar iedereen had even het gevoel dat we een team waren.`+partnerReact157(true);
    closeModal();action('Familiedag',txt,{Happiness:9,Stamina:-7},0,'good');safeSave();render();
  };
  window.familyTalk157=function(){
    ensureParenting157(); (state.children||[]).forEach(c=>changeChild157(c,{rel:3,behavior:3,happiness:2})); state.parenting.stress=clamp157((state.parenting.stress||0)-8);
    let txt='Ik hield een gezinsgesprek. Niet iedereen had zin, maar het bracht wel wat rust.'+partnerReact157(true);
    closeModal();action('Gezinsgesprek',txt,{Happiness:4,Smarts:2,Stamina:-2},0,'good');safeSave();render();
  };
  window.familyBudget157=function(){
    ensureParenting157();
    const lines=(state.children||[]).map(c=>{const a=Number(c.age||0), est=a<=3?3900:a<=11?3400:a<=17?4600:a<=22?2400:0;return `${c.name} (${a}) · ${childStage157(c)} · ± ${money(est)}/jaar`;}).join('<br>')||'Geen kinderen.';
    showModal(`<div class="modalTop"><div class="avatar">💸</div><div class="modalTitle">Gezinsbudget</div></div><div class="modalBody"><div class="card"><b>Geschatte jaarlijkse kindkosten</b><br>${lines}<br><br>Deze kosten worden automatisch verwerkt bij Age. Extra keuzes zoals hobby/dokter/cadeaus komen daarbovenop.</div><button class="btn" onclick="parentingMain157()">Terug</button></div>`);
  };

  function childSchoolYearEvent157(c){
    ensureChild157(c); const a=Number(c.age||0); let events=[];
    if(a<4)events=[['Peuterfase',`${c.name} had een pittige peuterdag. Veel energie, weinig logica.`,{happiness:-1,behavior:c.trait.id==='busy'?-3:0,rel:1},0,'warn'],['Mijlpaal',`${c.name} leerde iets nieuws en was zichtbaar trots.`,{happiness:4,rel:3},0,'good']];
    else if(a<=11)events=[['Schoolrapport',`${c.name} kreeg een schoolrapport.`,{school:c.trait.id==='smart'?6:r(-2,5),happiness:2},0,'good'],['Schoolreisje',`${c.name} wil mee op schoolreisje.`,{happiness:4,rel:2},r(30,140),'warn'],['Pesten',`${c.name} had gedoe met pesten/ruzie op school.`,{happiness:-6,behavior:-2,rel:2},0,'bad'],['Nieuwe vriendjes',`${c.name} maakte nieuwe vriendjes op school.`,{happiness:6,behavior:2},0,'good']];
    else if(a<=17)events=[['Slechte cijfers',`${c.name} haalde slechte cijfers en probeerde het eerst weg te lachen.`,{school:-7,behavior:-2,happiness:-2},0,'warn'],['Goede cijfers',`${c.name} deed het sterk op school. Ik was echt trots.`,{school:7,happiness:4,rel:2},0,'good'],['Tiener komt laat thuis',`${c.name} kwam veel te laat thuis. Er volgde een serieus gesprek.`,{behavior:-6,rel:-2,happiness:-2},0,'bad'],['Sportclub',`${c.name} wil op sportclub/hobby.`,{happiness:5,health:4},r(120,420),'warn'],['Gamen tot laat',`${c.name} zat veel te lang te gamen. Herkenbaar, maar school leed eronder.`,{school:-3,happiness:3,behavior:-3},0,'warn']];
    else if(a<=22)events=[['Studiekosten',`${c.name} had extra studie/thuiswoon-kosten.`,{school:3,rel:1},r(200,950),'warn'],['Volwassener gesprek',`${c.name} en ik hadden een volwassen gesprek over toekomst, werk en geld.`,{rel:5,school:2},0,'good']];
    else return '';
    let [title,txt,delta,cost,type]=pick157(events);
    if(cost>0){if(state.money>=cost){state.money-=cost;txt+=`<br>Kosten: ${money(cost)}.`;}else{state.debts=(state.debts||0)+cost;txt+=`<br>Ik kon het niet direct betalen; ${money(cost)} kwam als schuld erbij.`;type='bad';}}
    changeChild157(c,delta); addChildNote157(c,title+': '+txt.replace(/<[^>]*>/g,'')); return `<b>${title}</b><br>${txt}`;
  }

  window.runChildYearEvents157=function(){
    ensureParenting157(); const kids=(state.children||[]).filter(c=>Number(c.age||0)<=22); if(!kids.length)return;
    let logs=[];
    kids.forEach(c=>{
      if(Math.random()<0.55)logs.push(`${c.icon||'🧒'} ${c.name}: ${childSchoolYearEvent157(c)}`);
      if(c.trait.id==='smart')changeChild157(c,{school:1});
      if(c.trait.id==='rebellious'&&Math.random()<0.35){changeChild157(c,{behavior:-2,rel:-1});state.parenting.drama=clamp157((state.parenting.drama||0)+1);}
      if(c.trait.id==='sporty')changeChild157(c,{health:1});
      if(c.trait.id==='sensitive'&&c.happiness<35)state.parenting.stress=clamp157((state.parenting.stress||0)+3);
    });
    if(logs.length)addLog(`<b>Kinderen / schooljaar</b><br>${logs.join('<br><br>')}`,'warn',false);
    const teen=kids.filter(c=>Number(c.age||0)>=13&&Number(c.age||0)<=17);
    if(teen.length&&Math.random()<0.16){
      const c=pick157(teen); let type='warn',txt='';
      if(c.trait.id==='rebellious'&&Math.random()<0.55){txt=`${c.name} liep boos weg na ruzie en kwam later terug. Dit raakte de band flink.`;changeChild157(c,{rel:-8,happiness:-7,behavior:-6});type='bad';state.parenting.drama=clamp157((state.parenting.drama||0)+8);}
      else{txt=`${c.name} had een moeilijk tienermoment. We moesten echt praten om het weer normaal te krijgen.`;changeChild157(c,{rel:2,happiness:-3,behavior:-2});state.parenting.drama=clamp157((state.parenting.drama||0)+3);}
      addChildNote157(c,txt); addLog(`<b>Family drama</b><br>${txt}`,type,false);
    }
    safeSave();
  };

  window.childHomeRoom157=function(){
    ensureParenting157(); if(!(state.children||[]).length)return toast('Geen kinderen.');
    const c=pick157(state.children); ensureChild157(c);
    let txt=c.trait.id==='gamer'?`${c.name} zat in de game kamer en vroeg of ik mee wilde spelen.`:c.trait.id==='creative'?`${c.name} maakte een creatieve rommel in huis. Irritant, maar ook mooi.`:c.trait.id==='busy'?`${c.name} rende door het huis alsof de vloer lava was.`:`${c.name} hing thuis rond en wilde aandacht.`;
    changeChild157(c,{rel:3,happiness:4}); action('Kinderen thuis',txt,{Happiness:4,Stamina:-3},0,'good');
  };
  const oldHomeSocial157=window.homeSocialScreen154;
  if(oldHomeSocial157){
    window.homeSocialScreen154=function(){
      oldHomeSocial157();
      setTimeout(()=>{try{const modal=document.getElementById('modal');if(modal&&!document.getElementById('kidsHomeBtn157')&&(state.children||[]).length){const btn=document.createElement('button');btn.id='kidsHomeBtn157';btn.className='btn';btn.innerHTML='👶 Kinderen thuis<br><span class="mini">kamer/gezins-event met kinderen</span>';btn.onclick=()=>childHomeRoom157();const body=modal.querySelector('.modalBody');const alt=[...modal.querySelectorAll('button')].find(b=>/Terug/i.test(b.textContent||''));if(body&&alt)body.insertBefore(btn,alt);else if(body)body.appendChild(btn);}}catch(e){}},30);
    };
    try{homeSocialScreen154=window.homeSocialScreen154;}catch(e){}
  }

  const oldRelationships157=window.relationshipsHTML||(typeof relationshipsHTML==='function'?relationshipsHTML:null);
  window.relationshipsHTML=function(){let h=oldRelationships157?oldRelationships157():'';if((state.children||[]).length&&!h.includes('Parenting & Family Life'))h+=`<div class="section">Parenting & Family Life</div>${row('👨‍👩‍👧','Parenting & Family Life','Kinderen opvoeden, school, hobby, drama en gezinsbudget','parentingMain157()')}`;return h;};
  try{relationshipsHTML=window.relationshipsHTML;}catch(e){}
  const oldActivities157=window.activitiesHTML||(typeof activitiesHTML==='function'?activitiesHTML:null);
  window.activitiesHTML=function(){let h=oldActivities157?oldActivities157():'';if((state.children||[]).length&&!h.includes('Parenting & Family Life'))h+=`<div class="section">Gezin</div>${row('👨‍👩‍👧','Parenting & Family Life','Opvoeden, school-events, gezinsbudget en family drama','parentingMain157()')}`;return h;};
  try{activitiesHTML=window.activitiesHTML;}catch(e){}
  const oldAge157=window.ageUp||(typeof ageUp==='function'?ageUp:null);
  window.ageUp=function(){if(oldAge157)oldAge157();try{runChildYearEvents157();}catch(e){console.warn('[v15.7 parenting year]',e);}};
  try{ageUp=window.ageUp;}catch(e){}

  setTimeout(()=>{try{ensureParenting157();safeSave();}catch(e){}},300);
})();

