        state.job.grossAnnual=gross+inc; state.job.salary=state.job.grossAnnual;
        txt=`Ik kreeg promotie. Bruto +${money(inc)}/jaar.<br>Nieuw: ${jobMoneyLine161(state.job)}<br>Meer verantwoordelijkheid, dus ook meer stress.`;
