    if(s==='fight'&&state.fightCareer){state.fightCareer.contract=null;state.fightCareer.salary=0;}
    const fb=state.football||state.footballCareer||state.soccerCareer; if(s==='football'&&fb){fb.contract=null;fb.salary=0;}
