 window.wweAction164=function(c){const m=window.__wwe,w=state.wrestling;let perf=(w.skill||0)*.25+(w.promo||0)*.20+(w.selling||0)*.20+(w.ringIQ||0)*.20+(w.popularity||0)*.15+r(-8,8),gain=0,crowd=0,risk=0,txt='';if(c==='work'){gain=perf/10+4;crowd=8;txt='Publiek zat erin.'}if(c==='fast'){gain=perf/10+6;crowd=5;risk=5;txt='Snelle start werkte.'}if(c==='heel'){gain=perf/12+5;crowd=6;risk=3;w.heat=clamp((w.heat||0)+5);txt='Heel heat werkte.'}if(c==='safe'){gain=perf/13+3;risk=-3;txt='Veilig maar solide.'}if(c==='sell'){gain=(w.selling||0)/8+6;crowd=5;txt='Sterke selling.'}if(c==='highrisk'){gain=perf/9+8;crowd=10;risk=16;txt='High risk pop.'}if(c==='promo'){gain=(w.promo||0)/7+4;crowd=6;txt='Promo in match hielp.'}if(c==='technical'){gain=((w.skill||0)+(w.ringIQ||0))/14+5;crowd=3;txt='Technisch sterk.'}if(c==='clean'){gain=perf/10+5;crowd=5;txt='Clean finish poging.'}if(c==='protect'){gain=(w.selling||0)/8+7;crowd=4;txt='Opponent protected.'}if(c==='cheat'){gain=perf/11+6;crowd=8;risk=5;w.heat=clamp((w.heat||0)+8);txt='Cheat gaf story heat.'}if(c==='bigspot'){gain=perf/8+10;crowd=12;risk=18;txt='Big spot pop.'}if(Math.random()<Math.max(0,risk)/100){txt+=' Blessure-risk.';applyStats({Health:-3});m.rating-=3}m.rating+=Math.round(gain);m.crowd+=crowd;m.risk+=risk;m.log.push(txt);m.phase++;wwePhase164()};
 function wweResolve164(){const m=window.__wwe,w=state.wrestling,s=state.sportsRankings.wwe;let total=m.rating+m.crowd+Math.round((w.popularity||0)/4)+r(-8,8),points=0,outcome='',type='good',bonus=0;if(total>75){points=22;outcome='Match of the night vibe.';w.popularity=clamp((w.popularity||0)+r(6,14));w.momentum=clamp((w.momentum||50)+r(8,16));w.wins++}else if(total>48){points=12;outcome='Solide tv/PLE match.';w.popularity=clamp((w.popularity||0)+r(2,7));w.momentum=clamp((w.momentum||50)+r(2,8));w.wins++}else{points=-6;outcome='Vlakke match, creative twijfelt.';w.momentum=clamp((w.momentum||50)-r(4,10));w.losses++;type='warn'}if(m.type==='contender'&&points>0)points+=18;if(m.type==='title'&&total>58){s.champion=true;s.rank=1;w.level='champion';if(!w.titles.includes('WWE Championship'))w.titles.push('WWE Championship');outcome+='<br>Title moment!'}if(m.type==='ple'){points+=10;bonus=w.contract?Math.round((w.contract.bookingBonus||0)*r(1,4)):r(300,2500)}if(m.type==='rumble'&&total>65){points+=25;outcome+='<br>Rumble performance richting main event.'}s.points=clamp((s.points||0)+points);rank(s,points>18?3:points>5?1:-1);if(s.points>100)s.mainEvent=true;state.money+=bonus;closeModal();action('WWE/NXT booking',`${m.stip}<br>${m.log.join('<br>')}<br>${outcome}<br>Ranking: ${rt(s.rank,s.champion)} · story points ${s.points}<br>${bonus?`Bonus: ${cash(bonus)}`:''}`,{Happiness:points>0?10:-4,Health:m.risk>25?-3:-1,Stamina:-10},0,type);safeSave();render();window.__wwe=null}
 const oldAct=window.activitiesHTML||(typeof activitiesHTML==='function'?activitiesHTML:null);
 window.activitiesHTML=function(){let h=oldAct?oldAct():'';if(!h.includes('Rankings & Tactical Fights'))h+=`<div class="section">Rankings & Tactical Fights</div>${row('🏆','Rankings & Tactical Fights','WWE/GLORY/UFC rankings, title fights en tactische keuzes','sportsRankingsHub164()')}`;return h};try{activitiesHTML=window.activitiesHTML}catch(e){}
 const oldW=window.wrestlingCareerScreen163;if(oldW){window.wrestlingCareerScreen163=function(){oldW();setTimeout(()=>{try{const body=document.querySelector('#modal .modalBody');if(body&&!document.getElementById('rankFightBtn164')){const b=document.createElement('button');b.id='rankFightBtn164';b.className='btn gold';b.innerHTML='🏆 Rankings & Tactical Matches<br><span class="mini">contenders, title fights, PLE keuzes</span>';b.onclick=()=>sportsRankingsHub164();body.insertBefore(b,body.querySelector('.btn.alt')||null)}}catch(e){}},30)};try{wrestlingCareerScreen163=window.wrestlingCareerScreen163}catch(e){}}
