 const INV={savings:['🏦','Spaarrekening',[1,3],0,100],index:['📈','Indexfonds',[-8,12],.03,500],crypto:['🪙','Crypto',[-50,80],.12,100],realestate:['🏢','Vastgoedfonds',[-5,15],.04,1000],scam:['⚠️','Vage garantie investering',[-100,120],.35,250]};
 const BUS={webshop:['📦','Webshop',3500,35,[-1500,6500]],snackbar:['🍟','Snackbar',12000,30,[-3500,18000]],gym:['🏋️','Sportschool',22000,32,[-7000,35000]],gamestudio:['🎮','Game studio',18000,45,[-10000,60000]],wrestlingschool:['🤼','Wrestling school',30000,38,[-9000,55000]],garage:['🔧','Garage',26000,34,[-8000,42000]]};
 const pick=a=>a[Math.floor(Math.random()*a.length)], clamp=v=>Math.max(0,Math.min(100,Math.round(v||0)));
