 function en(){state.lifestyle=state.lifestyle||{items:[],investments:[],businesses:[],loans:[],yearlyCosts:0};state.lifestyle.items=state.lifestyle.items||[];state.lifestyle.investments=state.lifestyle.investments||[];state.lifestyle.businesses=state.lifestyle.businesses||[];state.lifestyle.loans=state.lifestyle.loans||[];state.houses=state.houses||[];state.children=state.children||[]}
