 function buy(item,opt={}){en();if(!item)return toast('Item niet gevonden.');let price=opt.price??item.price;if(state.money<price)return toast('Niet genoeg geld: '+m(price));let h=opt.house||house(),room=opt.room||item.room,scope=opt.scope||'global';if(item.unique){if(item.cat==='home'){if(!h)return toast('Je hebt eerst een woning nodig.');if(!rooms(h).includes(room))return toast('Deze woning heeft geen '+rn(room));if(ownH(h,room,item.id))return toast('Al in bezit.')}else if(own(item.id,scope))return toast('Al in bezit.')}state.money-=price;if(item.cat==='home'){h.upgrades=h.upgrades||{};h.upgrades[room]=h.upgrades[room]||[];h.upgrades[room].push(item.id)}else state.lifestyle.items.push({id:item.id,scope,target:opt.target||null,boughtAge:state.age,price});if(item.effects)applyStats(item.effects);if(opt.child){opt.child.happiness=clamp((opt.child.happiness||50)+6);opt.child.rel=clamp((opt.child.rel||50)+4);if(item.id==='school_supplies')opt.child.school=clamp((opt.child.school||50)+7)}if(opt.partner&&state.partner)state.partner.rel=clamp((state.partner.rel||60)+(item.id==='date_night'?8:5));closeModal();action('Lifestyle aankoop',`${item.icon} <b>${item.name}</b> gekocht voor ${m(price)}.<br>${item.desc}${item.yearlyCost?'<br>Jaarlijkse kosten erbij: '+m(item.yearlyCost):''}`,item.effects||{Happiness:1},0,'good');safeSave();render()}
