 window.houseUpgradeHub165=function(){let h=house();if(!h)return showModal(`<div class="modalTop"><div class="avatar">🏠</div><div class="modalTitle">Huis upgrades</div></div><div class="modalBody"><div class="card">Je hebt eerst een woning nodig.</div><button class="btn alt" onclick="moneyLifestyleHub165()">Terug</button></div>`);showModal(`<div class="modalTop"><div class="avatar">🏠</div><div class="modalTitle">Huis & kamer-upgrades</div></div><div class="modalBody">${status()}<div class="card"><b>${h.name}</b><br>Kamers: ${rooms(h).map(rn).join(', ')}</div>${rooms(h).map(r=>`<button class="btn" onclick="roomUpgradeHub165('${r}')">${ri(r)} ${rn(r)} upgraden</button>`).join('')}<button class="btn alt" onclick="moneyLifestyleHub165()">Terug</button></div>`)};
 window.roomUpgradeHub165=function(room){let h=house(),items=ITEMS.filter(x=>x.cat==='home'&&x.room===room);showModal(`<div class="modalTop"><div class="avatar">${ri(room)}</div><div class="modalTitle">${rn(room)}</div></div><div class="modalBody"><div class="card">Upgrades: ${((h.upgrades||{})[room]||[]).map(id=>it(id)?.name||id).join(', ')||'nog niks'}</div>${items.map(a=>{let o=ownH(h,room,a.id);return `<button class="btn ${o?'locked':''}" onclick="${o?'':`buyLifestyleItem165('${a.id}')`}">${a.icon} ${a.name} · ${m(a.price)}<br><span class="mini">${o?'Al in bezit':a.desc} ${a.yearlyCost?'· '+m(a.yearlyCost)+'/jr':''}</span></button>`}).join('')}<button class="btn alt" onclick="houseUpgradeHub165()">Terug</button></div>`)};
 window.shoppingHub165=function(){showModal(`<div class="modalTop"><div class="avatar">🛍️</div><div class="modalTitle">Shopping</div></div><div class="modalBody">${status()}${ITEMS.filter(x=>x.cat==='shopping').map(a=>`<button class="btn" onclick="buyLifestyleItem165('${a.id}')">${a.icon} ${a.name} · ${m(a.price)}<br><span class="mini">${a.desc}</span></button>`).join('')}<button class="btn alt" onclick="moneyLifestyleHub165()">Terug</button></div>`)};
 window.familySpendingHub165=function(){let partner=state.partner?ITEMS.filter(x=>x.cat==='relationship').map(a=>`<button class="btn" onclick="buyRelationshipItem165('${a.id}')">${a.icon} ${a.name} · ${m(a.price)}</button>`).join(''):'<div class="card">Geen partner.</div>';let kids=state.children.length?state.children.map((c,i)=>`<button class="btn" onclick="childSpendScreen165(${i})">${c.icon||'🧒'} ${c.name}</button>`).join(''):'<div class="card">Geen kinderen.</div>';showModal(`<div class="modalTop"><div class="avatar">👨‍👩‍👧</div><div class="modalTitle">Familie & relatie-uitgaven</div></div><div class="modalBody">${status()}<div class="section">Partner</div>${partner}<div class="section">Kinderen</div>${kids}<button class="btn alt" onclick="moneyLifestyleHub165()">Terug</button></div>`)};
