 window.buyInvestment165=function(type,amount){let t=INV[type];if(state.money<amount)return toast('Niet genoeg geld.');state.money-=amount;state.lifestyle.investments.push({type,name:t[1],value:amount,startedAge:state.age});closeModal();action('Investering',`${t[0]} Ik investeerde ${m(amount)} in ${t[1]}.`,{Smarts:1},0,'good');safeSave();render()};
 window.sellInvestment165=function(i){let inv=state.lifestyle.investments[i];if(!inv)return;state.money+=inv.value;state.lifestyle.investments.splice(i,1);closeModal();action('Investering verkocht',`Ik verkocht ${inv.name} voor ${m(inv.value)}.`,{Happiness:1},0,'good');safeSave();render()};
 window.businessHub165=function(){let cur=state.lifestyle.businesses.map((b,i)=>`<button class="btn" onclick="businessDetail165(${i})">${BUS[b.type]?.[0]||'🏪'} ${b.name}<br><span class="mini">level ${b.level} · reputatie ${b.reputation}% · waarde ${m(b.value)}</span></button>`).join('')||'<div class="card">Nog geen business.</div>';showModal(`<div class="modalTop"><div class="avatar">🏪</div><div class="modalTitle">Eigen business</div></div><div class="modalBody">${status()}<div class="section">Jouw business</div>${cur}<div class="section">Start business</div>${Object.entries(BUS).map(([k,b])=>`<button class="btn" onclick="startBusiness165('${k}')">${b[0]} ${b[1]} · ${m(b[2])}</button>`).join('')}<button class="btn alt" onclick="moneyLifestyleHub165()">Terug</button></div>`)};
 window.startBusiness165=function(type){let b=BUS[type];if(state.money<b[2])return toast('Niet genoeg geld.');state.money-=b[2];state.lifestyle.businesses.push({type,name:b[1],level:1,reputation:r(25,55),staff:0,value:Math.round(b[2]*.75),startedAge:state.age});closeModal();action('Business gestart',`${b[0]} Ik startte ${b[1]} voor ${m(b[2])}.`,{Happiness:5,Smarts:3},0,'good');safeSave();render()};
 window.businessDetail165=function(i){let b=state.lifestyle.businesses[i],meta=BUS[b.type];showModal(`<div class="modalTop"><div class="avatar">${meta[0]}</div><div class="modalTitle">${b.name}</div></div><div class="modalBody"><div class="card">Level ${b.level}<br>Reputatie ${b.reputation}%<br>Personeel ${b.staff}<br>Waarde ${m(b.value)}</div><button class="btn" onclick="businessInvest165(${i})">📈 Uitbreiden · ${m(2500*b.level)}</button><button class="btn" onclick="businessHire165(${i})">👥 Personeel aannemen · ${m(1200)}</button><button class="btn red" onclick="businessSell165(${i})">🏷️ Verkopen</button><button class="btn alt" onclick="businessHub165()">Terug</button></div>`)};
 window.businessInvest165=function(i){let b=state.lifestyle.businesses[i],cost=2500*b.level;if(state.money<cost)return toast('Niet genoeg geld.');state.money-=cost;b.level++;b.reputation=clamp(b.reputation+r(3,10));b.value+=Math.round(cost*.75);closeModal();action('Business uitbreiding',`Ik investeerde ${m(cost)} in ${b.name}.`,{Smarts:2,Happiness:2},0,'good');safeSave();render()};
