/* v16.6 Car Sell/Rent Fix */
(function(){
  function money166(v){try{return money(v)}catch(e){return '€ '+Math.round(v||0).toLocaleString('nl-NL');}}
  function clamp166(v,min,max){return Math.max(min,Math.min(max,Math.round(v||0)));}
  function normalizeCar166(c){
    if(!c)return c;
    c.value = Math.max(0, Math.round(Number(c.value ?? c.price ?? 0)));
    c.price = Math.max(c.value, Math.round(Number(c.price ?? c.value ?? 0)));
    c.upkeep = Math.max(0, Math.round(Number(c.upkeep ?? Math.max(300,c.value*.06))));
    // In DATA rent is monthly; bought cars often already store rent yearly. Keep sane yearly rental income.
    let rent = Number(c.rent ?? 0);
    if(rent>0 && rent<6000 && c.value>8000) rent = rent*12;
    if(!rent || rent<=0) rent = Math.max(120, Math.round(c.value*0.055));
    c.rent = Math.round(rent);
    c.rented = !!c.rented;
    c.condition = clamp166(c.condition ?? 85, 1, 100);
    return c;
  }
  function ensureCars166(){
    state.cars = state.cars || [];
    state.cars.forEach(normalizeCar166);
  }
  window.toggleCarRent166 = function(i){
    ensureCars166();
    const c=state.cars[i];
    if(!c)return toast('Deze auto bestaat niet meer.');
    c.rented=!c.rented;
    const txt=c.rented
      ? `Ik verhuurde mijn ${c.name}. Verwachte verhuurinkomsten: ${money166(c.rent)}/jaar. De auto blijft wel onderhoud en waardeverlies hebben.`
      : `Ik stopte de verhuur van mijn ${c.name}. Vanaf nu is hij weer voor eigen gebruik.`;
    closeModal();
    action('Auto verhuur',txt,{Happiness:c.rented?1:0},0,c.rented?'good':'warn');
    safeSave();
    render();
  };
  window.sellCar166 = function(i){
    ensureCars166();
    const c=state.cars[i];
    if(!c)return toast('Deze auto bestaat niet meer.');
    const condition = clamp166(c.condition ?? 85,1,100);
    const sale = Math.max(50, Math.round((c.value||0) * (0.72 + condition/400)));
    const name=c.name||'auto';
    state.money += sale;
    state.cars.splice(i,1);
    closeModal();
    action('Auto verkocht',`Ik verkocht mijn ${name} voor ${money166(sale)}.<br>Conditie: ${condition}%.`,{Happiness:1},0,'good');
    safeSave();
    render();
  };
  window.repairCar166 = function(i){
    ensureCars166();
    const c=state.cars[i]; if(!c)return toast('Deze auto bestaat niet meer.');
    const condition=clamp166(c.condition??85,1,100);
    if(condition>=95)return toast('Deze auto is al bijna perfect.');
    const cost=Math.round((100-condition)*(c.value||1000)/900);
    if(state.money<cost)return toast('Niet genoeg geld: '+money166(cost));
    state.money-=cost; c.condition=clamp166(condition+Math.round(cost/Math.max(1,(c.value||1000)/900)),1,100);
    closeModal();
    action('Auto reparatie',`Ik liet mijn ${c.name} repareren voor ${money166(cost)}. Conditie nu ${c.condition}%.`,{Happiness:1},0,'good');
    safeSave(); render();
  };
  window.assetCar = function(i){
    ensureCars166();
    const c=state.cars[i];
    if(!c)return toast('Deze auto bestaat niet meer.');
    const sellEstimate=Math.max(50,Math.round((c.value||0)*(0.72+(c.condition||85)/400)));
    showModal(`<div class="modalTop"><div class="avatar">🚗</div><div class="modalTitle">${c.name}</div></div>
    <div class="modalBody">
      <div class="card">
        Waarde: ${money166(c.value)}<br>
        Geschatte verkoopprijs: ${money166(sellEstimate)}<br>
        Verhuur: ${c.rented?'actief':'niet actief'} · ${money166(c.rent)}/jaar<br>
        Onderhoud: ${money166(c.upkeep)}/jaar<br>
        Conditie: ${c.condition}%<br>
        Drive Skill: ${state.talents?.drive||0} · Race Skill: ${state.talents?.race||0}
      </div>
      <button class="btn" onclick="carLifeScreen(${i})">🚘 Rijden / racen</button>
      <button class="btn" onclick="toggleCarRent166(${i})">${c.rented?'🔒 Stop verhuur':'💶 Verhuur auto'}<br><span class="mini">${c.rented?'Auto terug voor eigen gebruik':'Ontvang jaarlijks '+money166(c.rent)}</span></button>
      <button class="btn" onclick="repairCar166(${i})">🔧 Repareren / onderhoud</button>
      <button class="btn red" onclick="sellCar166(${i})">🏷️ Verkopen<br><span class="mini">verwacht ${money166(sellEstimate)}</span></button>
      <button class="btn alt" onclick="closeModal()">Terug</button>
    </div>`);
  };
  try{assetCar=window.assetCar;}catch(e){}

  // Make yearly car rent more reliable and avoid old broken inline state.
  const oldYearlyAssets166 = window.yearlyAssets || (typeof yearlyAssets==='function'?yearlyAssets:null);
  window.yearlyAssets = function(){
    if(oldYearlyAssets166)oldYearlyAssets166();
    try{
      ensureCars166();
      let income=0, lines=[];
      state.cars.forEach(c=>{
        if(c.rented){
          const wear=Math.max(1,Math.round((c.condition||85)-Math.random()*8-2));
          c.condition=clamp166(wear,1,100);
          income += c.rent||0;
          lines.push(`${c.name}: verhuur ${money166(c.rent)} · conditie ${c.condition}%`);
        }
      });
      if(income>0){
        state.money += income;
        addLog(`<b>Auto verhuur</b><br>${lines.join('<br>')}<br><br>Totaal ontvangen: ${money166(income)}.`,'good',false);
      }
      safeSave();
    }catch(e){console.warn('[v16.6 car yearly]',e);}
  };
  try{yearlyAssets=window.yearlyAssets;}catch(e){}

  setTimeout(()=>{try{ensureCars166();safeSave();}catch(e){}},300);
})();

