      return showModal(`<div class="modalTop"><div class="avatar">🤼</div><div class="modalTitle">Wrestling Career</div></div><div class="modalBody"><div class="card">Wrestling school kan vanaf 16 jaar.</div><button class="btn alt" onclick="closeModal()">Terug</button></div>`);
